-- Poems batch 9
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('88d4489c-981b-416d-97bd-d7de86b432d8','九日與敬處士左學士同賦采菊上東山便爲首句','戴叔倫','唐','唐诗','tang','','[]','采菊上東山，山高路非遠。',108,'全唐诗/poet.tang.14000.json','["采菊上東山，山高路非遠。", "江湖乍遼敻，城郭亦在眼。", "晝日市井喧，閏年禾稼晚。", "開尊會佳客，長嘯臨絕巘。", "戲鶴唳且閑，斷雲輕不卷。", "鄉心各萬里，醉話時一展。", "喬木列遙天，殘陽貫平坂。", "徒憂征車重，自笑謀慮淺。", "却顧郡齋中，寄傲與君同。"]'),
('289f44b0-41de-41e2-84b8-41e04a7f604c','奉天酬別鄭諫議雲逵盧拾遺景亮見別之作','戴叔倫','唐','唐诗','tang','','[]','巨孽盜都城，傳聞天下驚。',288,'全唐诗/poet.tang.14000.json','["巨孽盜都城，傳聞天下驚。", "陪臣九江畔，走馬來赴難。", "伏奏見龍顏，旋持手詔還。", "單車不可駐，朱檻未遑攀。", "故人出相餞，共悲行路難。", "臨岐荷贈言，對酒獨傷魂。", "世故山川險，憂多思慮昏。", "重陰蔽芳月，疊嶺明舊雪。", "泥積轍更深，木冰花不發。", "鄭君間世賢，忠孝乃雙全。", "大義棄妻子，至淳易生死。", "知心三四人，越境千餘里。", "駿馬帳前發，驚塵路旁起。", "樓頭俛首看，莫敢相留止。", "拜闕奏良圖，留中沃聖謨。", "洗兵救衞郡，誘敵討幽都。", "名亞典屬國，良選諫大夫。", "從容九霄上，談笑授陰符。", "盧生富才術，特立居近密。", "採掇獻吾君，朝廷視聽新。", "寬饒狂自比，汲黯直爲鄰。", "就列繼三事，主文當七人。", "可憐長守道，不覺五逢春。", "昔去城南陌，各爲天際客。"]'),
('d10b060f-73a8-4f5e-bf88-786d1c274e75','梧桐','戴叔倫','唐','唐诗','tang','','[]','亭亭南軒外，貞幹修且直。',36,'全唐诗/poet.tang.14000.json','["亭亭南軒外，貞幹修且直。", "廣葉結青陰，繁花連素色。", "天資韶雅性，不愧知音識。"]'),
('69227cca-7a41-431d-8ce9-8eda02f0c6e1','孤石','戴叔倫','唐','唐诗','tang','','[]','迥若千仞峰，孤危不盈尺。',36,'全唐诗/poet.tang.14000.json','["迥若千仞峰，孤危不盈尺。", "早晚他山來，猶帶煙雨跡。", "貞堅自有分，不亂和氏璧。"]'),
('dda01b8e-4e02-4173-b3b7-6ca523acd4fe','花','戴叔倫','唐','唐诗','tang','','[]','花發炎景中，芳春獨能久。',36,'全唐诗/poet.tang.14000.json','["花發炎景中，芳春獨能久。", "因風任開落，向日無先後。", "若待秋霜來，蘭蓀共何有。"]'),
('ac8989bc-6581-4530-9869-49574f9b111c','竹','戴叔倫','唐','唐诗','tang','','[]','卷籜正離披，新枝復蒙密。',36,'全唐诗/poet.tang.14000.json','["卷籜正離披，新枝復蒙密。", "翛翛月下聞，褭褭林際出。", "豈獨對芳菲，終年色如一。"]'),
('d79f3c3f-edf2-442b-9ee1-f12d5305b8b0','懷素上人草書歌','戴叔倫','唐','唐诗','tang','','[]','楚僧懷素工草書，古法盡能新有餘。',112,'全唐诗/poet.tang.14000.json','["楚僧懷素工草書，古法盡能新有餘。", "神清骨竦意真率，醉來爲我揮健筆。", "始從破體變風姿，一一花開春景遲。", "忽爲壯麗就枯澀，龍蛇騰盤獸屹立。", "馳毫驟墨劇奔駟，滿座失聲看不及。", "心手相師勢轉奇，詭形怪狀翻合宜。", "人人細問此中妙，懷素自言初不知。"]'),
('065c182e-76f5-4777-b84e-e80651f509df','女耕田行','戴叔倫','唐','唐诗','tang','','[]','乳燕入巢笋成竹，誰家二女種新穀。',144,'全唐诗/poet.tang.14000.json','["乳燕入巢笋成竹，誰家二女種新穀。", "無人無牛不及犁，持刀斫地翻作泥。", "自言家貧母年老，長兄從軍未娶嫂。", "去年災疫牛囤空，截絹買刀都市中。", "頭巾掩面畏人識，以刀代牛誰與同。", "姊妹相攜心正苦，不見路人唯見土。", "疏通畦隴防亂苗，整頓溝塍待時雨。", "日正南岡下餉歸，可憐朝雉擾驚飛。", "東鄰西舍花發盡，共惜餘芳淚滿衣。"]'),
('44916888-b8b7-4a9e-95fe-d18888843b29','柳花歌送客往桂陽','戴叔倫','唐','唐诗','tang','','[]','滄浪渡頭柳花發，斷續因風飛不絕。',80,'全唐诗/poet.tang.14000.json','["滄浪渡頭柳花發，斷續因風飛不絕。", "搖烟拂水積翠間，綴雪含霜誰忍攀。", "夾岸紛紛送君去，鳴櫂孤尋到何處。", "移家深入桂水源，種柳新成花更繁。", "定知別後消散盡，却憶今朝傷旅魂。"]'),
('c1250a5c-8655-4616-86bd-bae55f8ec692','邊城曲','戴叔倫','唐','唐诗','tang','','[]','人生莫作遠行客，遠行莫戍黃沙磧。',96,'全唐诗/poet.tang.14000.json','["人生莫作遠行客，遠行莫戍黃沙磧。", "黃沙磧下八月時，霜風裂膚百草衰。", "塵沙晴天迷道路，河水悠悠向東去。", "胡笳聽徹雙淚流，羈魂慘慘生邊愁。", "原頭獵火夜相向，馬蹄蹴蹋層冰上。", "不似京華俠少年，清歌妙舞落花前。"]'),
('95949c09-0922-413f-9e5d-9bfb356d8f04','屯田詞','戴叔倫','唐','唐诗','tang','','[]','春來耕田遍沙磧，老稚欣欣種禾麥。',112,'全唐诗/poet.tang.14000.json','["春來耕田遍沙磧，老稚欣欣種禾麥。", "麥苗漸長天苦晴，土乾确确鉏不得。", "新禾未熟飛蝗至，青苗食盡餘枯莖。", "捕蝗歸來守空屋，囊無寸帛缾無粟。", "十月移屯來向城，官教去伐南山木。", "驅牛駕車入山去，霜重草枯牛凍死。", "艱辛歷盡誰得知，望斷天南淚如雨。"]'),
('31c410b3-6b61-4398-86e5-e4a6bfe07087','巫山高','戴叔倫','唐','唐诗','tang','','[]','巫山峨峨高插天，危峰十二凌紫煙。',94,'全唐诗/poet.tang.14000.json','["巫山峨峨高插天，危峰十二凌紫煙。", "瞿塘嘈嘈急如弦，洄流勢逆將覆船。", "雲梯豈可進，百[丈]那能牽，陸行巉巖水不前。", "灑淚向流水，淚歸東海邊。", "含愁對明月，明月空自圓。", "故鄉回首思綿綿，側身天地心茫然。"]'),
('d39ab0c0-9771-4cce-910d-94eaddaf2908','早春曲','戴叔倫','唐','唐诗','tang','','[]','青樓昨夜東風轉，錦帳凝寒覺春淺。',96,'全唐诗/poet.tang.14000.json','["青樓昨夜東風轉，錦帳凝寒覺春淺。", "垂楊搖絲鶯亂啼，褭褭煙光不堪翦。", "博山吹雲龍腦香，銅壺滴愁更漏長。", "玉頰啼紅夢初醒，羞見青鸞鏡中影。", "儂家少年愛游逸，萬里輪蹄去無跡。", "朱顏未衰消息稀，腸斷天涯草空碧。"]'),
('0a629440-590c-46f8-ba98-f6e33a16a910','白苧詞','戴叔倫','唐','唐诗','tang','','[]','館娃宮中露華冷，月落啼鵶散金井。',128,'全唐诗/poet.tang.14000.json','["館娃宮中露華冷，月落啼鵶散金井。", "吳王扶頭酒初醒，秉燭張筵樂清景。", "美人不眠憐夜永，起舞亭亭亂花影。", "新裁白苧勝紅綃，玉佩珠纓金步搖。", "回鸞轉鳳意自嬌，銀箏錦瑟聲相調。", "君恩如水流不斷，但願年年此同宵。", "東風吹花落庭樹，春色催人等閑去。", "大家爲歡莫延佇，頃刻銅龍報天曙。"]'),
('a032115c-e129-487b-b0cb-c8d15f01d2a7','行路難','戴叔倫','唐','唐诗','tang','','[]','出門行路難，富貴安可期。',124,'全唐诗/poet.tang.14000.json','["出門行路難，富貴安可期。", "淮陰不免惡少辱，阮生亦作窮途悲。", "顛倒英雄古來有，封侯却屬屠沽兒。", "長安車馬隨輕肥，青雲賓從紛交馳。", "白眼向人多意氣，宰牛烹羊如折葵。", "讌樂寧知白日短，時時醉擁雙蛾眉。", "揚雄閉門空讀書，門前碧草春離離。", "不如拂衣且歸去，世上浮名徒爾爲。"]'),
('032ae665-b243-47cb-bce0-29ba76ab5871','相思曲','戴叔倫','唐','唐诗','tang','','[]','高樓重重閉明月，腸斷僊郎隔年別。',128,'全唐诗/poet.tang.14000.json','["高樓重重閉明月，腸斷僊郎隔年別。", "紫簫橫笛寂無聲，獨向瑤窗坐愁絕。", "魚沈鴈杳天涯路，始信人間別離苦。", "恨滿牙牀翡翠衾，怨折金釵鳳皇股。", "井深轆轤嗟綆短，衣帶相思日應緩。", "將刀斫水水復連，揮刃割情情不斷。", "落紅亂逐東流水，一點芳心爲君死。", "妾身願作巫山雲，飛入仙郎夢魂裏。"]'),
('aa2573dd-66a5-4d1b-93a7-8ebd842af47c','送別錢起','戴叔倫','唐','唐诗','tang','','[]','陽關多古調，無奈醉中聞。',48,'全唐诗/poet.tang.14000.json','["陽關多古調，無奈醉中聞。", "歸夢吳山遠，離情楚水分。", "孤舟經暮雨，征路入秋雲。", "後夜同明月，山窗定憶君。"]'),
('ccf2d9c1-f855-415f-929b-6609bc18b8ab','送張南史','戴叔倫','唐','唐诗','tang','','[]','陋巷無車轍，煙蘿總是春。',48,'全唐诗/poet.tang.14000.json','["陋巷無車轍，煙蘿總是春。", "賈生獨未達，原憲竟忘貧。", "草座留山月，荷衣遠洛塵。", "最憐知己在，林下訪閑人。"]'),
('4de7087b-106a-46c1-bba4-cb54c90be50c','春日早朝應制','戴叔倫','唐','唐诗','tang','','[]','仙仗肅朝官，承平聖主歡。',48,'全唐诗/poet.tang.14000.json','["仙仗肅朝官，承平聖主歡。", "月沈宮漏靜，雨濕禁花寒。", "丹荔來金闕，朱櫻貢玉盤。", "六龍扶御日，只許近臣看。"]'),
('85664d8d-957f-45b3-8943-653dfe6f9570','早行寄朱山人放','戴叔倫','唐','唐诗','tang','','[]','山曉旅人去，天高秋氣悲。',48,'全唐诗/poet.tang.14000.json','["山曉旅人去，天高秋氣悲。", "明河川上沒，芳草露中衰。", "此別又千里，少年能幾時。", "心知剡溪路，聊且寄前期。"]'),
('0b8ef604-25bb-4670-baee-590b8bd7a99f','除夜宿石頭驛','戴叔倫','唐','唐诗','tang','','["\u5b64\u72ec", "\u601d\u4e61", "\u6625\u8282"]','旅館誰相問，寒燈獨可親。',48,'全唐诗/poet.tang.14000.json','["旅館誰相問，寒燈獨可親。", "一年將盡夜，萬里未歸人。", "寥落悲前事，支離笑此身。", "愁顏與衰鬢，明日又逢春。"]'),
('5502f772-645a-44bb-a825-797ef4a8bc2d','吳明府自遠而來留宿','戴叔倫','唐','唐诗','tang','','[]','出門逢故友，衣服滿塵埃。',48,'全唐诗/poet.tang.14000.json','["出門逢故友，衣服滿塵埃。", "歲月不可問，山川何處來。", "綺城容弊宅，散職寄靈臺。", "自此留君醉，相歡得幾回。"]'),
('94ae3e7e-eb5d-414c-bfd6-124f50687ce5','客夜與故人偶集','戴叔倫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53cb\u60c5", "\u5199\u666f", "\u79cb\u5929", "\u4e94\u8a00\u5f8b\u8bd7", "\u76f8\u805a"]','天秋月又滿，城闕夜千重。',48,'全唐诗/poet.tang.14000.json','["天秋月又滿，城闕夜千重。", "還作江南會，翻疑夢裏逢。", "風枝驚暗鵲，露草覆寒蛩。", "羈旅長堪醉，相留畏曉鐘。"]'),
('a3bcc6e4-b13f-4000-961e-d5d77850bf28','送友人東歸','戴叔倫','唐','唐诗','tang','','[]','萬里楊柳色，出關送故人。',48,'全唐诗/poet.tang.14000.json','["萬里楊柳色，出關送故人。", "輕煙拂流水，落日照行塵。", "積夢江湖闊，憶家兄弟貧。", "裴回灞亭上，不語自傷春。"]'),
('2547b0a5-ba78-40c9-b95a-1c9ad3840518','江上別張歡','戴叔倫','唐','唐诗','tang','','[]','年年五湖上，厭見五湖春。',48,'全唐诗/poet.tang.14000.json','["年年五湖上，厭見五湖春。", "長醉非關酒，多愁不爲貧。", "山川迷道路，伊洛困風塵。", "今日扁舟別，俱爲滄海人。"]'),
('9d48316f-ab78-4a8e-b47e-87c28cde1763','廣陵送趙主簿自蜀歸絳州寧覲','戴叔倫','唐','唐诗','tang','','[]','將歸汾水上，遠省錦城來。',48,'全唐诗/poet.tang.14000.json','["將歸汾水上，遠省錦城來。", "已泛西江盡，仍隨北鴈迴。", "暮雲征馬速，曉月故關開。", "漸向庭闈近，留君醉一杯。"]'),
('5a7a3460-b622-461e-90a4-4838330f236f','別友人','戴叔倫','唐','唐诗','tang','','[]','擾擾倦行役，相逢陳蔡間。',48,'全唐诗/poet.tang.14000.json','["擾擾倦行役，相逢陳蔡間。", "如何百年內，不見一人閑。", "對酒惜餘景，問程愁亂山。", "秋風萬里道，又出穆陵關。"]'),
('15d8fec3-5fcc-4b52-acb2-f405b374e67d','宿城南盛本道懷皇甫冉','戴叔倫','唐','唐诗','tang','','[]','暑夜宿[南城]，懷人夢不成。',50,'全唐诗/poet.tang.14000.json','["暑夜宿[南城]，懷人夢不成。", "高樓邀落月，疊鼓送殘更。", "隔浦雲林近，滿川風露清。", "東碕不可見，矯首若爲情。"]'),
('037dbc62-bcf2-4ab9-b784-5eb36fceb76f','暉上人獨坐亭','戴叔倫','唐','唐诗','tang','','[]','蕭條心境外，兀坐獨參禪。',48,'全唐诗/poet.tang.14000.json','["蕭條心境外，兀坐獨參禪。", "蘿月明盤石，松風落潤泉。", "性空長入定，心悟自通玄。", "去住渾無跡，青山謝世緣。"]'),
('d681657c-0c46-43c2-b207-9ef5caf0c494','送崔融','戴叔倫','唐','唐诗','tang','','[]','王者應無敵，天兵動遠征。',48,'全唐诗/poet.tang.14000.json','["王者應無敵，天兵動遠征。", "建牙連朔漠，飛騎入胡城。", "夜月邊城影，秋風隴水聲。", "陳琳能草檄，含笑出長平。"]'),
('53271d0c-d102-4246-9bb3-2bceeebfa579','遊少林寺','戴叔倫','唐','唐诗','tang','','[]','步入招提路，因之訪道林。',48,'全唐诗/poet.tang.14000.json','["步入招提路，因之訪道林。", "石龕苔蘚積，香徑白雲深。", "雙樹含秋色，孤峰起夕陰。", "屧廊行欲遍，回首一長吟。"]'),
('9032f0a7-5e1b-4a5e-9170-1e66d98304ef','崇德道中','戴叔倫','唐','唐诗','tang','','[]','暖日菜心稠，晴煙麥穗抽。',48,'全唐诗/poet.tang.14000.json','["暖日菜心稠，晴煙麥穗抽。", "客心雙去翼，歸夢一扁舟。", "廢塔巢雙鶴，長波漾白鷗。", "關山明月到，愴惻十年遊。"]'),
('6455fe19-27eb-4b87-afd7-b4f873e100c7','雨','戴叔倫','唐','唐诗','tang','','[]','歷歷愁心亂，迢迢獨夜長。',48,'全唐诗/poet.tang.14000.json','["歷歷愁心亂，迢迢獨夜長。", "春帆江上雨，曉鏡鬢邊霜。", "啼鳥雲山靜，落花溪水香。", "家人亦念我，與汝黯相忘。"]'),
('ec3fc263-bbc7-4291-8bc7-2d03a1c1b8f8','過賈誼宅','戴叔倫','唐','唐诗','tang','','[]','一謫長沙地，三年歎逐臣。',48,'全唐诗/poet.tang.14000.json','["一謫長沙地，三年歎逐臣。", "上書憂漢室，作賦弔靈均。", "舊宅秋荒草，西風客薦蘋。", "淒涼回首處，不見洛陽人。"]'),
('1be804ea-a0ce-4aea-9e39-887f68cf31b5','冬日有懷李賀長吉','戴叔倫','唐','唐诗','tang','','[]','歲晚齋居寂，情人動我思。',48,'全唐诗/poet.tang.14000.json','["歲晚齋居寂，情人動我思。", "每因一尊酒，重和百篇詩。", "月冷猨啼慘，天高鴈去遲。", "夜郎流落久，何日是歸期。"]'),
('c8f4531a-d998-405a-a731-6aad0d5e9ea8','送郎士元','戴叔倫','唐','唐诗','tang','','[]','白髮金陵客，懷歸不暫留。',48,'全唐诗/poet.tang.14000.json','["白髮金陵客，懷歸不暫留。", "交情分兩地，行色載孤舟。", "黃葉蟬吟晚，滄江鴈送秋。", "何年重會此，詩酒復追游。"]'),
('3d6d7013-76d1-4214-882f-3a1aad5c53f0','春江獨釣','戴叔倫','唐','唐诗','tang','','[]','獨釣春江上，春江引趣長。',48,'全唐诗/poet.tang.14000.json','["獨釣春江上，春江引趣長。", "斷煙栖草碧，流水帶花香。", "心事同沙鳥，浮生寄野航。", "荷衣塵不染，何用濯滄浪。"]'),
('7870f171-e37e-4db8-a185-11456878bc13','山居即事','戴叔倫','唐','唐诗','tang','','[]','巖雲掩竹扉，去鳥帶餘暉。',48,'全唐诗/poet.tang.14000.json','["巖雲掩竹扉，去鳥帶餘暉。", "地僻生涯薄，山深俗事稀。", "養花分宿雨，翦葉補秋衣。", "野渡逢漁子，同舟蕩月歸。"]'),
('3f692193-2a80-41b5-b4bf-47176d040535','賦得長亭柳','戴叔倫','唐','唐诗','tang','','[]','濯濯長亭柳，陰連灞水流。',48,'全唐诗/poet.tang.14000.json','["濯濯長亭柳，陰連灞水流。", "雨搓金縷細，煙褭翠絲柔。", "送客添新恨，聽鶯憶舊遊。", "贈行多折取，那得到深秋。"]'),
('3e8a4cd3-227f-4ab1-815e-1a3cd4ab8397','客中言懷','戴叔倫','唐','唐诗','tang','','[]','白髮照烏紗，逢人只自嗟。',48,'全唐诗/poet.tang.14000.json','["白髮照烏紗，逢人只自嗟。", "官閑如致仕，客久似無家。", "夜雨孤燈夢，春風幾度花。", "故園歸有日，詩酒老生涯。"]'),
('fa33b688-c3d1-4ad5-a22d-060ff0284ed1','山行','戴叔倫','唐','唐诗','tang','','[]','山行分曙色，一路見人稀。',48,'全唐诗/poet.tang.14000.json','["山行分曙色，一路見人稀。", "野鳥啼還歇，林花墮不飛。", "雲迷棲鶴寺，水澀釣魚磯。", "回首天將暝，逢僧話未歸。"]'),
('f7c428e4-35ed-46b6-baa2-557fe2465458','春日訪山人','戴叔倫','唐','唐诗','tang','','[]','遠訪山中客，分泉謾煮茶。',48,'全唐诗/poet.tang.14000.json','["遠訪山中客，分泉謾煮茶。", "相攜林下坐，共惜鬢邊華。", "歸路逢殘雨，沿溪見落花。", "候門童子問，遊樂到誰家。"]'),
('e18e44fa-1116-482b-b2b6-8924c2a93f6f','臥病','戴叔倫','唐','唐诗','tang','','[]','門掩青山臥，莓苔積雨深。',48,'全唐诗/poet.tang.14000.json','["門掩青山臥，莓苔積雨深。", "病多知藥性，客久見人心。", "衆鳥趨林健，孤蟬抱葉吟。", "滄洲詩社散，無夢盍朋簪。"]'),
('4882d2c6-162e-4d85-981d-33248c715568','贈月溪羽士','戴叔倫','唐','唐诗','tang','','[]','月明溪水上，誰識步虛聲。',48,'全唐诗/poet.tang.14000.json','["月明溪水上，誰識步虛聲。", "夜靜金波冷，風微玉練平。", "自知塵夢遠，一洗道心清。", "更弄瑤笙罷，秋空鶴又鳴。"]'),
('620d8028-e841-4433-b452-79da14a217b1','贈行脚僧','戴叔倫','唐','唐诗','tang','','[]','補衲隨緣住，難違塵外蹤。',48,'全唐诗/poet.tang.14000.json','["補衲隨緣住，難違塵外蹤。", "木杯能渡水，鐵鉢肯降龍。", "到處棲雲榻，何年臥雪峰。", "知師歸日近，應偃舊房松。"]'),
('af70ca68-0b8e-4066-a608-d3b99d5be866','重遊長真寺','戴叔倫','唐','唐诗','tang','','[]','同到長真寺，青山四面同。',48,'全唐诗/poet.tang.14000.json','["同到長真寺，青山四面同。", "鳥啼花竹暗，人散戶庭空。", "蒲潤千年雨，松門午夜風。", "舊遊悲往日，回首各西東。"]'),
('d66100e5-9fac-4ff9-8da7-43726dfc54d9','晚望','戴叔倫','唐','唐诗','tang','','[]','山氣碧氤氳，深林帶夕曛。',48,'全唐诗/poet.tang.14000.json','["山氣碧氤氳，深林帶夕曛。", "人歸孤嶂晚，犬吠隔溪雲。", "杉竹何年種，煙塵此地分。", "桃源寧異此，猶恐世間聞。"]'),
('8c0e9034-1e1e-404a-99de-123ede62a56e','寄贈翠巖奉上人','戴叔倫','唐','唐诗','tang','','[]','蘭若倚西岡，年深松桂長。',48,'全唐诗/poet.tang.14000.json','["蘭若倚西岡，年深松桂長。", "似聞葛洪井，還近贊公房。", "挂衲雲林靜，翻經石榻涼。", "下方一回首，煙露日蒼蒼。"]'),
('c3321e8d-59fb-4be6-845c-f623b00e1c1e','過龍灣五王閣訪友人不遇','戴叔倫','唐','唐诗','tang','','[]','野橋秋水落，江閣暝煙微。',48,'全唐诗/poet.tang.14000.json','["野橋秋水落，江閣暝煙微。", "白日又欲午，高人猶未歸。", "青林依古塔，虛館靜柴扉。", "坐久思題字，翻憐柿葉稀。"]'),
('a75e3e5f-b328-44e8-8294-5f1b1a5e1c0c','與友人過山寺','戴叔倫','唐','唐诗','tang','','[]','共有春山興，幽尋此日同。',48,'全唐诗/poet.tang.14000.json','["共有春山興，幽尋此日同。", "談詩訪靈徹，入社愧陶公。", "竹暗閉房雨，茶香別院風。", "誰知塵境外，路與白雲通。"]'),
('0ad19dbe-d1cc-45ca-bfd2-bf5e13a4d2ba','賦得古井送王明府','戴叔倫','唐','唐诗','tang','','[]','古井庇幽亭，涓涓一竇明。',48,'全唐诗/poet.tang.14000.json','["古井庇幽亭，涓涓一竇明。", "仙源通海水，靈液孕山精。", "久旱寧同涸，長年秪自清。", "欲彰貞白操，酌獻使君行。"]'),
('a5f02dc7-f833-49d8-a67d-1b2f6684150e','送耿十三湋復往遼海','戴叔倫','唐','唐诗','tang','','[]','仗劍萬里去，孤城遼海東。',48,'全唐诗/poet.tang.14000.json','["仗劍萬里去，孤城遼海東。", "旌旗愁落日，鼓角壯悲風。", "野迥邊塵息，烽消戍壘空。", "轅門正休暇，投策拜元戎。"]'),
('02b2dd5f-2f9f-4d33-a641-6ba7d7493b59','寄禪師寺華上人次韻三首 一','戴叔倫','唐','唐诗','tang','','[]','百年渾是客，白髮總盈顛。',48,'全唐诗/poet.tang.14000.json','["百年渾是客，白髮總盈顛。", "佛國三秋別，雲臺五色連。", "朝盤香積飯，夜甕落花泉。", "遙憶談玄地，月高人未眠。"]'),
('569d13a9-3432-4c46-8008-3abf484a41ba','寄禪師寺華上人次韻三首 二','戴叔倫','唐','唐诗','tang','','[]','禪心如落葉，不逐曉風顛。',48,'全唐诗/poet.tang.14000.json','["禪心如落葉，不逐曉風顛。", "猊坐翻蕭瑟，臯比喜接連。", "芙蓉開紫霧，湘玉映清泉。", "白晝談經罷，閑從石上眠。"]'),
('65d1fa84-153c-4a45-95da-f90cb66f36a5','寄禪師寺華上人次韻三首 三','戴叔倫','唐','唐诗','tang','','[]','德士名難避，風流學濟顛。',48,'全唐诗/poet.tang.14000.json','["德士名難避，風流學濟顛。", "禮羅加璧至，薦鶚與雲連。", "塵世休飛錫，松林且枕泉。", "近聞離講席，聽雨半山眠。"]'),
('40170491-a095-4f94-aad8-d556180cb33b','獨坐','戴叔倫','唐','唐诗','tang','','[]','白髮懷閩嶠，丹心戀薊門。',48,'全唐诗/poet.tang.14000.json','["白髮懷閩嶠，丹心戀薊門。", "官閑勝道院，宅遠類荒村。", "二月霜花薄，羣山雨氣昏。", "東菑春事及，好向野人論。"]'),
('46f4cc6a-a027-4a06-84a9-56395fb8f130','李大夫見贈因之有呈','戴叔倫','唐','唐诗','tang','','[]','何言訪衰疾，旌斾重淹留。',48,'全唐诗/poet.tang.14000.json','["何言訪衰疾，旌斾重淹留。", "謝禮誠難荅，裁詩豈易酬。", "江清寒照動，山迥野雲秋。", "一醉龍沙上，終歡勝舊遊。"]'),
('eea8e448-8578-44f3-8040-0c108cf016ff','長沙送梁副端歸京','戴叔倫','唐','唐诗','tang','','[]','奏書歸闕下，祖帳出湘東。',48,'全唐诗/poet.tang.14000.json','["奏書歸闕下，祖帳出湘東。", "滿座他鄉別，何年此會同。", "藉芳憐岸草，聞笛怨江風。", "且莫乘流去，心期在醉中。"]'),
('429399f8-4683-45ff-9a0d-6e5267513bb2','和尉遲侍郎夏杪聞蟬','戴叔倫','唐','唐诗','tang','','[]','楚人方苦熱，柱史獨聞蟬。',48,'全唐诗/poet.tang.14000.json','["楚人方苦熱，柱史獨聞蟬。", "晴日暮江上，驚風一葉前。", "蕩搖清管雜，幽咽野風傳。", "旅舍聞君聽，無由更晝眠。"]'),
('923eceba-072c-4fe4-b193-6fd190839a14','和李相公勉晦日蓬池遊宴','戴叔倫','唐','唐诗','tang','','[]','高會吹臺中，新年月桂空。',48,'全唐诗/poet.tang.14000.json','["高會吹臺中，新年月桂空。", "貂蟬臨野水，旌斾引春風。", "細草縈斜岸，纖條出故叢。", "微文復看獵，寧與解神同。"]'),
('eec91480-a38d-47e1-814e-2413278f6a6f','彭婆館逢韋判官使還','戴叔倫','唐','唐诗','tang','','[]','受辭分路遠，會府見君稀。',48,'全唐诗/poet.tang.14000.json','["受辭分路遠，會府見君稀。", "雨雪經年去，軒車此日歸。", "暮春愁見別，久客順相依。", "寂寞伊川上，楊花空自飛。"]'),
('55fb24cb-b3bd-400d-ab52-ce0d043574b9','酬別劉九郎評事傳經同泉字','戴叔倫','唐','唐诗','tang','','[]','舉袂掩離弦，枉君愁思篇。',48,'全唐诗/poet.tang.14000.json','["舉袂掩離弦，枉君愁思篇。", "忽驚池上鷺，下咽隴頭泉。", "對牖牆陰滿，臨扉日影圓。", "賴聞黃太守，章句此中傳。"]'),
('72f66359-5261-40fe-aa02-0858906f0598','漢南遇方評事','戴叔倫','唐','唐诗','tang','','[]','移家住漢陰，不復問華簪。',48,'全唐诗/poet.tang.14000.json','["移家住漢陰，不復問華簪。", "貰酒宜城近，燒田夢澤深。", "暮山逢鳥入，寒水見魚沈。", "與物皆無累，終年愜本心。"]'),
('8090e457-24df-4e6c-996b-3b81bb0d82a0','湘中懷古','戴叔倫','唐','唐诗','tang','','[]','昔人從逝水，有客弔秋風。',48,'全唐诗/poet.tang.14000.json','["昔人從逝水，有客弔秋風。", "何意千年隔，論心一日同。", "楚亭方作亂，漢律正酬功。", "倏忽桑田變，讒言亦已空。"]'),
('793368a9-a932-42cc-bf9c-e959f80b45eb','京口懷古','戴叔倫','唐','唐诗','tang','','[]','大江橫萬里，古渡渺千秋。',48,'全唐诗/poet.tang.14000.json','["大江橫萬里，古渡渺千秋。", "浩浩波聲險，蒼蒼天色愁。", "三方歸漢鼎，一水限吳州。", "霸國今何在，清泉長自流。"]'),
('e63f90cc-4ef7-4234-b76e-2532517ff7b6','逢友生言懷','戴叔倫','唐','唐诗','tang','','[]','安親非避地，羈旅十餘年。',48,'全唐诗/poet.tang.14000.json','["安親非避地，羈旅十餘年。", "道長時流許，家貧故舊憐。", "相逢今歲暮，遠別一方偏。", "去住俱難說，江湖正渺然。"]'),
('7b4d67f8-36ac-41eb-a77a-d1c8f6124b41','長門怨','戴叔倫','唐','唐诗','tang','','[]','自憶專房寵，曾居第一流。',48,'全唐诗/poet.tang.14000.json','["自憶專房寵，曾居第一流。", "移恩向他處，暫妒不容收。", "夜靜管弦絕，月明宮殿秋。", "空將舊時意，長望鳳皇樓。"]'),
('e764d248-d37f-476d-8b21-a0e670462087','郊園即事寄蕭侍郎','戴叔倫','唐','唐诗','tang','','[]','衰鬢辭餘秩，秋風入故園。',48,'全唐诗/poet.tang.14000.json','["衰鬢辭餘秩，秋風入故園。", "結茅成暖室，汲井及清源。", "鄰里桑麻接，兒童笑語喧。", "終朝非役役，聊寄遠人言。"]'),
('95714d30-d40c-4390-9100-eb148b6b28c4','贈韋評事儹','戴叔倫','唐','唐诗','tang','','[]','與道共浮沈，人間歲月深。',48,'全唐诗/poet.tang.14000.json','["與道共浮沈，人間歲月深。", "是非園吏夢，憂喜塞翁心。", "細草誰開徑，芳條自結陰。", "由來居物外，無事可抽簪。"]'),
('ba352bc9-9eb6-4886-923f-07330f530e54','送少微上人入蜀','戴叔倫','唐','唐诗','tang','','[]','十方俱是夢，一念偶尋山。',48,'全唐诗/poet.tang.14000.json','["十方俱是夢，一念偶尋山。", "望剎經巴寺，持瓶向蜀關。", "亂猨心本定，流水性長閑。", "世俗多離別，王城幾日還。"]'),
('1752fbf4-95f6-4138-989f-9c19a6bd4106','送道虔上人遊方','戴叔倫','唐','唐诗','tang','','[]','律儀通外學，詩思入禪關。',48,'全唐诗/poet.tang.14000.json','["律儀通外學，詩思入禪關。", "煙景隨緣到，風姿與道閑。", "貫花留靜室，咒水度空山。", "誰識浮雲意，悠悠天地間。"]'),
('10413ab8-4600-43cc-956f-045ce6b1e6dd','送嵩律師頭陁寺','戴叔倫','唐','唐诗','tang','','[]','相傳五部學，更有一人成。',48,'全唐诗/poet.tang.14000.json','["相傳五部學，更有一人成。", "此日靈山去，何方半座迎。", "麻衣逢雪暖，草履躡雲輕。", "若見中林石，應知第四生。"]'),
('f12ad26b-b20f-49cb-846d-3499b611e290','舟中見雨','戴叔倫','唐','唐诗','tang','','[]','今夜初聽雨，江南杜若青。',48,'全唐诗/poet.tang.14000.json','["今夜初聽雨，江南杜若青。", "功名何鹵莽，兄弟總彫零。", "夢遠愁蝴蝶，情深愧鶺鴒。", "撫孤終日意，身世尚流萍。"]'),
('cbea4caf-5ceb-43fd-8a50-843fe173c2ac','送僧南歸','戴叔倫','唐','唐诗','tang','','[]','兵塵猶澒洞，僧舍亦徵求。',48,'全唐诗/poet.tang.14000.json','["兵塵猶澒洞，僧舍亦徵求。", "師向江南去，予方轂下留。", "風霜兩足白，宇宙一身浮。", "歸及梅花發，題詩寄隴頭。"]'),
('cbd647c8-41ad-43eb-bce7-855eb14d8cc2','江干','戴叔倫','唐','唐诗','tang','','[]','江干望不極，樓閣影繽紛。',48,'全唐诗/poet.tang.14000.json','["江干望不極，樓閣影繽紛。", "水氣多爲雨，人煙遠是雲。", "予生何濩落，客路轉辛勤。", "楊柳牽愁思，和春上翠帬。"]'),
('fbf0e38a-50c3-40f9-80a3-cd1246aa8288','過友人隱居','戴叔倫','唐','唐诗','tang','','[]','瀟灑絕塵喧，清溪流遶門。',48,'全唐诗/poet.tang.14000.json','["瀟灑絕塵喧，清溪流遶門。", "水聲鳴石瀨，蘿影到林軒。", "地靜留眠鹿，庭虛下飲猨。", "春花正夾岸，何必問桃源。"]'),
('724a9196-3c47-4e7c-8870-e793ee066415','宿天竺寺曉發羅源','戴叔倫','唐','唐诗','tang','','[]','黃昏投古寺，深院一燈明。',48,'全唐诗/poet.tang.14000.json','["黃昏投古寺，深院一燈明。", "水砌長杉列，風廊敗葉鳴。", "山雲留別偈，王事速歸程。", "迢遰羅源路，輕輿候曉行。"]'),
('baaa5dfa-6510-474c-99f9-a03c32768b4d','留宿羅源西峰寺示輝上人','戴叔倫','唐','唐诗','tang','','[]','一宿西峰寺，塵煩暫覺清。',48,'全唐诗/poet.tang.14000.json','["一宿西峰寺，塵煩暫覺清。", "遠林生夕籟，高閣起鐘聲。", "山寂僧初定，廊深火自明。", "雖云殊出處，聊與說無生。"]'),
('06f1624e-7ad1-4ca1-b946-6254b905f1a2','題橫山寺','戴叔倫','唐','唐诗','tang','','[]','偶入橫山寺，湖山景最幽。',48,'全唐诗/poet.tang.14000.json','["偶入橫山寺，湖山景最幽。", "露涵松翠濕，風湧浪花浮。", "老衲供茶盌，斜陽送客舟。", "自緣歸思促，不得更遲留。"]'),
('19e5262b-b22a-4cc5-b251-46d7a8d4cb89','泛舟','戴叔倫','唐','唐诗','tang','','[]','風軟扁舟穩，行依綠水堤。',48,'全唐诗/poet.tang.14000.json','["風軟扁舟穩，行依綠水堤。", "孤尊秋露滑，短櫂晚煙迷。", "夜靜月初上，江空天更低。", "飄飄信流去，悞過子猷溪。"]'),
('86791562-7f76-43b0-b239-598d641fadd3','宿靈巖寺','戴叔倫','唐','唐诗','tang','','[]','馬疲盤道峻，投宿入招提。',48,'全唐诗/poet.tang.14000.json','["馬疲盤道峻，投宿入招提。", "雨急山溪漲，雲迷嶺樹低。", "涼風來殿角，赤日下天西。", "偃腹虛簷外，林空鳥恣啼。"]'),
('0d105844-3175-4e39-90ba-bb869891646e','江上別劉駕','戴叔倫','唐','唐诗','tang','','[]','天涯芳草遍，江路又逢春。',48,'全唐诗/poet.tang.14000.json','["天涯芳草遍，江路又逢春。", "海月留人醉，山花笑客貧。", "離杯傾祖帳，征騎逐行塵。", "回首風流地，登臨少一人。"]'),
('102ba9a8-65ac-4347-baf5-21fef20bcc65','南軒','戴叔倫','唐','唐诗','tang','','[]','野居何處是，軒外一橫塘。',48,'全唐诗/poet.tang.14000.json','["野居何處是，軒外一橫塘。", "座納薰風細，簾垂白日長。", "面山如對畫，臨水坐流觴。", "更愛閑花木，欣欣得向陽。"]'),
('f878d7c0-7f8b-4deb-bebb-d450bb7ac331','泊鴈','戴叔倫','唐','唐诗','tang','','[]','泊鴈鳴深渚，收霞落晚川。',48,'全唐诗/poet.tang.14000.json','["泊鴈鳴深渚，收霞落晚川。", "柝隨風斂陣，樓映月低弦。", "漠漠汀帆轉，幽幽岸火然。", "壑危通細路，溝曲繞平田。"]'),
('3e8f776f-0c85-48a6-8565-da85a2ab2123','巡諸州漸次空靈戍','戴叔倫','唐','唐诗','tang','','[]','寒盡鴻先至，春回客未歸。',48,'全唐诗/poet.tang.14000.json','["寒盡鴻先至，春回客未歸。", "蚤知名是病，不敢繡爲衣。", "霧積川原暗，山多郡縣稀。", "明朝下湘岸，更逐鷓鴣飛。"]'),
('d071b0f6-bdaa-42be-96df-ab00f8186a52','潭州使院書情寄江夏賀蘭副端','戴叔倫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','雲雨一蕭散，悠悠關復河。',48,'全唐诗/poet.tang.14000.json','["雲雨一蕭散，悠悠關復河。", "俱從汎舟役，近隔洞庭波。", "楚水去不盡，秋風今又過。", "無因得相見，却恨寄書多。"]'),
('c8284ada-18a4-46ad-8a47-c2b0c02204ff','過柳州','戴叔倫','唐','唐诗','tang','','[]','地盡江南戍，山分桂北林。',48,'全唐诗/poet.tang.14000.json','["地盡江南戍，山分桂北林。", "火雲三月合，石路九疑深。", "暗谷隨風過，危橋共鳥尋。", "羈魂愁似絕，不復待猨吟。"]'),
('92a76081-ee79-4913-b0c4-b2163366db31','經巴東嶺','戴叔倫','唐','唐诗','tang','','[]','巴山不可上，徒馭亦裴回。',48,'全唐诗/poet.tang.14000.json','["巴山不可上，徒馭亦裴回。", "舊棧歌難度，朝雲濕未開。", "瀑泉飛雪雨，驚獸走風雷。", "此去無停候，征人幾日回。"]'),
('b725ab1b-8c34-4b5a-84e4-b675f8b69ebe','過申州','戴叔倫','唐','唐诗','tang','','[]','萬人曾戰死，幾處見休兵。',48,'全唐诗/poet.tang.14000.json','["萬人曾戰死，幾處見休兵。", "井邑初安堵，兒童未長成。", "涼風吹古木，野火入殘營。", "牢落千餘里，山空水復清。"]'),
('64cdc9bb-3c88-4415-afac-2b4e58aff020','次下牢韻','戴叔倫','唐','唐诗','tang','','[]','獨立荒亭上，蕭蕭對晚風。',48,'全唐诗/poet.tang.14000.json','["獨立荒亭上，蕭蕭對晚風。", "天高吳塞闊，日落楚山空。", "猨叫三聲斷，江流一水通。", "前程千萬里，一夕宿巴東。"]'),
('be93ebfd-afa5-4786-b428-079e7fb904e2','潘處士宅會別','戴叔倫','唐','唐诗','tang','','[]','相邀寒影晚，惜別故山空。',48,'全唐诗/poet.tang.14000.json','["相邀寒影晚，惜別故山空。", "鄰里疎林在，池塘野水通。", "十年難遇後，一醉幾人同。", "復此悲行子，蕭蕭逐轉蓬。"]'),
('ba70934d-2cd2-4c17-93d9-9fdddfc57807','暮春沐髮晦日書懷寄韋功曹渢李錄事從訓王少府純','戴叔倫','唐','唐诗','tang','','[]','朝沐敞南闈，盤跚待日晞。',48,'全唐诗/poet.tang.14000.json','["朝沐敞南闈，盤跚待日晞。", "持梳髮更落，覽鏡意多違。", "吾友見嘗少，春風去不歸。", "登高取一醉，猶可及芳菲。"]'),
('6de6b7e8-1416-4973-9c8e-1fb8583fe9ea','長安早春贈萬評事','戴叔倫','唐','唐诗','tang','','[]','春風歸戚里，曉日上花枝。',48,'全唐诗/poet.tang.14000.json','["春風歸戚里，曉日上花枝。", "清管新鶯發，重門細柳垂。", "經過千騎客，調笑五陵兒。", "何事靈臺客，狂歌自不知。"]'),
('de25722d-0e68-4f4b-9848-c00c6fd235b8','留別宋處士','戴叔倫','唐','唐诗','tang','','[]','留歡方繼燭，此會豈他人。',48,'全唐诗/poet.tang.14000.json','["留歡方繼燭，此會豈他人。", "鄉里遊從舊，兒童內外親。", "夜深愁不醉，老去別何頻。", "莫折園中柳，相看惜暮春。"]'),
('46932f6d-eead-473e-baa5-f4964c35256f','留別道州李使君圻','戴叔倫','唐','唐诗','tang','','[]','瀧路下丹徼，郵童揮畫橈。',48,'全唐诗/poet.tang.14000.json','["瀧路下丹徼，郵童揮畫橈。", "山回千騎隱，雲斷兩鄉遙。", "漁滬擁寒溜，畬田落遠燒。", "維舟更相憶，惆悵坐空宵。"]'),
('cb3dbb9b-a1f3-4d72-9cff-32e7dc1c9394','將遊東都留別包諫議','戴叔倫','唐','唐诗','tang','','[]','衰客慙墨綬，素舸逐秋風。',48,'全唐诗/poet.tang.14000.json','["衰客慙墨綬，素舸逐秋風。", "雲雨恩難報，江湖意已終。", "縣當仙洞口，路出故園東。", "唯有新離恨，長留夢寐中。"]'),
('e970ba00-44ec-487e-b91d-af402def0099','灞岸別友','戴叔倫','唐','唐诗','tang','','[]','車馬去遲遲，離言未盡時。',48,'全唐诗/poet.tang.14000.json','["車馬去遲遲，離言未盡時。", "看花一醉別，會面幾年期。", "樵路高山館，漁洲楚帝祠。", "南登回首處，猶得望京師。"]'),
('6e6a54ca-94ec-4d07-841e-117036eb2c4d','臨川從事還別崔法曹','戴叔倫','唐','唐诗','tang','','[]','謬官辭獲免，濫獄會平反。',48,'全唐诗/poet.tang.14000.json','["謬官辭獲免，濫獄會平反。", "遠與故人別，龍鍾望所言。", "陰天寒不雨，古木夜多猨。", "老病北歸去，餘年學灌園。"]'),
('5cab2b12-b5aa-4633-a0b0-5a7d30b33b4c','海上別薛舟','戴叔倫','唐','唐诗','tang','','[]','行旅悲搖落，風波厭別離。',48,'全唐诗/poet.tang.14000.json','["行旅悲搖落，風波厭別離。", "客程秋草遠，心事故人知。", "暮鳥翻江岸，征徒起路岐。", "自應無定所，還似欲相隨。"]'),
('e641d940-1046-4717-a1eb-e7eff336bc3b','婺州路別錄事','戴叔倫','唐','唐诗','tang','','[]','府中相見少，江上獨行遙。',48,'全唐诗/poet.tang.14000.json','["府中相見少，江上獨行遙。", "會日起離恨，新年別舊僚。", "春雲猶伴雪，寒渚未通潮。", "回首羣山暝，思君轉寂寥。"]'),
('068dc817-95dd-4f0f-8f5e-820afe25e3bb','建中癸亥歲奉天除夜宿武當山北茅平村','戴叔倫','唐','唐诗','tang','','[]','歲除日又暮，山險路仍新。',48,'全唐诗/poet.tang.14000.json','["歲除日又暮，山險路仍新。", "驅傳迷深谷，瞻星記北辰。", "古亭聊假寐，中夜忽逢人。", "相問皆嗚咽，傷心不待春。"]'),
('65156e09-c8f8-4bc2-b1f4-d03ffeed2745','京口送皇甫司馬副端曾舒州辭滿歸去東都','戴叔倫','唐','唐诗','tang','','[]','潮水忽復過，雲帆儼欲飛。',48,'全唐诗/poet.tang.14000.json','["潮水忽復過，雲帆儼欲飛。", "故園雙闕下，左宦十年歸。", "晚景照華髮，涼風吹繡衣。", "淹留更一醉，老去莫相違。"]'),
('b092a7d9-645f-47fd-bd75-76119951262d','送李審之桂州謁中丞叔','戴叔倫','唐','唐诗','tang','','[]','知音不可遇，才子向天涯。',48,'全唐诗/poet.tang.14000.json','["知音不可遇，才子向天涯。", "遠水下山急，孤舟上路賒。", "亂雲收暮雨，雜樹落疎花。", "到日應文會，風流勝阮家。"]'),
('4c1fbadd-5082-41a9-8db7-1b9d192aca1e','送王翁信及第歸江東舊隱','戴叔倫','唐','唐诗','tang','','[]','南行無俗侶，秋鴈與寒雲。',48,'全唐诗/poet.tang.14000.json','["南行無俗侶，秋鴈與寒雲。", "野趣自多愜，名香日總聞。", "吳山中路斷，浙水半江分。", "此地登臨慣，含情一送君。"]'),
('7d91e133-3234-446a-a944-7919d532da99','送李明府之任','戴叔倫','唐','唐诗','tang','','[]','身爲百里長，家寵五諸侯。',48,'全唐诗/poet.tang.14000.json','["身爲百里長，家寵五諸侯。", "含笑聽猨狖，搖鞭望斗牛。", "梅花堪比雪，芳草不知秋。", "別後南風起，相思夢嶺頭。"]'),
('1eaab85d-aa2b-4496-9d1c-3fd448789934','送郭太祝中孚歸江東','戴叔倫','唐','唐诗','tang','','[]','鄉人去欲盡，北鴈又南飛。',48,'全唐诗/poet.tang.14000.json','["鄉人去欲盡，北鴈又南飛。", "京洛風塵久，江湖音信稀。", "舊山知獨往，一醉莫相違。", "未得辭羈旅，無勞問是非。"]'),
('fa29734b-2c9f-4347-8923-e403f0633077','新秋夜寄江右友人','戴叔倫','唐','唐诗','tang','','[]','遙夜獨不寐，寂寥蓬戶中。',48,'全唐诗/poet.tang.14000.json','["遙夜獨不寐，寂寥蓬戶中。", "河明五陵上，月滿九門東。", "舊知親友散，故園江海空。", "懷歸正南望，此夕起秋風。"]'),
('4de1320f-f293-4f10-846b-1059c07aaab8','清明日送鄧芮二子還鄉','戴叔倫','唐','唐诗','tang','','[]','鐘鼓喧離日，車徒促夜裝。',48,'全唐诗/poet.tang.14000.json','["鐘鼓喧離日，車徒促夜裝。", "曉廚新變火，輕柳暗翻霜。", "傳鏡看華髮，持杯話故鄉。", "每嫌兒女淚，今日自霑裳。"]'),
('b49cb64c-709b-4fc0-bf82-ee616cbdc070','送謝夷甫宰餘姚縣','戴叔倫','唐','唐诗','tang','','[]','君去方爲宰，干戈尚未銷。',48,'全唐诗/poet.tang.14000.json','["君去方爲宰，干戈尚未銷。", "邑中殘老小，亂後少官僚。", "廨宇經兵火，公田沒海潮。", "到時應變俗，新政滿餘姚。"]'),
('16f2a421-f439-45f3-9fe5-b9948368568e','送柳道時余北還','戴叔倫','唐','唐诗','tang','','[]','征役各異路，煙波同旅愁。',48,'全唐诗/poet.tang.14000.json','["征役各異路，煙波同旅愁。", "輕橈上桂水，大艑下揚州。", "何處成後會，今朝分舊遊。", "離心比楊柳，蕭颯不勝秋。"]'),
('203982d6-d495-447c-ab81-0c07b54ff82a','送萬戶曹之任揚州便歸舊隱','戴叔倫','唐','唐诗','tang','','[]','擬歸雲壑去，聊寄宦名中。',48,'全唐诗/poet.tang.14000.json','["擬歸雲壑去，聊寄宦名中。", "俸祿資生事，文章實國風。", "聽潮回楚浪，看月照隋宮。", "儻有登樓望，還應伴庾公。"]'),
('764f58af-f3ba-4bc1-af61-f85d4e7d1500','送李長史縱之任常州','戴叔倫','唐','唐诗','tang','','[]','不與名利隔，且爲江漢遊。',48,'全唐诗/poet.tang.14000.json','["不與名利隔，且爲江漢遊。", "吳山本佳麗，謝客舊淹留。", "狹道通陵口，貧家住蔣州。", "思歸復怨別，寥落詎關秋。"]'),
('e474b107-4081-4a41-9cb9-e793f55b03fe','南賓送蔡侍御遊蜀','戴叔倫','唐','唐诗','tang','','[]','巴江秋欲盡，遠別更淒然。',48,'全唐诗/poet.tang.14000.json','["巴江秋欲盡，遠別更淒然。", "月照高唐峽，人隨賈客船。", "積雲藏嶮路，流水促行年。", "不料相逢日，空悲尊酒前。"]'),
('499e451a-6e1f-4d38-8988-2231069d6fbb','送崔拾遺峒江淮訪圖書','戴叔倫','唐','唐诗','tang','','[]','九門思諫議，萬里採風謠。',48,'全唐诗/poet.tang.14000.json','["九門思諫議，萬里採風謠。", "關外逢秋月，天涯過晚潮。", "鴈來雲杳杳，木落浦蕭蕭。", "空怨他鄉別，迴舟暮寂寥。"]'),
('46e33ccd-cb7d-43a6-aec1-7fe7281d1859','九日送洛陽李丞之任','戴叔倫','唐','唐诗','tang','','[]','爲文通絕境，從宦及良辰。',48,'全唐诗/poet.tang.14000.json','["爲文通絕境，從宦及良辰。", "洛下知名早，腰邊結綬新。", "且傾浮菊酒，聊拂染衣塵。", "獨恨滄波侶，秋來別故人。"]'),
('0419bd57-d2e1-4a94-a893-63b42eb0d986','奉陪李大夫九日宴龍沙','戴叔倫','唐','唐诗','tang','','[]','邦君採菊地，近接旅人居。',48,'全唐诗/poet.tang.14000.json','["邦君採菊地，近接旅人居。", "一命招衰疾，清光照里閭。", "去官慚比謝，下榻貴同徐。", "莫怪沙邊倒，偏霑杯酌餘。"]'),
('64882e32-e727-47ef-be16-1218fa9dab76','送車參軍江陵','戴叔倫','唐','唐诗','tang','','[]','槐花落盡柳陰清，蕭索涼天楚客情。',64,'全唐诗/poet.tang.14000.json','["槐花落盡柳陰清，蕭索涼天楚客情。", "海上舊山無的信，東門歸路不堪行。", "身隨幻境勞多事，跡學禪心厭有名。", "公子道存知不棄，欲依劉表住南荆。"]'),
('4a321972-1f6e-4382-b373-bf3cc516f92c','遊清溪蘭若','戴叔倫','唐','唐诗','tang','','[]','西看疊嶂幾千重，秀色孤標此一峰。',64,'全唐诗/poet.tang.14000.json','["西看疊嶂幾千重，秀色孤標此一峰。", "丹竈久閑荒宿草，碧溪深處有潛龍。", "靈仙已去空巖室，到客唯聞古寺鐘。", "遠對白雲幽隱在，年年不離舊杉松。"]'),
('d111558f-6992-4035-a2e1-e0df14c121b7','贈史開府','戴叔倫','唐','唐诗','tang','','[]','南天胡馬獨悲嘶，白首相逢話鼓鼙。',64,'全唐诗/poet.tang.14000.json','["南天胡馬獨悲嘶，白首相逢話鼓鼙。", "野戰頻年沙朔外，旌竿高與雪峰齊。", "扁舟遠泛輕全楚，落日愁看舊紫泥。", "早晚瑤階歸伏奏，獨能畫地取關西。"]'),
('5b63e28a-eabe-4695-b668-4d72e6e0713f','登樓望月寄鳳翔李少尹','戴叔倫','唐','唐诗','tang','','[]','陌上涼風槐葉凋，夕陽清露濕寒條。',64,'全唐诗/poet.tang.14000.json','["陌上涼風槐葉凋，夕陽清露濕寒條。", "登樓望月楚山迥，月到南樓山獨遙。", "心送情人趨鳳闕，目隨陽鴈極煙霄。", "軒轅不重無名客，此地還能訪寂寥。"]'),
('72b33b12-2a42-43b0-9327-b3b5cb7bf35b','和汴州李相公勉人日喜春','戴叔倫','唐','唐诗','tang','','[]','年來日日春光好，今日春光好更新。',64,'全唐诗/poet.tang.14000.json','["年來日日春光好，今日春光好更新。", "獨獻菜羹憐應節，遍傳金勝喜逢人。", "煙添柳色看猶淺，鳥踏梅花落已頻。", "東閤此時聞一曲，翻令和者不勝春。"]'),
('f04093a5-e41d-476f-9ff8-c23b3b7b540d','奉酬盧端公飲後贈諸公見示之作','戴叔倫','唐','唐诗','tang','','[]','佐幕臨戎旌斾間，五營無事萬家閑。',64,'全唐诗/poet.tang.14000.json','["佐幕臨戎旌斾間，五營無事萬家閑。", "風吹楊柳漸拂地，日映樓臺欲下山。", "綺席晝開留上客，朱門半掩擬重關。", "當時不敢辭先醉，誤逐羣公倒載還。"]'),
('c1fd9b73-7258-4449-9cb5-38ac9be815fa','贈司空拾遺','戴叔倫','唐','唐诗','tang','','[]','侍臣何事辭雲陛，江上彈冠見雪花。',64,'全唐诗/poet.tang.14000.json','["侍臣何事辭雲陛，江上彈冠見雪花。", "望闕未承丹鳳詔，開門空對楚人家。", "陳琳草奏才還在，王粲登樓興不賒。", "高館更容塵外客，仍令歸去待瓊華。"]'),
('ab185b82-5200-4a6d-a327-a21749e60981','越溪村居','戴叔倫','唐','唐诗','tang','','[]','年來橈客寄禪扉，多話貧居在翠微。',64,'全唐诗/poet.tang.14000.json','["年來橈客寄禪扉，多話貧居在翠微。", "黃雀數聲催柳變，清溪一路踏花歸。", "空林野寺經過少，落日深山伴侶稀。", "負米到家春未盡，風蘿閑掃釣魚磯。"]'),
('f3013337-5e2e-4fbb-ac96-c4d166c46d35','贈韓道士','戴叔倫','唐','唐诗','tang','','[]','日暮秋風吹野花，上清歸客意無涯。',64,'全唐诗/poet.tang.14000.json','["日暮秋風吹野花，上清歸客意無涯。", "桃源寂寂煙霞閉，天路悠悠星漢斜。", "還似世人生白髮，定知仙骨變黃芽。", "東城南陌頻相見，應是壺中別有家。"]'),
('223a80a9-26df-447d-bf07-7acd740fed42','寄萬德躬故居','戴叔倫','唐','唐诗','tang','','[]','日暮山風吹女蘿，故人舟楫定如何。',64,'全唐诗/poet.tang.14000.json','["日暮山風吹女蘿，故人舟楫定如何。", "呂仙祠下寒砧急，帝子閣前秋水多。", "閩海風塵鳴戍鼓，江湖煙雨暗漁蓑。", "何時醉把黃花酒，聽爾南征長短歌。"]'),
('18801489-9f1d-4d5d-9618-66e682d3fc54','寄司空曙','戴叔倫','唐','唐诗','tang','','[]','細雨柴門生遠愁，向來詩句若爲酬。',64,'全唐诗/poet.tang.14000.json','["細雨柴門生遠愁，向來詩句若爲酬。", "林花落處頻中酒，海燕飛時獨倚樓。", "北郭晚晴山更遠，南塘春盡水爭流。", "可能相別還相憶，莫遣楊花笑白頭。"]'),
('205cafa9-5b98-4e70-8a6c-1543fbb08f35','過故人陳羽山居','戴叔倫','唐','唐诗','tang','','[]','向來攜酒共追攀，此日看雲獨未還。',64,'全唐诗/poet.tang.14000.json','["向來攜酒共追攀，此日看雲獨未還。", "不見山中人半載，依然松下屋三間。", "峰攢仙境丹霞上，水遶漁磯綠玉灣。", "却望夏洋懷二妙，滿崖霜樹曉斑斑。"]'),
('2855bd7a-82bb-4ff7-8b63-002876bef4bc','弔暢當','戴叔倫','唐','唐诗','tang','','[]','萬里江南一布衣，早將佳句動京畿。',64,'全唐诗/poet.tang.14000.json','["萬里江南一布衣，早將佳句動京畿。", "徒聞子敬遺琴在，不見相如駟馬歸。", "朔雪恐迷新冢草，秋風愁老故山薇。", "玉堂知己能銘述，猶得精魂慰所依。"]'),
('53055f71-d58b-42e6-bd79-a88eb44e79d8','寄劉禹錫','戴叔倫','唐','唐诗','tang','','[]','謝相園西石徑斜，知君習隱暫爲家。',64,'全唐诗/poet.tang.14000.json','["謝相園西石徑斜，知君習隱暫爲家。", "有時出郭行芳草，長日臨池看落花。", "春去能忘詩共賦，客來應是酒頻賒。", "五年不見西山色，悵望浮雲隱落霞。"]'),
('5fe8b080-6494-4279-9a7b-e6b4917fc51f','寄孟郊','戴叔倫','唐','唐诗','tang','','[]','亂餘城郭怕經過，到處閑門長薜蘿。',64,'全唐诗/poet.tang.14000.json','["亂餘城郭怕經過，到處閑門長薜蘿。", "用世空悲聞道淺，入山偏喜識僧多。", "醉歸花徑雲生履，樵罷松巖雪滿蓑。", "石上幽期春又暮，何時載酒聽高歌。"]'),
('5774ddb1-5506-4a6c-8ab7-81c5d6a3d992','贈徐山人','戴叔倫','唐','唐诗','tang','','[]','亂餘山水半凋殘，江上逢君春正闌。',64,'全唐诗/poet.tang.14000.json','["亂餘山水半凋殘，江上逢君春正闌。", "針自指南天窅窅，星猶拱北夜漫漫。", "漢陵帝子黃金盌，晉代神仙白玉棺。", "回首風塵千里外，故園煙雨五峰寒。"]'),
('8f8d32be-b8c6-45ea-8f07-96bf932592e7','過賈誼舊居','戴叔倫','唐','唐诗','tang','','[]','楚鄉卑濕歎殊方，鵩賦人非宅已荒。',64,'全唐诗/poet.tang.14000.json','["楚鄉卑濕歎殊方，鵩賦人非宅已荒。", "謾有長書憂漢室，空將哀些弔沅湘。", "雨餘古井生秋草，葉盡疎林見夕陽。", "過客不須頻太息，咸陽宮殿亦淒涼。"]'),
('40d37823-3437-4e99-961c-b4b9c99f7354','宮詞','戴叔倫','唐','唐诗','tang','','[]','紫禁迢迢宮漏鳴，夜深無語獨含情。',64,'全唐诗/poet.tang.14000.json','["紫禁迢迢宮漏鳴，夜深無語獨含情。", "春風鸞鏡愁中影，明月羊車夢裏聲。", "塵暗玉堦綦跡斷，香飄金屋篆煙清。", "貞心一任蛾眉妒，買賦何須問馬卿。"]'),
('0e46e210-631f-40d7-99be-8f5e1f21e1be','漢宮人入道','戴叔倫','唐','唐诗','tang','','[]','蕭蕭白髮出宮門，羽服星冠道意存。',64,'全唐诗/poet.tang.14000.json','["蕭蕭白髮出宮門，羽服星冠道意存。", "霄漢九重辭鳳闕，雲山何處訪桃源。", "瑤池醉月勞仙夢，玉輦乘春却帝恩。", "回首吹簫天上伴，上陽花落共誰言。"]'),
('78f6ebbf-396a-4980-bbf1-0c14d80d384d','二靈寺守歲','戴叔倫','唐','唐诗','tang','','[]','守歲山房迥絕緣，燈光香灺共蕭然。',64,'全唐诗/poet.tang.14000.json','["守歲山房迥絕緣，燈光香灺共蕭然。", "無人更獻椒花頌，有客同參栢子禪。", "已悟化城非樂界，不知今夕是何年。", "憂心悄悄渾忘寐，坐待扶桑日麗天。"]'),
('dfdfe676-a556-40c1-b250-d9e935a39a63','暮春感懷 一','戴叔倫','唐','唐诗','tang','','[]','杜宇聲聲喚客愁，故園何處此登樓。',64,'全唐诗/poet.tang.14000.json','["杜宇聲聲喚客愁，故園何處此登樓。", "落花飛絮成春夢，賸水殘山異昔遊。", "歌扇多情明月在，舞衣無意綵雲收。", "東皇去後韶華盡，老圃寒香別有秋。"]'),
('66255fc9-0ccd-4d15-90a4-e44f0c4ce0f6','暮春感懷 二','戴叔倫','唐','唐诗','tang','','[]','四十無聞嬾慢身，放情丘壑任天真。',64,'全唐诗/poet.tang.14000.json','["四十無聞嬾慢身，放情丘壑任天真。", "悠悠往事杯中物，赫赫時名扇外塵。", "短策看雲松寺晚，疎簾聽雨草堂春。", "山花水鳥皆知己，百遍相過不厭貧。"]'),
('9c197e13-7039-48a1-97c1-63a8e56d0f85','哭朱放','戴叔倫','唐','唐诗','tang','','[]','幾年湖海挹餘芳，豈料蘭摧一夜霜。',64,'全唐诗/poet.tang.14000.json','["幾年湖海挹餘芳，豈料蘭摧一夜霜。", "人世空傳名耿耿，泉臺杳隔路茫茫。", "碧窗月落琴聲斷，華表雲深鶴夢長。", "最是不堪回首處，九泉煙冷樹蒼蒼。"]'),
('8502e6fa-f283-440a-a69a-12bb1b54610f','酬盩厔耿少府湋見寄','戴叔倫','唐','唐诗','tang','','[]','方丈蕭蕭落葉中，暮天深巷起悲風。',64,'全唐诗/poet.tang.14000.json','["方丈蕭蕭落葉中，暮天深巷起悲風。", "流年不盡人自老，外事無端心已空。", "家近小山當海畔，身留環衞蔭牆東。", "遙聞相訪頻逢雪，一醉寒宵誰與同。"]'),
('f75b5345-5fc9-44f2-b547-de2b3ffc8e97','贈慧上人','戴叔倫','唐','唐诗','tang','','[]','仙槎江口槎溪寺，幾度停舟訪未能。',64,'全唐诗/poet.tang.14000.json','["仙槎江口槎溪寺，幾度停舟訪未能。", "自恨頻年爲遠客，喜從異郡識高僧。", "雲霞色釅禪房衲，星月光涵古殿燈。", "何日却飛真錫返，故人丘木翳寒藤。"]'),
('ae41a4c9-251d-44ff-8f20-f1056c90c087','漸至涪州先寄王員外使君縱','戴叔倫','唐','唐诗','tang','','[]','文教通夷俗，均輸問火田。',72,'全唐诗/poet.tang.14000.json','["文教通夷俗，均輸問火田。", "江分巴字水，樹入夜郎煙。", "毒瘴含秋氣，陰崖蔽曙天。", "路難空計日，身老不由年。", "將命寧知遠，歸心詎可傳。", "星郎復何意，出守五溪邊。"]'),
('5f4362e4-b3a8-442b-a272-f9b96f2e37ed','和河南羅主簿送校書兄歸江南','戴叔倫','唐','唐诗','tang','','[]','兄弟泣殊方，天涯指故鄉。',96,'全唐诗/poet.tang.14000.json','["兄弟泣殊方，天涯指故鄉。", "斷雲無定處，歸鴈不成行。", "草莽人煙少，風波水驛長。", "上虞親渤澥，東楚隔瀟湘。", "古戍陰傳火，寒蕪曉帶霜。", "海門潮灩灩，沙岸荻蒼蒼。", "京輦辭芸閣，蘅芳憶草堂。", "知君始寧隱，還緝舊荷裳。"]'),
('4c9ca09f-e8e7-48a5-94a5-ec8ec6c99667','曉聞長樂鐘聲','戴叔倫','唐','唐诗','tang','','[]','漢苑鐘聲早，秦郊曙色分。',72,'全唐诗/poet.tang.14000.json','["漢苑鐘聲早，秦郊曙色分。", "霜凌萬戶徹，風散一城聞。", "已啓蓬萊殿，初朝鴛鷺羣。", "虛心方應物，大扣欲干雲。", "近雜雞人唱，新傳鳧氏文。", "能令翰苑客，流聽思氛氳。"]'),
('2666a3f9-aa59-4476-bb0b-0af3357d8d87','聽霜鐘','戴叔倫','唐','唐诗','tang','','[]','渺渺飛霜夜，寥寥遠岫鐘。',72,'全唐诗/poet.tang.14000.json','["渺渺飛霜夜，寥寥遠岫鐘。", "出雲疑斷續，入戶乍舂容。", "度枕頻驚夢，隨風幾韻松。", "悠揚來不已，杳靄去何從。", "髣髴煙嵐隔，依稀巖嶠重。", "此時聊一聽，餘響繞千峰。"]'),
('0f145a5d-ead7-40dc-88a8-217f5bf05e38','聽霜鐘','戴叔倫','唐','唐诗','tang','','[]','寥亮來豐嶺，分明辨古鐘。',72,'全唐诗/poet.tang.14000.json','["寥亮來豐嶺，分明辨古鐘。", "應霜如自擊，中節每相從。", "靜聽非閑扣，潛應蘊聖蹤。", "風間時斷續，雲外更舂容。", "虛警和清籟，雄鳴隔亂峰。", "因知諭知己，感激更難逢。"]'),
('39ee422a-e77c-494c-b5c7-75b5a7fa9833','酬崔法曹遺劒','戴叔倫','唐','唐诗','tang','','[]','臨風脫佩劒，相勸靜胡塵。',24,'全唐诗/poet.tang.14000.json','["臨風脫佩劒，相勸靜胡塵。", "自料無筋力，何由荅故人。"]'),
('e3f3e233-70e4-49fd-bb09-c6a0a54f7d4e','敬報孫常州二首 一','戴叔倫','唐','唐诗','tang','','[]','衰病苦奔走，未嘗追舊遊。',24,'全唐诗/poet.tang.14000.json','["衰病苦奔走，未嘗追舊遊。", "何言問憔悴，此日駐方舟。"]'),
('c9449155-5986-4467-8e84-30e5205e3f1e','敬報孫常州二首 二','戴叔倫','唐','唐诗','tang','','[]','遠道曳故屐，餘春會高齋。',24,'全唐诗/poet.tang.14000.json','["遠道曳故屐，餘春會高齋。", "因言別離久，得盡平生懷。"]'),
('99ade326-5aeb-4d54-b7f3-cb1351a5e23e','將赴東陽留上包諫議','戴叔倫','唐','唐诗','tang','','[]','敝邑連山遠，仙舟數刻同。',24,'全唐诗/poet.tang.14000.json','["敝邑連山遠，仙舟數刻同。", "多慚屢回首，前路在泥中。"]'),
('a0a91b39-3990-4eba-b4ef-86f3eca64ce8','荅崔法曹','戴叔倫','唐','唐诗','tang','','[]','後會知不遠，今歡亦願留。',24,'全唐诗/poet.tang.14000.json','["後會知不遠，今歡亦願留。", "江天梅雨散，況在月中樓。"]'),
('a13ca9e2-3f3d-4065-b001-6b5ff7e36dcc','問嚴居士易','戴叔倫','唐','唐诗','tang','','[]','自公來問易，不復待加年。',24,'全唐诗/poet.tang.14000.json','["自公來問易，不復待加年。", "更有垂簾會，遙知續草玄。"]'),
('b750e80a-f2d3-4197-b1cb-45c9e7251ddd','新年第二夜荅處上人宿玉芝觀見寄','戴叔倫','唐','唐诗','tang','','[]','陽春已三日，會友聞昨夜。',24,'全唐诗/poet.tang.14000.json','["陽春已三日，會友聞昨夜。", "可愛剡溪僧，獨尋陶景舍。"]'),
('3335bee1-90a8-4998-9731-c11a8fce0597','赴撫州對酬崔法曹夜雨滴空堦五首 一','戴叔倫','唐','唐诗','tang','','[]','雨落濕孤客，心驚比棲鳥。',24,'全唐诗/poet.tang.14000.json','["雨落濕孤客，心驚比棲鳥。", "空階夜滴繁，相亂應到曉。"]'),
('1c189006-aefd-4e4f-bdcc-3393aa34f56a','赴撫州對酬崔法曹夜雨滴空堦五首 二','戴叔倫','唐','唐诗','tang','','[]','高會棗樹宅，清言蓮社僧。',24,'全唐诗/poet.tang.14000.json','["高會棗樹宅，清言蓮社僧。", "兩鄉同夜雨，旅館又無燈。"]'),
('c9e83d27-9a83-4eb6-b348-333bc281c2b9','赴撫州對酬崔法曹夜雨滴空堦五首 三','戴叔倫','唐','唐诗','tang','','[]','謗議不自辨，親朋那得知。',24,'全唐诗/poet.tang.14000.json','["謗議不自辨，親朋那得知。", "雨中驅馬去，非是獨傷離。"]'),
('2e91df9f-dc79-4657-a431-44a6378b0ecd','赴撫州對酬崔法曹夜雨滴空堦五首 四','戴叔倫','唐','唐诗','tang','','[]','離室雨初晦，客程雲陡暗。',24,'全唐诗/poet.tang.14000.json','["離室雨初晦，客程雲陡暗。", "方爲對吏人，敢望郵童探。"]'),
('a9fa19f8-6e21-460a-a1ad-ad0272328262','赴撫州對酬崔法曹夜雨滴空堦五首 五','戴叔倫','唐','唐诗','tang','','[]','縱酒常擲盞，狂歌時入室。',24,'全唐诗/poet.tang.14000.json','["縱酒常擲盞，狂歌時入室。", "離羣怨雨聲，幽抑方成疾。"]'),
('a6d7f53c-9631-4849-9975-4887c7e0fb61','又酬曉燈[離暗]室五首 一','戴叔倫','唐','唐诗','tang','','[]','知疑姦叟謗，閑與情人話。',24,'全唐诗/poet.tang.14000.json','["知疑姦叟謗，閑與情人話。", "猶是別時燈，不眠同此夜。"]'),
('9715a2f1-2b9f-459e-9d0d-36e9c5b78544','又酬曉燈[離暗]室五首 二','戴叔倫','唐','唐诗','tang','','[]','寒燈揚曉焰，重屋驚春雨。',24,'全唐诗/poet.tang.14000.json','["寒燈揚曉焰，重屋驚春雨。", "應想遠行人，路逢泥濘阻。"]'),
('fcf8623a-3c01-4bea-94cd-663e6b2a2f76','又酬曉燈[離暗]室五首 三','戴叔倫','唐','唐诗','tang','','[]','燈光照虛屋，雨影懸空壁。',24,'全唐诗/poet.tang.14000.json','["燈光照虛屋，雨影懸空壁。", "一向簷下聲，遠來愁處滴。"]'),
('e3f71946-f5ac-4789-a750-6af2337a11b8','又酬曉燈[離暗]室五首 四','戴叔倫','唐','唐诗','tang','','[]','楚僧話寂滅，俗慮比虛空。',24,'全唐诗/poet.tang.14000.json','["楚僧話寂滅，俗慮比虛空。", "賴有殘燈喻，相傳昏暗中。"]'),
('fb3ddaff-b685-4259-b956-5cf875608319','又酬曉燈[離暗]室五首 五','戴叔倫','唐','唐诗','tang','','[]','雨聲亂燈影，明滅在空堦。',24,'全唐诗/poet.tang.14000.json','["雨聲亂燈影，明滅在空堦。", "併枉五言贈，知同萬里懷。"]'),
('7614ca20-733c-4ff3-a655-3c8ea0d498ef','同賦龍沙墅','戴叔倫','唐','唐诗','tang','','[]','回轉沙岸近，欹斜林嶺重。',24,'全唐诗/poet.tang.14000.json','["回轉沙岸近，欹斜林嶺重。", "因君訪遺跡，此日見真龍。"]'),
('ccd8b7c0-3d74-4cb0-8980-3dcd5a265a30','昭君詞','戴叔倫','唐','唐诗','tang','','[]','漢宮若遠近，路在寒沙上。',24,'全唐诗/poet.tang.14000.json','["漢宮若遠近，路在寒沙上。", "到死不得歸，何人共南望。"]'),
('9017db43-e553-41c6-8e41-faec2e570bc5','勸陸三飲酒','戴叔倫','唐','唐诗','tang','','[]','寒郊好天氣，勸酒莫辭頻。',24,'全唐诗/poet.tang.14000.json','["寒郊好天氣，勸酒莫辭頻。", "擾擾鍾陵市，無窮不醉人。"]'),
('16616009-65cd-4aca-9fa7-d811bc47da08','關山月二首 一','戴叔倫','唐','唐诗','tang','','[]','月出照關山，秋風人未還。',24,'全唐诗/poet.tang.14000.json','["月出照關山，秋風人未還。", "清光無遠近，鄉淚半書間。"]'),
('01898455-f8ad-437f-b6b7-e85557bcdc22','關山月二首 二','戴叔倫','唐','唐诗','tang','','[]','一鴈過連營，繁霜覆古城。',24,'全唐诗/poet.tang.14000.json','["一鴈過連營，繁霜覆古城。", "胡笳在何處，半夜起邊聲。"]'),
('46c5d728-c508-4eb6-ab70-b3bda8705e74','送王司直','戴叔倫','唐','唐诗','tang','','["\u53cb\u4eba", "\u9001\u522b", "\u53cb\u60c5"]','西塞雲山遠，東風道路長。',24,'全唐诗/poet.tang.14000.json','["西塞雲山遠，東風道路長。", "人心勝潮水，相送過潯陽。"]'),
('a0f43418-33bc-4f98-899b-0685366eea5e','宿無可上人房','戴叔倫','唐','唐诗','tang','','[]','偶來人境外，何處染囂塵。',24,'全唐诗/poet.tang.14000.json','["偶來人境外，何處染囂塵。", "倘許棲林下，僧中老此身。"]'),
('c1a46701-7f8e-4fda-af01-a547f34e1961','山居','戴叔倫','唐','唐诗','tang','','[]','麋鹿自成羣，何人到白雲。',24,'全唐诗/poet.tang.14000.json','["麋鹿自成羣，何人到白雲。", "山中無外事，終日醉醺醺。"]'),
('151e3f4f-cb2b-4bf1-bd53-800f2185e4d1','口號','戴叔倫','唐','唐诗','tang','','[]','白髮千莖雪，寒窗嬾著書。',24,'全唐诗/poet.tang.14000.json','["白髮千莖雪，寒窗嬾著書。", "最憐吟苜蓿，不及向桑榆。"]'),
('c4a4c891-c602-4085-86e2-78b7678059e1','夜坐','戴叔倫','唐','唐诗','tang','','[]','夜靜河漢高，獨坐庭前月。',24,'全唐诗/poet.tang.14000.json','["夜靜河漢高，獨坐庭前月。", "忽起故園思，動作經年別。"]'),
('2e0dfd8f-821c-40ce-b802-251e56eb1ed3','隄上柳','戴叔倫','唐','唐诗','tang','','[]','垂柳萬條絲，春來織別離。',24,'全唐诗/poet.tang.14000.json','["垂柳萬條絲，春來織別離。", "行人攀折處，閨妾斷腸時。"]'),
('1ec2a7d3-28e5-4dc8-b9e9-7c4e160ac871','遣興','戴叔倫','唐','唐诗','tang','','[]','明月臨滄海，閑雲戀故山。',24,'全唐诗/poet.tang.14000.json','["明月臨滄海，閑雲戀故山。", "詩名滿天下，終日掩柴關。"]'),
('e341327a-fb05-44d4-b771-6d22bd4cc7e5','贈張揮使','戴叔倫','唐','唐诗','tang','','[]','謫戍孤城小，思家萬里遙。',24,'全唐诗/poet.tang.14000.json','["謫戍孤城小，思家萬里遙。", "漢廷求衞霍，劒佩上青霄。"]'),
('ec7585c2-b556-44ce-9536-4ab29f138ed1','偶成','戴叔倫','唐','唐诗','tang','','[]','野水連天碧，峯巒入海青。',24,'全唐诗/poet.tang.14000.json','["野水連天碧，峯巒入海青。", "滄浪者誰子，一曲醉中聽。"]'),
('e4166f66-36ab-4fe1-ab8b-87bae3cf862c','畫蟬','戴叔倫','唐','唐诗','tang','','[]','飲露身何潔，吟風韻更長。',24,'全唐诗/poet.tang.14000.json','["飲露身何潔，吟風韻更長。", "斜陽千萬樹，無處避螳螂。"]'),
('095b716b-89b6-4ecc-a3f9-7ffa0bd688d4','題天柱山圖','戴叔倫','唐','唐诗','tang','','[]','拔翠五雲中，擎天不計功。',24,'全唐诗/poet.tang.14000.json','["拔翠五雲中，擎天不計功。", "誰能凌絕頂，看取日升東。"]'),
('a012f579-47b8-4b62-a91b-6792bb94ae53','松鶴','戴叔倫','唐','唐诗','tang','','[]','雨濕松陰涼，風落松花細。',24,'全唐诗/poet.tang.14000.json','["雨濕松陰涼，風落松花細。", "獨鶴愛清幽，飛來不飛去。"]'),
('181e032c-d33f-449e-a589-92402eb757c9','草堂一上人','戴叔倫','唐','唐诗','tang','','[]','一公持一鉢，相復度遙岑。',24,'全唐诗/poet.tang.14000.json','["一公持一鉢，相復度遙岑。", "地瘦無黃獨，春來草更深。"]'),
('1dbe219f-270f-4ad6-aec7-6f15ae73ad70','題黃司直園','戴叔倫','唐','唐诗','tang','','[]','爲憶去年梅，凌寒特地來。',24,'全唐诗/poet.tang.14000.json','["爲憶去年梅，凌寒特地來。", "門前空臘盡，渾未有花開。"]'),
('1464676a-cfac-4c42-8e13-c578e0a54d43','北山游亭','戴叔倫','唐','唐诗','tang','','[]','西崦水泠泠，沿岡有游亭。',24,'全唐诗/poet.tang.14000.json','["西崦水泠泠，沿岡有游亭。", "自從春草長，遙見祗青青。"]'),
('1feb3681-6f79-4a9d-ae12-5b826046cac1','贈李唐山人','戴叔倫','唐','唐诗','tang','','[]','此意無所欲，閉門風景遲。',24,'全唐诗/poet.tang.14000.json','["此意無所欲，閉門風景遲。", "柳條將白髮，相對共垂絲。"]'),
('cc44f781-f0bb-4947-bf2b-92e0e1275f32','題秦隱君麗句亭','戴叔倫','唐','唐诗','tang','','[]','北人歸欲盡，猶自住蕭山。',24,'全唐诗/poet.tang.14000.json','["北人歸欲盡，猶自住蕭山。", "閉戶不曾出，詩名滿世間。"]'),
('c48cb12c-8c93-46f0-ae68-fed69e1fefbe','荅孫常州見憶','戴叔倫','唐','唐诗','tang','','[]','畫鷁春風裏，迢遙去若飛。',24,'全唐诗/poet.tang.14000.json','["畫鷁春風裏，迢遙去若飛。", "那能寄相憶，不並子猷歸。"]'),
('ba16449e-a278-49cf-9605-e772c7b68422','送裴明州效南朝體','戴叔倫','唐','唐诗','tang','','[]','沅水連湘水，千波萬浪中。',24,'全唐诗/poet.tang.14000.json','["沅水連湘水，千波萬浪中。", "知郎未得去，慚愧石尤風。"]'),
('e3265b08-784b-400b-8fe7-d1654c0d22b8','戲留顧十一明府','戴叔倫','唐','唐诗','tang','','[]','江明雨初歇，山暗雲猶濕。',24,'全唐诗/poet.tang.14000.json','["江明雨初歇，山暗雲猶濕。", "未可動歸橈，前程風浪急。"]'),
('ffbd4e81-ebc5-4248-97f3-e94a33ac9515','荅崔載華','戴叔倫','唐','唐诗','tang','','[]','文案日成堆，愁眉拽不開。',24,'全唐诗/poet.tang.14000.json','["文案日成堆，愁眉拽不開。", "偷歸甕間臥，逢箇楚狂來。"]'),
('10cef41f-2e8b-43fc-a431-038760d73e2c','將赴行營勸客同醉','戴叔倫','唐','唐诗','tang','','[]','絲管霜天夜，煙塵淮水西。',24,'全唐诗/poet.tang.14000.json','["絲管霜天夜，煙塵淮水西。", "明朝上征去，相伴醉如泥。"]'),
