('2bd56b00-f9a0-490c-b3ae-262f704ba596','撫州被推昭雪荅陸太祝三首 三','戴叔倫','唐','唐诗','tang','','[]','春風旅館長庭蕪，俯首低眉一老夫。',32,'全唐诗/poet.tang.14000.json','["春風旅館長庭蕪，俯首低眉一老夫。", "已對鐵冠窮事本，不知廷尉念冤無。"]'),
('6a1da34c-2be0-485b-bead-81a1911e840e','送獨孤𢘽還京','戴叔倫','唐','唐诗','tang','','[]','舉家相逐還鄉去，不向秋風怨別時。',32,'全唐诗/poet.tang.14000.json','["舉家相逐還鄉去，不向秋風怨別時。", "湖水兩重山萬里，定知行盡到京師。"]'),
('770a0170-ad29-4655-ab97-d06e71cb76ea','臨流送顧東陽','戴叔倫','唐','唐诗','tang','','[]','海上獨歸慚不及，邑中遺愛定無雙。',32,'全唐诗/poet.tang.14000.json','["海上獨歸慚不及，邑中遺愛定無雙。", "蘭橈起唱逐流去，却恨山溪通外江。"]'),
('fa637bf1-eb04-411f-8171-c5bfadb32805','行營送馬侍御','戴叔倫','唐','唐诗','tang','','[]','萬里羽書來未絕，五關烽火晝仍傳。',32,'全唐诗/poet.tang.14000.json','["萬里羽書來未絕，五關烽火晝仍傳。", "故人多病盡歸去，唯有劉楨不得眠。"]'),
('5c5a2ba4-4609-4c96-8022-23ca17b0e46f','送秦系','戴叔倫','唐','唐诗','tang','','[]','五都來往無舊業，一代公卿盡故人。',32,'全唐诗/poet.tang.14000.json','["五都來往無舊業，一代公卿盡故人。", "不肯低頭受羈束，遠師溪上拂纓塵。"]'),
('99e2e5ca-c2d3-4a74-889c-5187d67fb5e4','送裴判官回湖南','戴叔倫','唐','唐诗','tang','','[]','莫怕南風且盡歡，湘山多雨夏中寒。',32,'全唐诗/poet.tang.14000.json','["莫怕南風且盡歡，湘山多雨夏中寒。", "送君萬里不覺遠，此地曾爲心鐵官。"]'),
('b2b17513-9627-4dae-9779-c2df11a7007e','再巡道永留別','戴叔倫','唐','唐诗','tang','','[]','鬢下初驚白髮時，更逢離別助秋悲。',32,'全唐诗/poet.tang.14000.json','["鬢下初驚白髮時，更逢離別助秋悲。", "從今不學四方事，已共家人海上期。"]'),
('bbd2ad8c-e1cd-4b4e-afb2-8464e20188d2','別崔法曹','戴叔倫','唐','唐诗','tang','','["\u5e90\u5c71"]','欲作別離西入秦，芝田棗逕往來頻。',32,'全唐诗/poet.tang.14000.json','["欲作別離西入秦，芝田棗逕往來頻。", "東湖此夕更留醉，逢著廬山學道人。"]'),
('5ff11599-0092-414d-a759-a18078140df7','送蕭二','戴叔倫','唐','唐诗','tang','','[]','擬向田間老此身，寒郊怨別甚於春。',32,'全唐诗/poet.tang.14000.json','["擬向田間老此身，寒郊怨別甚於春。", "又聞故里朋遊盡，到日知逢何處人。"]'),
('7cd7fe9c-61e1-4421-a500-4f22ebd7e494','湘川野望','戴叔倫','唐','唐诗','tang','','[]','懷王獨與佞人謀，聞道忠臣入亂流。',32,'全唐诗/poet.tang.14000.json','["懷王獨與佞人謀，聞道忠臣入亂流。", "今日登高望不見，楚雲湘水各悠悠。"]'),
('ed8693c8-135b-43a0-ac7d-5dadfd9980d8','將至道州寄李使君','戴叔倫','唐','唐诗','tang','','[]','九疑深路遶山回，木落天清猨晝哀。',32,'全唐诗/poet.tang.14000.json','["九疑深路遶山回，木落天清猨晝哀。", "猶隔簫韶一峯在，遙傳五馬向東來。"]'),
('9a4b12f1-b33b-4b6a-91b4-41d96a59dbf3','與虞沔州謁藏真上人','戴叔倫','唐','唐诗','tang','','[]','故侯將我到山中，更上西峯見遠公。',32,'全唐诗/poet.tang.14000.json','["故侯將我到山中，更上西峯見遠公。", "共問置心何處好，主人揮手指虛空。"]'),
('b5f7a070-808f-45b7-ab66-4bdcd7a562e0','題招隱寺','戴叔倫','唐','唐诗','tang','','[]','昨日臨川謝病還，求田問舍獨相關。',32,'全唐诗/poet.tang.14000.json','["昨日臨川謝病還，求田問舍獨相關。", "宋時有井如今在，却種胡麻不買山。"]'),
('0271a9ee-1faa-4b35-b9d4-c6c3b47127b6','過珥瀆單老','戴叔倫','唐','唐诗','tang','','[]','毫末成圍海變田，單家依舊住溪邊。',32,'全唐诗/poet.tang.14000.json','["毫末成圍海變田，單家依舊住溪邊。", "比來已向人間老，今日相過却少年。"]'),
('9038c3e7-8bce-44ce-a133-a63b7335e5bb','族兄各年八十餘見招游洞','戴叔倫','唐','唐诗','tang','','[]','鶴髮婆娑鄉里親，相邀共看往年春。',32,'全唐诗/poet.tang.14000.json','["鶴髮婆娑鄉里親，相邀共看往年春。", "擬將兒女歸來住，且是茅山見老人。"]'),
('5707de8e-3b74-44f2-a67d-4743b9c1597f','登高回乘月尋僧','戴叔倫','唐','唐诗','tang','','[]','插鬢茱萸來未盡，共隨明月下沙堆。',32,'全唐诗/poet.tang.14000.json','["插鬢茱萸來未盡，共隨明月下沙堆。", "高緇寂寂不相問，醉客無端入定來。"]'),
('a82d0171-3f18-4888-b953-0bbb51a1023f','贈殷亮','戴叔倫','唐','唐诗','tang','','[]','日日河邊見水流，傷春未已復悲秋。',32,'全唐诗/poet.tang.14000.json','["日日河邊見水流，傷春未已復悲秋。", "山中舊宅無人住，來往風塵共白頭。"]'),
('4f1531af-037e-4ca4-8d56-834b2167eed9','夜發袁江寄李潁川劉侍御','戴叔倫','唐','唐诗','tang','','[]','半夜回舟入楚鄉，月明山水共蒼蒼。',32,'全唐诗/poet.tang.14000.json','["半夜回舟入楚鄉，月明山水共蒼蒼。", "孤猨更叫秋風裏，不是愁人亦斷腸。"]'),
('7f0c60b4-819f-4141-b19f-b3e34a02ee97','對酒示申屠學士','戴叔倫','唐','唐诗','tang','','[]','三重江水萬重山，山裏春風度日閑。',32,'全唐诗/poet.tang.14000.json','["三重江水萬重山，山裏春風度日閑。", "且向白雲求一醉，莫教愁夢到鄉關。"]'),
('81c81f68-1a2a-403b-a030-109b8041ecc1','對月荅袁明府','戴叔倫','唐','唐诗','tang','','[]','山下孤城月上遲，相留一醉本無期。',32,'全唐诗/poet.tang.14000.json','["山下孤城月上遲，相留一醉本無期。", "明年此夕遊何處，縱有清光知對誰。"]'),
('e764d6e6-d554-4374-9726-0e7264ee616b','送前上饒嚴明府攝玉山','戴叔倫','唐','唐诗','tang','','[]','家在故林吳楚間，冰爲溪水玉爲山。',32,'全唐诗/poet.tang.14000.json','["家在故林吳楚間，冰爲溪水玉爲山。", "更將舊政化鄰邑，遙見逋人相逐還。"]'),
('481f61cc-a1a2-44a2-96ca-583a9347bdfe','聽歌回馬上贈崔法曹','戴叔倫','唐','唐诗','tang','','[]','秋風裏許杏花開，杏樹傍邊醉客來。',32,'全唐诗/poet.tang.14000.json','["秋風裏許杏花開，杏樹傍邊醉客來。", "共待夜深聽一曲，醒人騎馬斷腸迴。"]'),
('8e4f925a-9a24-437e-b334-3415f5585988','酬駱侍御荅詩','戴叔倫','唐','唐诗','tang','','[]','風傳畫閣空知曉，雨濕江城不見春。',32,'全唐诗/poet.tang.14000.json','["風傳畫閣空知曉，雨濕江城不見春。", "堆案遶牀君莫怪，已經愁思古時人。"]'),
('79036bb6-752d-474c-a130-0ff60d73853a','送孫直遊郴州','戴叔倫','唐','唐诗','tang','','[]','孤舟上水過湘沅，桂嶺南枝花正繁。',32,'全唐诗/poet.tang.14000.json','["孤舟上水過湘沅，桂嶺南枝花正繁。", "行客自知心有托，不聞驚浪與啼猨。"]'),
('4e733ce3-0c15-4cf7-a71c-dccfddc7092a','麓山寺會送尹秀才','戴叔倫','唐','唐诗','tang','','[]','湖上逢君亦不閑，暫將離別到深山。',32,'全唐诗/poet.tang.14000.json','["湖上逢君亦不閑，暫將離別到深山。", "飄蓬驚鳥那自定，強欲相留雲樹間。"]'),
('01796277-e2e7-4050-8305-d1b82afd532e','送董頲','戴叔倫','唐','唐诗','tang','','[]','霜鴈羣飛下楚田，羈人掩淚望秦天。',32,'全唐诗/poet.tang.14000.json','["霜鴈羣飛下楚田，羈人掩淚望秦天。", "君行江海無定所，別後相思何處邊。"]'),
('3dc2c19f-a20a-4405-b4e7-5a1b2f75cf03','別張員外','戴叔倫','唐','唐诗','tang','','[]','木葉紛紛湘水濱，此中何事往頻頻。',32,'全唐诗/poet.tang.14000.json','["木葉紛紛湘水濱，此中何事往頻頻。", "臨風自笑歸時晚，更送浮雲逐故人。"]'),
('cd2c8227-421c-470d-8d69-5bfe9ccefea7','送張評事','戴叔倫','唐','唐诗','tang','','[]','城郭喧喧爭送遠，危梁褭褭渡東津。',32,'全唐诗/poet.tang.14000.json','["城郭喧喧爭送遠，危梁褭褭渡東津。", "楊花展轉引征騎，莫怪山中多看人。"]'),
('3ab9c97e-e1ee-42f8-9ddd-06b5c5f4fff0','送呂少府','戴叔倫','唐','唐诗','tang','','[]','共醉流芳獨歸去，故園高士日相親。',32,'全唐诗/poet.tang.14000.json','["共醉流芳獨歸去，故園高士日相親。", "深山古路無楊柳，折取桐花寄遠人。"]'),
('bbd101d7-645d-46b0-a793-e1844ad764c7','送人游嶺南','戴叔倫','唐','唐诗','tang','','["\u79bb\u522b", "\u5fe7\u4f24"]','少別華陽萬里遊，近南風景不曾秋。',32,'全唐诗/poet.tang.14000.json','["少別華陽萬里遊，近南風景不曾秋。", "紅芳綠筍是行路，縱有啼猨聽却幽。"]'),
('9170ad6d-98f7-48eb-a960-b9c4f8cae0b4','妻亡後別妻弟','戴叔倫','唐','唐诗','tang','','[]','楊柳青青滿路垂，贈行惟折古松枝。',32,'全唐诗/poet.tang.14000.json','["楊柳青青滿路垂，贈行惟折古松枝。", "停舟一對湘江哭，哭罷無言君自知。"]'),
('bcb12c44-575d-4e7c-b3f2-25ffba4f5fcd','和崔法曹建溪聞猨','戴叔倫','唐','唐诗','tang','','[]','曾向巫山峽裏行，羈猨一叫一回驚。',32,'全唐诗/poet.tang.14000.json','["曾向巫山峽裏行，羈猨一叫一回驚。", "聞道建溪腸欲斷，的知斷著第三聲。"]'),
('6215cc8f-11df-4617-bd87-4f33001a07ba','湘南即事','戴叔倫','唐','唐诗','tang','','["\u6292\u60c5", "\u6101\u82e6"]','盧橘花開楓葉衰，出門何處望京師。',32,'全唐诗/poet.tang.14000.json','["盧橘花開楓葉衰，出門何處望京師。", "沅湘日夜東流去，不爲愁人住少時。"]'),
('a8c68b88-d4bb-4236-b648-f13c8d810344','代書寄京洛舊遊','戴叔倫','唐','唐诗','tang','','[]','今年十月溫風起，湘水悠悠生白蘋。',32,'全唐诗/poet.tang.14000.json','["今年十月溫風起，湘水悠悠生白蘋。", "欲寄遠書還不敢，却愁驚動故鄉人。"]'),
('245e85be-c3f9-425d-a685-e3a54f755583','蘄州行營作','戴叔倫','唐','唐诗','tang','','[]','蘄水城西向北看，桃花落盡柳花殘。',32,'全唐诗/poet.tang.14000.json','["蘄水城西向北看，桃花落盡柳花殘。", "朱旗半捲山川小，白馬連嘶草樹寒。"]'),
('fb68fac8-4200-4362-88b3-76ba0792b853','題武當逸禪師蘭若','戴叔倫','唐','唐诗','tang','','[]','我身本似遠行客，況是亂時多病身。',32,'全唐诗/poet.tang.14000.json','["我身本似遠行客，況是亂時多病身。", "經山涉水向何處，羞見竹林禪定人。"]'),
('42465c23-b469-4754-9429-1fad7a53d3ec','穀城逢楊評事','戴叔倫','唐','唐诗','tang','','[]','遠自五陵獨竄身，筑陽山中歸路新。',32,'全唐诗/poet.tang.14000.json','["遠自五陵獨竄身，筑陽山中歸路新。", "橫流夜長不得渡，駐馬荒亭逢故人。"]'),
('f3870907-4c8a-4d1b-be03-5d2e9c30391a','聽韓使君美人歌','戴叔倫','唐','唐诗','tang','','[]','仙人此夜忽凌波，更唱瑤臺一遍歌。',32,'全唐诗/poet.tang.14000.json','["仙人此夜忽凌波，更唱瑤臺一遍歌。", "嫁與將軍天上住，人間可得再相過。"]'),
('d35c106a-a213-46d1-b8e0-5a8466f2ccf7','轉應詞','戴叔倫','唐','唐诗','tang','','["\u8c6a\u653e", "\u5199\u666f", "\u8fb9\u585e", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u601d\u4e61", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','邊草，邊草，邊草盡來共老。',40,'全唐诗/poet.tang.14000.json','["邊草，邊草，邊草盡來共老。", "山南山北雪晴，千里萬里月明。", "明月，明月，胡笳一聲愁絕。"]'),
('1ae43520-9762-47f0-b034-3013298ad02b','精舍對雨','戴叔倫','唐','唐诗','tang','','[]','空門寂寂澹吾身，溪雨微微洗客塵。',32,'全唐诗/poet.tang.14000.json','["空門寂寂澹吾身，溪雨微微洗客塵。", "臥向白雲晴未盡，任他黃鳥醉芳春。"]'),
('5a8cf387-6398-4264-856b-dd30578ffc31','宿灌陽灘','戴叔倫','唐','唐诗','tang','','[]','十月江邊蘆葉飛，灌陽灘冷上舟遲。',32,'全唐诗/poet.tang.14000.json','["十月江邊蘆葉飛，灌陽灘冷上舟遲。", "今朝未遇高風便，還與沙鷗宿水湄。"]'),
('a1be4a54-cf26-4951-b3db-8c5c43ccf174','酬贈張衆甫','戴叔倫','唐','唐诗','tang','','[]','野人無本意，散木任天材。',60,'全唐诗/poet.tang.14000.json','["野人無本意，散木任天材。", "分向空山老，何言上苑來。", "迢遙千里道，依倚九層臺。", "出處寧知命，輪轅豈自媒。", "更慙張處士，相與別蒿萊。"]'),
('0bb1a7c8-b1d8-4683-ac28-b6676e12f667','客舍秋懷呈駱正字士則','戴叔倫','唐','唐诗','tang','','[]','無言堪自喩，偶坐更相悲。',48,'全唐诗/poet.tang.14000.json','["無言堪自喩，偶坐更相悲。", "木落驚年長，門閑惜草衰。", "買山猶未得，諫獵又非時。", "設被浮名繫，歸休漸欲遲。"]'),
('74c10308-05f9-4c02-ab28-fad2b23f438d','寄中書李舍人紓','戴叔倫','唐','唐诗','tang','','[]','萍翻蓬自卷，不共本心期。',48,'全唐诗/poet.tang.14000.json','["萍翻蓬自卷，不共本心期。", "復入重城裏，頻看百草滋。", "水流歸思遠，花發長年悲。", "盡日春風起，無人見此時。"]'),
('0588faba-2b1b-4451-9c6e-8ddd3a696de9','贈康老人洽','戴叔倫','唐','唐诗','tang','','[]','酒泉布衣舊才子，少小知名帝城裏。',224,'全唐诗/poet.tang.14000.json','["酒泉布衣舊才子，少小知名帝城裏。", "一篇飛入九重門，樂府喧喧聞至尊。", "宮中美人皆唱得，七貴因之盡相識。", "南鄰北里日經過，處處淹留樂事多。", "不脫弊裘輕錦綺，長吟佳句掩笙歌。", "賢王貴主於我厚，駿馬蒼頭如己有。", "暗將心事隔風塵，盡擲年光逐杯酒。", "青門幾度見春歸，折柳尋花送落暉。", "杜陵往往逢秋暮，望月臨風攀古樹。", "繁霜入鬢何足論，舊國連天不知處。", "爾來倏忽五十年，却憶當時思眇然。", "多識故侯悲宿草，曾看流水沒桑田。", "百人會中一身在，被褐飲瓢終不改。", "陌頭車馬共營營，不解如君任此生。"]'),
('2446f3e6-9a1f-465f-9cba-e481a62e956d','暮春遊長沙東湖贈辛兖州巢父二首 一','戴叔倫','唐','唐诗','tang','','[]','湘流分曲浦，繚繞古城東。',48,'全唐诗/poet.tang.14000.json','["湘流分曲浦，繚繞古城東。", "岸轉千家合，林開一鏡空。", "人生無事少，心賞幾回同。", "且復忘羈束，悠悠落照中。"]'),
('869a90a2-6d0b-4c59-90c4-f6c2ec8ab6b6','暮春遊長沙東湖贈辛兖州巢父二首 二','戴叔倫','唐','唐诗','tang','','[]','回環路不盡，歷覽意彌新。',48,'全唐诗/poet.tang.14000.json','["回環路不盡，歷覽意彌新。", "古木畬田火，澄江盪槳人。", "緩歌尋極浦，一醉送殘春。", "莫恨長沙遠，他年憶此辰。"]'),
('5173303e-8dd5-4ef5-a730-53dd933c131f','同兖州張秀才過王侍御參謀宅賦十韻','戴叔倫','唐','唐诗','tang','','[]','十年官不進，歛跡無怨咎。',120,'全唐诗/poet.tang.14000.json','["十年官不進，歛跡無怨咎。", "漂蕩海內遊，淹留楚鄉久。", "因參戎幕下，寄宅湘川口。", "翦竹開廣庭，瞻山敞虛牖。", "閑門早春至，陋巷新晴後。", "覆地落殘梅，和風褭輕柳。", "逢迎車馬客，邀結風塵友。", "意愜時會文，夜長聊飲酒。", "秉心轉孤直，沈照隨可否。", "豈學屈大夫，憂慙對漁叟。"]'),
('b458312e-4d72-43bf-a5e7-bd427620b1cb','同辛兖州巢父盧副端岳相思獻酬之作因抒歸懷兼呈辛魏二院長楊長寧','戴叔倫','唐','唐诗','tang','','[]','暮角發高城，情人坐中起。',84,'全唐诗/poet.tang.14000.json','["暮角發高城，情人坐中起。", "臨觴不及醉，分散秋風裏。", "雖有明日期，離心若千里。", "前歡反惆悵，後會還如此。", "焉得夜淹留，一回終宴喜。", "羈遊復牽役，皆去重湖水。", "早晚泛歸舟，吾從數君子。"]'),
('5a30cdb0-aab8-4c0d-9ef3-78f7216ceb66','酬袁太祝長卿小湖村山居書懷見寄','戴叔倫','唐','唐诗','tang','','[]','背江居隙地，辭職作遺人。',72,'全唐诗/poet.tang.14000.json','["背江居隙地，辭職作遺人。", "耕鑿資餘力，樵漁逐四鄰。", "麥秋桑葉大，梅雨稻田新。", "籬落栽山果，池塘養海鱗。", "放歌聊自足，幽思忽相親。", "余亦歸休者，依君老此身。"]'),
('cf5e472b-669d-441b-bd55-7ef708eacf0e','送汶水王明府','戴叔倫','唐','唐诗','tang','','[]','何時別故鄉，歸去佩銅章。',48,'全唐诗/poet.tang.14000.json','["何時別故鄉，歸去佩銅章。", "親族移家盡，閭閻百戰場。", "背關餘古木，近塞足風霜。", "遺老應相賀，知君不下堂。"]'),
('8c50fc55-ea8f-47ee-a9a0-9712f66d5cb6','奉同汴州李相公勉送郭布殿中出巡','戴叔倫','唐','唐诗','tang','','[]','軒車出東閣，都邑遶南河。',48,'全唐诗/poet.tang.14000.json','["軒車出東閣，都邑遶南河。", "馬首先春至，人心比歲和。", "省風傳隱恤，持法去煩苛。", "却想埋輪者，論功此日多。"]'),
('8823f9ad-2be8-46c2-b906-67c13d1e5862','送東陽顧明府罷歸','戴叔倫','唐','唐诗','tang','','[]','祖帳臨鮫室，黎人擁鷁舟。',48,'全唐诗/poet.tang.14000.json','["祖帳臨鮫室，黎人擁鷁舟。", "坐藍高士去，繼組鄙夫留。", "白日落寒水，青楓遶曲洲。", "相看作離別，一倍不禁愁。"]'),
('39ed3638-6e4f-4408-a070-71776dcfc0fc','撫州對事後送外生宋垓歸饒州覲侍呈上姊夫','戴叔倫','唐','唐诗','tang','','[]','淮汴初喪亂，蔣山烽火起。',192,'全唐诗/poet.tang.14000.json','["淮汴初喪亂，蔣山烽火起。", "與君隨親族，奔迸辭故里。", "京口附商客，海門正狂風。", "憂心不敢住，夜發驚浪中。", "雲開方見日，潮盡爐峯出。", "石壁轉棠陰，鄱陽寄茅室。", "淹留三十年，分種越人田。", "骨肉無半在，鄉園猶未旋。", "爾家習文藝，旁究天人際。", "父子自相傳，優游聊卒歲。", "學成不求達，道勝那厭貧。", "時入閭巷醉，好是羲皇人。", "頃因物役牽，偶逐簪組輩。", "謗書喧朝市，撫己慙淺昧。", "世業大小禮，近通顏謝詩。", "念渠還領會，非敢獨爲師。"]'),
('e31e68e4-cfbe-41d3-bbee-6fe3f21b4c4d','永康孫明府頲秩滿將歸枉路訪別','戴叔倫','唐','唐诗','tang','','[]','門前水流咽，城下亂山多。',48,'全唐诗/poet.tang.14000.json','["門前水流咽，城下亂山多。", "非是還家路，寧知枉騎過。", "風煙復欲隔，悲笑屢相和。", "不學陶公醉，無因奈別何。"]'),
('1e4f32bf-4c3f-445c-a840-8365b398c01f','將赴湖南留別東陽舊僚兼示吏人','戴叔倫','唐','唐诗','tang','','[]','智力苦不足，黎甿殊未安。',72,'全唐诗/poet.tang.14000.json','["智力苦不足，黎甿殊未安。", "忽從新命去，復隔舊寮歡。", "曉路整車馬，離亭會衣冠。", "冰堅細流咽，燒盡亂峯寒。", "耆老相餞送，兒童亦悲酸。", "桐鄉寄生怨，欲話此情難。"]'),
('3e98dfa2-956b-4824-9a58-929872bd511b','撫州處士胡泛見送北迴兩館至南昌縣界查溪蘭若別','戴叔倫','唐','唐诗','tang','','[]','移罇鋪山曲，祖帳查溪陰。',72,'全唐诗/poet.tang.14000.json','["移罇鋪山曲，祖帳查溪陰。", "鋪山即遠道，查溪非故林。", "淒然誦新詩，落淚霑素襟。", "郡政我何有，別情君獨深。", "禪庭古樹秋，宿雨清沈沈。", "揮袂千里遠，悲傷去住心。"]'),
('4b21d308-5be0-42e0-a78b-bcbbb62e42f1','將巡郴永途中作','戴叔倫','唐','唐诗','tang','','[]','行役留三楚，思歸又一春。',48,'全唐诗/poet.tang.14000.json','["行役留三楚，思歸又一春。", "自疑冠下髮，聊此鏡中人。", "機息知名誤，形衰恨道貧。", "空將舊泉石，長與夢相親。"]'),
('25e98249-7f22-41ae-82bc-270870b2e641','桂陽北嶺偶過野人所居聊書即事呈王永州邕李道州圻','戴叔倫','唐','唐诗','tang','','[]','犬吠空山響，林深一逕存。',144,'全唐诗/poet.tang.14000.json','["犬吠空山響，林深一逕存。", "隔雲尋板屋，渡水到柴門。", "日晝風煙靜，花明草樹繁。", "乍疑秦世客，漸識楚人言。", "不記逃鄉里，居然長子孫。", "種田燒險谷，汲井鑿高原。", "畦葉藏春雉，庭柯宿旅猨。", "嶺陰無瘴癘，地隙有蘭蓀。", "內戶均皮席，枯瓢沃野餐。", "遠心知自負，幽賞詎能論。", "轉步重崖合，瞻途落照昏。", "他時願攜手，莫比武陵源。"]'),
('994b35f3-5d8e-45b0-8ab9-c59bbe2627e4','下鼻亭瀧行八十里聊狀艱險寄青苗鄭副端朔陽','戴叔倫','唐','唐诗','tang','','[]','瀧水天際來，鼻山地中坼。',144,'全唐诗/poet.tang.14000.json','["瀧水天際來，鼻山地中坼。", "盤渦幾十處，疊溜皆千尺。", "直寫卷沈沙，驚翻衝絕壁。", "淙淙振崖谷，洶洶竟朝夕。", "人語不自聞，日光亂相射。", "艤舟始搖漾，舉棹旋奔激。", "既下同建瓴，半空方避石。", "前危苦未盡，後險何其迫。", "倏閃疾風雷，蒼皇蕩魂魄。", "因隨伏流出，忽與跳波隔。", "遠想欲回軒，豈茲還泛鷁。", "雲涯多候館，努力勤登歷。"]'),
('bdc07246-3835-46d3-8bcb-584c7a2ef676','少女生日感懷','戴叔倫','唐','唐诗','tang','','[]','五逢晬日今方見，置爾懷中自惘然。',64,'全唐诗/poet.tang.14000.json','["五逢晬日今方見，置爾懷中自惘然。", "乍喜老身辭遠役，翻悲一笑隔重泉。", "欲教針線嬌難解，暫弄琴書性已便。", "還有蔡家殘史籍，可能分與外人傳。"]'),
('766e9f06-a076-44aa-8ea9-bc9650dcacf7','張評事涉秦居士系見訪郡齋即同賦中字','戴叔倫','唐','唐诗','tang','','[]','軺車忽枉轍，郡府自生風。',72,'全唐诗/poet.tang.14000.json','["軺車忽枉轍，郡府自生風。", "遣吏山禽在，開罇野客同。", "古牆抽臘筍，喬木颺春鴻。", "能賦傳幽思，清言盡至公。", "城欹殘照入，池曲大江通。", "此地人來少，相歡一醉中。"]'),
('d0228a1b-aee8-4571-b1e0-4ee232b5d636','小雪','戴叔倫','唐','唐诗','tang','','[]','花雪隨風不厭看，更多還肯失林巒。',32,'全唐诗/poet.tang.14000.json','["花雪隨風不厭看，更多還肯失林巒。", "愁人正在書窗下，一片飛來一片寒。"]'),
('2937426d-da4f-4bc6-9280-a84b1f2cc1c9','句','戴叔倫','唐','唐诗','tang','','[]','鄰里龍沙北。',30,'全唐诗/poet.tang.14000.json','["鄰里龍沙北。", "麥秋桑葉大，梅雨稻田新。", "籬落栽山果，池塘養錦鱗。"]'),
('97cd4e39-463e-4717-8eca-7e01e4827e5f','競渡歌','張建封','唐','唐诗','tang','','["\u7aef\u5348\u8282"]','五月五日天晴明，楊花繞江啼曉鶯。',224,'全唐诗/poet.tang.14000.json','["五月五日天晴明，楊花繞江啼曉鶯。", "使君未出郡齋外，江上早聞齊和聲。", "使君出時皆有準，馬前已被紅旗引。", "兩岸羅衣破暈香，銀釵照日如霜刃。", "鼓聲三下紅旗開，兩龍躍出浮水來。", "櫂影斡波飛萬劒，鼓聲劈浪鳴千雷。", "鼓聲漸急標將近，兩龍望標目如瞬。", "坡上人呼霹靂驚，竿頭綵挂虹蜺暈。", "前船搶水已得標，後船失勢空揮橈。", "瘡眉血首爭不定，輸岸一朋心似燒。", "只將輸贏分罰賞，兩岸十舟五來往。", "須臾戲罷各東西，競脫文身請書上。", "吾今細觀競度兒，何殊當路權相持。", "不思得岸各休去，會到摧車折檝時。"]'),
('ca8389c9-3ecf-4efb-9abd-d620c977e9a2','酬韓校書愈打毬歌','張建封','唐','唐诗','tang','','[]','僕本修文持筆者，今來帥領紅旌下。',192,'全唐诗/poet.tang.14000.json','["僕本修文持筆者，今來帥領紅旌下。", "不能無事習虵矛，閑就平場學使馬。", "軍中伎癢驍智材，競馳駿逸隨我來。", "護軍對引相向去，風呼月旋朋先開。", "俯身仰擊復傍擊，難於古人左右射。", "齊觀百步透短門，誰羨養由遙破的。", "儒生疑我新發狂，武夫愛我生雄光。", "杖移鬃底拂尾後，星從月下流中場。", "人不約，心自一，馬不鞭，蹄自疾。", "凡情莫辨捷中能，拙目翻驚巧時失。", "韓生訝我爲斯藝，勸我徐驅作安計。", "不知戎事竟何成，且愧吾人一言惠。"]'),
('e08d9140-736a-43b7-80db-7d0815e5f0c2','春山夜月','于良史','唐','唐诗','tang','','["\u6708\u4eae", "\u6625\u5929", "\u5c71\u6c34", "\u6e38\u5386"]','春山多勝事，賞翫夜忘歸。',48,'全唐诗/poet.tang.14000.json','["春山多勝事，賞翫夜忘歸。", "掬水月在手，弄花香滿衣。", "興來無遠近，欲去惜芳菲。", "南望鳴鐘處，樓臺深翠微。"]'),
('d15965ee-8558-400d-889d-15bd933181b8','宿藍田山口奉寄沈員外','于良史','唐','唐诗','tang','','[]','山暝飛羣鳥，川長泛四鄰。',48,'全唐诗/poet.tang.14000.json','["山暝飛羣鳥，川長泛四鄰。", "煙歸河畔草，月照渡頭人。", "朋友懷東道，鄉關戀北辰。", "去留無所適，岐路獨迷津。"]'),
('cea53702-480c-4b1c-bb8a-bb95c8e701dc','冬日野望寄李贊府','于良史','唐','唐诗','tang','','[]','地際朝陽滿，天邊宿霧收。',48,'全唐诗/poet.tang.14000.json','["地際朝陽滿，天邊宿霧收。", "風兼殘雪起，河帶斷冰流。", "北闕馳心極，南圖尚旅遊。", "登臨思不已，何處得銷愁。"]'),
('153638ca-1f1b-4214-8d83-41919a6675f8','閑居寄薛華','于良史','唐','唐诗','tang','','[]','隱几讀黃老，閑居耳目清。',48,'全唐诗/poet.tang.14000.json','["隱几讀黃老，閑居耳目清。", "僻居人事少，多病道心生。", "雨洗山林濕，鴉鳴池館晴。", "晚來因廢卷，行藥至西城。"]'),
('c426e92d-e18f-4dcc-810e-5d967353dfa4','江上送友人','于良史','唐','唐诗','tang','','[]','看爾動行櫂，未收離別筵。',48,'全唐诗/poet.tang.14000.json','["看爾動行櫂，未收離別筵。", "千帆忽見及，亂却故人船。", "紛泊雁羣起，逶迤沙漵連。", "長亭十里外，應是少人煙。"]'),
('f2df70bb-0958-4bc6-bef3-593eae26d678','田家秋日送友','于良史','唐','唐诗','tang','','[]','蒼茫日初宴，遙野雲初收。',48,'全唐诗/poet.tang.14000.json','["蒼茫日初宴，遙野雲初收。", "殘雨北山裏，夕陽東渡頭。", "舟依漁溓合，水入田家流。", "何意君迷駕，山林應有秋。"]'),
('a50f6900-25c0-49d5-8d6c-39b33a9fb878','自吟','于良史','唐','唐诗','tang','','[]','出身三十年，髮白衣猶碧。',24,'全唐诗/poet.tang.14000.json','["出身三十年，髮白衣猶碧。", "日暮倚朱門，從朱污袍赤。"]'),
('50de24cb-7548-4a09-bb9f-7681a1fe7d27','感興','崔膺','唐','唐诗','tang','','[]','富貴難義合，困窮易感恩。',72,'全唐诗/poet.tang.14000.json','["富貴難義合，困窮易感恩。", "古來忠烈士，多出貧賤門。", "世上桃李樹，但結繁華子。", "白屋抱關人，青雲壯心死。", "本以勢利交，勢盡交情已。", "如何失情後，始歎門易軌。"]'),
('ac3dfa77-1d98-474b-a7b5-76d080cbd0fa','別佳人','崔膺','唐','唐诗','tang','','[]','壠上流泉壠下分，斷腸嗚咽不堪聞。',32,'全唐诗/poet.tang.14000.json','["壠上流泉壠下分，斷腸嗚咽不堪聞。", "嫦娥一入月中去，巫峽千秋空白雲。"]'),
('27423bb8-fa3f-41e6-83a6-9c105c176d3d','御溝新柳','馮宿','唐','唐诗','tang','','[]','夾道天渠遠，垂絲御柳新。',72,'全唐诗/poet.tang.14000.json','["夾道天渠遠，垂絲御柳新。", "千條宜向日，萬戶共迎春。", "輕翠含煙發，微音逐吹頻。", "靜看思渡口，迴望憶江濱。", "嫋嫋分遊騎，依依駐旅人。", "陽和如可及，攀折在茲辰。"]'),
('6a7b56ab-bb3a-462e-b704-7cba25843e6b','酬白樂天劉夢得','馮宿','唐','唐诗','tang','','[]','共稱洛邑難其選，何幸天書用不才。',64,'全唐诗/poet.tang.14000.json','["共稱洛邑難其選，何幸天書用不才。", "遙約和風新草木，且令新雪靜塵埃。", "臨岐有愧傾三省，別酌無辭醉百杯。", "明歲杏園花下集，須知春色自東來。"]'),
('3128cf50-ec04-4964-855a-2bc5b0531987','樂府荅孟東野戲贈','陸長源','唐','唐诗','tang','','[]','芙蓉初出水，菡萏露中花。',24,'全唐诗/poet.tang.14000.json','["芙蓉初出水，菡萏露中花。", "風吹著枯木，無奈值空槎。"]'),
('fbefe905-26fd-4334-895d-c87e0ff08671','詶孟十二新居見寄','陸長源','唐','唐诗','tang','','[]','大道本夷曠，高情亦沖虛。',120,'全唐诗/poet.tang.14000.json','["大道本夷曠，高情亦沖虛。", "因隨白雲意，偶逐青蘿居。", "青蘿紛蒙密，四序無慘舒。", "餘清濯子襟，散彩還吾廬。", "去歲登美第，策名在公車。", "將必繼管蕭，豈惟躡應徐。", "首夏尚清和，殘芳遍丘墟。", "褰幃蔭窗柳，汲井滋園蔬。", "達者貴知心，古人不願餘。", "愛君蔣生逕，且著茂陵書。"]'),
('589b7577-0753-4ffb-b6c4-66854d6fedb8','荅東野夷門雪','陸長源','唐','唐诗','tang','','[]','好丹與素道不同，失意得途事皆別。',48,'全唐诗/poet.tang.14000.json','["好丹與素道不同，失意得途事皆別。", "東隣少年樂未央，南客思歸腸欲絕。", "千里長河冰復冰，雲鴻冥冥楚山雪。"]'),
('5eaa1d14-09d3-446b-a722-01c4d674dace','句','陸長源','唐','唐诗','tang','','[]','忽然一曲稱君心，破却中人百家產。',32,'全唐诗/poet.tang.14000.json','["忽然一曲稱君心，破却中人百家產。", "城外平人驅欲盡，帳中猶打衮花球。"]'),
('dc8caaf5-a738-4e46-973c-f7050efaf214','寄興國池鶴上劉相公','張衆甫','唐','唐诗','tang','','[]','馴狎經時久，䙰褷短翮存。',48,'全唐诗/poet.tang.14000.json','["馴狎經時久，䙰褷短翮存。", "不隨淮海變，空媿稻粱恩。", "獨立秋天靜，單棲夕露繁。", "欲飛還斂翼，詎敢望乘軒。"]'),
('c336a822-fed8-4896-af78-7dc493780df0','送李司直使吳','張衆甫','唐','唐诗','tang','','[]','使臣方擁傳，王事遠辭家。',48,'全唐诗/poet.tang.14000.json','["使臣方擁傳，王事遠辭家。", "震澤逢殘雨，新豐過落花。", "水萍千葉散，風柳萬條斜。", "何處看離恨，春江無限沙。"]'),
('6da94437-62ec-4f16-b3da-a7b18662e736','送李觀之宣州謁袁中丞賦得三州渡','張衆甫','唐','唐诗','tang','','[]','古渡大江濱，西南距要津。',48,'全唐诗/poet.tang.14000.json','["古渡大江濱，西南距要津。", "自當舟檝路，應濟往來人。", "翻浪驚飛鳥，回風起綠蘋。", "君看波上客，歲晚獨垂綸。"]'),
('abc4c2ff-a861-4170-881b-babe127564a4','宿慧山寺','王武陵','唐','唐诗','tang','','[]','秋日遊古寺，秋山正蒼蒼。',72,'全唐诗/poet.tang.14000.json','["秋日遊古寺，秋山正蒼蒼。", "泛舟次巖壑，稽首金仙堂。", "下有寒泉流，上有珍禽翔。", "石門吐明月，竹木涵清光。", "中夜河沈沈，但聞松桂香。", "曠然出塵境，憂慮澹已忘。"]'),
('9bc26733-1070-4a17-b803-b5b9de83e5fc','秋暮登北樓','王武陵','唐','唐诗','tang','','[]','秋滿空山悲客心，山樓晴望散幽襟。',64,'全唐诗/poet.tang.14000.json','["秋滿空山悲客心，山樓晴望散幽襟。", "一川紅樹迎霜老，數曲清溪繞寺深。", "寒氣急催遙塞雁，夕風高送遠城砧。", "三年海上音書絕，鄉國蕭條惟夢尋。"]'),
('2224bbe8-9998-4a41-b624-8c59969ed098','宿慧山寺 一','朱宿','唐','唐诗','tang','','[]','古寺隱秋山，登攀度林樾。',72,'全唐诗/poet.tang.14000.json','["古寺隱秋山，登攀度林樾。", "悠然清蓮界，此地塵境絕。", "機閑任晝昏，慮澹知生滅。", "微吹遞遙泉，疎松對殘月。", "庭虛露華綴，池淨荷香發。", "心悟形未留，遲遲履歸轍。"]'),
('0d2dd1c1-8133-420d-ba0b-1bd8f67e8e6b','宿慧山寺 二','朱宿','唐','唐诗','tang','','[]','歲月人間促，煙霞此地多。',24,'全唐诗/poet.tang.14000.json','["歲月人間促，煙霞此地多。", "殷勤竹林寺，更得幾迴過。"]'),
('b6d6a90c-8065-48b0-a99f-138d984fb40c','送惟良上人歸江南','盧綸','唐','唐诗','tang','','[]','落日映危檣，歸僧向岳陽。',48,'全唐诗/poet.tang.14000.json','["落日映危檣，歸僧向岳陽。", "注瓶寒浪靜，讀律夜船香。", "苦霧沈山影，陰霾發海光。", "羣生一何負，多病禮醫王。"]'),
('baa8ac70-3b99-49e7-ab47-0c35c7b125c9','送韓都護還邊','盧綸','唐','唐诗','tang','','[]','好勇知名早，爭雄上將間。',48,'全唐诗/poet.tang.14000.json','["好勇知名早，爭雄上將間。", "戰多春入塞，獵慣夜登山。", "陣合龍蛇動，軍移草木閑。", "今來部曲盡，白首過蕭關。"]'),
('7c6b3a96-fbbf-4407-83cf-5c6ad0c4b496','送吉中孚校書歸楚州舊山','盧綸','唐','唐诗','tang','','[]','青袍芸閣郎，談笑挹侯王。',264,'全唐诗/poet.tang.14000.json','["青袍芸閣郎，談笑挹侯王。", "舊籙藏雲穴，新詩滿帝鄉。", "名高閑不得，到處人爭識。", "誰知冰雪顏，已雜風塵色。", "此去復如何，東臯岐路多。", "藉芳臨紫陌，回首憶滄波。", "年來倦蕭索，但說淮南樂。", "並檝湖上遊，連檣月中泊。", "沿溜入閶門，千燈夜市喧。", "喜逢鄰舍伴，遙語問鄉園。", "下淮風自急，樹杪分郊邑。", "送客隨岸行，離人出帆立。", "漁村繞水田，澹澹隔晴煙。", "欲就林中醉，先期石上眠。", "林昏天未曙，但向雲邊去。", "暗入無路山，心知有花處。", "登高日轉明，下望見春城。", "洞裏草空長，塚邊人自耕。", "寥寥行異境，過盡千峰影。", "露色凝古壇，泉聲落寒井。", "仙成不可期，多別自堪悲。", "爲問桃源客，何人見亂時。"]'),
('9fb76b92-4f30-43b9-8c96-ce8e3b718dec','送姨弟裴均尉諸曁','盧綸','唐','唐诗','tang','','[]','相悲得成長，同是外家恩。',48,'全唐诗/poet.tang.14000.json','["相悲得成長，同是外家恩。", "舊業廢三畝，弱年成一門。", "城開山日早，吏散渚禽喧。", "東閣謬容止，予心君冀言。"]'),
('ac042cb6-34ae-4d77-9942-56fb5aad802e','送鄧州崔長史','盧綸','唐','唐诗','tang','','[]','出山車騎次諸侯，坐領圖書見督郵。',64,'全唐诗/poet.tang.14000.json','["出山車騎次諸侯，坐領圖書見督郵。", "遶郭桑麻通淅口，滿川風景接襄州。", "高城鳥過方催夜，廢壘蟬鳴不待秋。", "聞說元規偏愛月，知君常得伴登樓。"]'),
('d30d7e0b-1af1-488e-a533-4a9c45366c1a','送鹽鐵裴判官入蜀','盧綸','唐','唐诗','tang','','[]','傳詔收方貢，登車著賜衣。',48,'全唐诗/poet.tang.14000.json','["傳詔收方貢，登車著賜衣。", "榷商蠻客富，稅地芋田肥。", "雲白風雷歇，林清洞穴稀。", "炎涼君莫問，見即在忘歸。"]'),
('f81fd429-5b1f-481a-a7a3-ffa1a1eaddc9','送魏廣下第歸揚州','盧綸','唐','唐诗','tang','','[]','楚鄉雲水內，春日衆山開。',48,'全唐诗/poet.tang.14000.json','["楚鄉雲水內，春日衆山開。", "淮浪參差起，江帆次第來。", "獨歸初失桂，共醉忽停杯。", "漢詔年年有，何愁掩上才。"]'),
('84b01399-c9cc-4660-a2fd-c92550bc6513','送潘述應宏詞下第歸江南','盧綸','唐','唐诗','tang','','[]','愁與醉相和，昏昏竟若何。',48,'全唐诗/poet.tang.14000.json','["愁與醉相和，昏昏竟若何。", "感年懷闕久，失意夢鄉多。", "雨裏行青草，山前望白波。", "江樓覆棋好，誰引仲宣過。"]'),
('23ef9a8b-4c38-48e4-a143-a54a9d411abc','送從舅成都縣丞廣歸蜀','盧綸','唐','唐诗','tang','','[]','襃谷通岷嶺，青冥此路深。',48,'全唐诗/poet.tang.14000.json','["襃谷通岷嶺，青冥此路深。", "晚程椒瘴熱，野飯荔枝陰。", "古郡三刀夜，春橋萬里心。", "唯應對楊柳，暫醉卓家琴。"]'),
('27673f94-0473-48be-874c-928016c01b78','送宋校書赴宣州幕','盧綸','唐','唐诗','tang','','[]','南想宣城郡，清江野戍閑。',48,'全唐诗/poet.tang.14000.json','["南想宣城郡，清江野戍閑。", "艨艟高映浦，睥睨曲隨山。", "名寄圖書內，威生將吏間。", "春行板橋暮，應伴庾公還。"]'),
('298603f3-945f-4112-a9d7-f6d9e73dccc7','送李縱別駕加員外郎却赴常州幕','盧綸','唐','唐诗','tang','','[]','霄漢正聯飛，江湖又獨歸。',48,'全唐诗/poet.tang.14000.json','["霄漢正聯飛，江湖又獨歸。", "暫歡同賜被，不待易朝衣。", "山雨迎軍晚，蘆風候火微。", "還當宴鈴閣，謝守亦光輝。"]'),
('90873ddd-2b28-4582-be1e-9967bac5dd8b','送元贊府重任龍門縣','盧綸','唐','唐诗','tang','','[]','二職亞陶公，歸程與夢同。',48,'全唐诗/poet.tang.14000.json','["二職亞陶公，歸程與夢同。", "柳垂平澤雨，魚躍大河風。", "混跡威長在，孤清志自雄。", "應嗤向隅者，空寄路塵中。"]'),
('d704fc60-067b-4385-b541-b3f0fb4c6e0d','送黎燧尉陽翟','盧綸','唐','唐诗','tang','','[]','玉貌承嚴訓，金聲稱上才。',48,'全唐诗/poet.tang.14000.json','["玉貌承嚴訓，金聲稱上才。", "列筵青草偃，驟馬綠楊開。", "潘縣花添發，梅家鶴暫來。", "誰知望恩者，空逐路人回。"]'),
('37408b78-1836-4f05-90ae-d13fcb2e86b3','送丹陽趙少府','盧綸','唐','唐诗','tang','','[]','恭聞林下別，未至亦霑裳。',48,'全唐诗/poet.tang.14000.json','["恭聞林下別，未至亦霑裳。", "荻岸雨聲盡，江天虹影長。", "佩韋宗嬾慢，偷橘愛芳香。", "遙想從公後，稱榮在上堂。"]'),
('91f0030c-0030-4b54-9f67-aa37cf114dfe','送菊潭王明府','盧綸','唐','唐诗','tang','','[]','組綬掩衰顏，輝光里第間。',48,'全唐诗/poet.tang.14000.json','["組綬掩衰顏，輝光里第間。", "晚涼經灞水，清晝入商山。", "行境逢花發，彈琴見鶴還。", "唯應理農後，鄉老賀君閑。"]'),
('5b42b7db-84ff-4e02-89ea-1d78079a8550','送陳明府赴萍縣','盧綸','唐','唐诗','tang','','[]','素舸載陶公，南隨萬里風。',48,'全唐诗/poet.tang.14000.json','["素舸載陶公，南隨萬里風。", "梅花成雪嶺，橘樹當家僮。", "祠掩荒山下，田開野荻中。", "歲終書善績，應與古碑同。"]'),
('c8451a8d-f39f-44a7-a9e3-f9f8c0636582','送申屠正字往湖南迎親兼謁趙和州因呈上侍郎使君幷戲簡前歷陽李明府','盧綸','唐','唐诗','tang','','[]','曉月朣朦映水關，水邊因到歷陽山。',64,'全唐诗/poet.tang.14000.json','["曉月朣朦映水關，水邊因到歷陽山。", "千艘財貨朱橋下，一曲閭閻青荻間。", "坦腹定逢潘令醉，上樓應伴庾公閑。", "歡餘若問南行計，知念天涯負米還。"]'),
('6ac0413e-d57f-451a-9111-d5c79ed5a730','送李尚書郎君昆季侍從歸覲滑州','盧綸','唐','唐诗','tang','','[]','鳳雛聯翼美王孫，綵服戎裝擬塞垣。',64,'全唐诗/poet.tang.14000.json','["鳳雛聯翼美王孫，綵服戎裝擬塞垣。", "金鼎對筵調野膳，玉鞭齊騎引行軒。", "冰河一曲旌旗滿，墨詔千封雨露繁。", "更說務農能罷戰，敢持謌頌慶晨昏。"]'),
('698d746e-7903-48fa-920c-f68eee20c36a','送張調參軍侍從歸觐荆南因寄長林司空十四曙','盧綸','唐','唐诗','tang','','[]','玉勒侍行襜，郄超未有髯。',48,'全唐诗/poet.tang.14000.json','["玉勒侍行襜，郄超未有髯。", "守儒輕獵騎，承誨訪沈潛。", "雲勢將峰雜，江聲與嶼兼。", "還當見王粲，應念二毛添。"]'),
('8b7ead4e-e822-4c8a-99ba-b884e0e29a6c','送馬尚書郎君侍從歸覲太原','盧綸','唐','唐诗','tang','','[]','玉人垂玉鞭，百騎帶櫜鞬。',48,'全唐诗/poet.tang.14000.json','["玉人垂玉鞭，百騎帶櫜鞬。", "從賞野郵靜，獻新秋果鮮。", "塞屯豐雨雪，虜帳失山川。", "遙想稱觴後，唯當共被眠。"]'),
('d10be540-a81f-43dc-8cf2-5d347f47468d','送張成季往江上賦得垂楊','盧綸','唐','唐诗','tang','','[]','垂楊真可憐，地勝覺春偏。',48,'全唐诗/poet.tang.14000.json','["垂楊真可憐，地勝覺春偏。", "一穗雨聲裏，千條池色前。", "露繁光的皪，日麗影團圓。", "若到隋隄望，應逢花滿船。"]'),
('f8f3931e-fb9a-45db-bd7d-e20034434010','送陝府王司法','盧綸','唐','唐诗','tang','','[]','東門雪覆塵，出送陝城人。',48,'全唐诗/poet.tang.14000.json','["東門雪覆塵，出送陝城人。", "粉郭朝喧市，朱橋夜掩津。", "上寮應重學，小吏已甘貧。", "謝朓曾爲掾，希君一比鄰。"]'),
('6b51846c-dad8-4e78-86fb-b1722719cb46','送太常李主簿歸覲省','盧綸','唐','唐诗','tang','','[]','粲粲美仍都，清閑一貴儒。',48,'全唐诗/poet.tang.14000.json','["粲粲美仍都，清閑一貴儒。", "定交分玉劒，發詠寫冰壺。", "風景隨台位，河山入障圖。", "上堂多慶樂，肯念谷中愚。"]'),
('59cde0c6-34f7-41f9-b059-c3930b1835d2','送從叔程歸西川幕','盧綸','唐','唐诗','tang','','[]','千山冰雪晴，山靜錦花明。',48,'全唐诗/poet.tang.14000.json','["千山冰雪晴，山靜錦花明。", "羣鶴棲蓮府，諸戎拜柳營。", "浪依巴字息，風入蜀關清。", "豈念在貧巷，竹林鳴鳥聲。"]'),
('8da69f75-03c4-4501-9930-01c8c3033c44','送萬巨','盧綸','唐','唐诗','tang','','[]','把酒留君聽琴，難堪歲暮離心。',56,'全唐诗/poet.tang.14000.json','["把酒留君聽琴，難堪歲暮離心。", "霜葉無風自落，秋雲不雨空陰。", "人愁荒村路細，馬怯寒溪水深。", "望斷青山獨立，更知何處相尋。"]'),
('672a31e0-ed1c-4061-9da6-8f1e39a7a251','途中遇雨馬上口號留別張劉二端公','盧綸','唐','唐诗','tang','','[]','陰雷慢轉野雲長，駿馬雙嘶愛雨涼。',32,'全唐诗/poet.tang.14000.json','["陰雷慢轉野雲長，駿馬雙嘶愛雨涼。", "應念龍鐘在泥滓，欲摧肝膽事王章。"]'),
('3eced59f-88bb-4404-99dd-67e57deec2bc','送夔州班使君','盧綸','唐','唐诗','tang','','[]','曉日照樓船，三軍拜峽前。',48,'全唐诗/poet.tang.14000.json','["曉日照樓船，三軍拜峽前。", "白雲隨浪散，青壁與城連。", "萬嶺岷峨雪，千家橘柚川。", "還知楚河內，天子許經年。"]'),
('fcb84cce-b6cd-4346-97ef-bbe40d7a22ee','送從舅成都丞廣歸蜀','盧綸','唐','唐诗','tang','','[]','巴字天邊水，秦人去是歸。',48,'全唐诗/poet.tang.14000.json','["巴字天邊水，秦人去是歸。", "棧長山雨響，溪亂火田稀。", "俗富行應樂，官雄祿豈微。", "魏舒終有淚，還識甯家衣。"]'),
('c14c68c7-d454-4a5c-8657-fb413db1591a','無題','盧綸','唐','唐诗','tang','','[]','耻將名利託交親，只向尊前樂此身。',64,'全唐诗/poet.tang.14000.json','["耻將名利託交親，只向尊前樂此身。", "才大不應成滯客，時危且喜是閑人。", "高歌猶愛思歸引，醉語惟誇漉酒巾。", "囗囗囗囗囗囗囗，豈能偏遣老風塵。"]'),
('a977b0f8-5edd-40ad-b571-3a08343cec6b','題念濟寺','盧綸','唐','唐诗','tang','','[]','靈空聞偈夜清靜，雨裏花枝朝暮開。',32,'全唐诗/poet.tang.14000.json','["靈空聞偈夜清靜，雨裏花枝朝暮開。", "故友九泉留語別，逐臣千里寄書來。"]'),
('c222b6d5-2eb5-4603-84ed-b5afef260fae','河口逢江州朱道士因聽琴','盧綸','唐','唐诗','tang','','["\u5e90\u5c71"]','廬山道士夜攜琴，映月相逢辨語音。',32,'全唐诗/poet.tang.14000.json','["廬山道士夜攜琴，映月相逢辨語音。", "引坐霜中彈一弄，滿船商客有歸心。"]'),
('9c08d89e-9c4a-4cb2-a7f7-8affe0e8fe70','送夏侯校書歸華陰別墅','盧綸','唐','唐诗','tang','','[]','山前白鶴村，竹雪覆柴門。',60,'全唐诗/poet.tang.14000.json','["山前白鶴村，竹雪覆柴門。", "候客定爲黍，務農因燎原。", "乳冰懸暗井，蓮石照晴軒。", "貰酒鄰里睦，曝衣場圃喧。", "依然望君去，余性亦何昏。"]'),
('49adda39-bfe8-402d-9f77-05ad95fb4231','送絳州郭參軍','盧綸','唐','唐诗','tang','','[]','炎天故絳路，千里麥花香。',48,'全唐诗/poet.tang.14000.json','["炎天故絳路，千里麥花香。", "董澤雷聲發，汾橋水氣涼。", "府趨隨宓賤，野宴接王祥。", "送客今何幸，經宵醉玉堂。"]'),
('85a5d11f-1e42-4441-9c9c-eb87a27c73e9','中書舍人李座上送潁陽徐少府','盧綸','唐','唐诗','tang','','[]','潁陽春色似河陽，一望繁花一縣香。',32,'全唐诗/poet.tang.14000.json','["潁陽春色似河陽，一望繁花一縣香。", "今日送官君最恨，可憐才子白鬚長。"]'),
('23a1f1d4-dde1-49ec-9b25-a44e24e7eceb','與從弟瑾同下第後出關言別 一','盧綸','唐','唐诗','tang','','[]','同作金門獻賦人，二年悲見故園春。',32,'全唐诗/poet.tang.14000.json','["同作金門獻賦人，二年悲見故園春。", "到闕不沾新雨露，還家空帶舊風塵。"]'),
('b9cf7be7-b5f3-443a-b19f-987b19d7874f','與從弟瑾同下第後出關言別 二','盧綸','唐','唐诗','tang','','[]','雜花飛盡柳陰陰，官路逶迤綠草深。',32,'全唐诗/poet.tang.14000.json','["雜花飛盡柳陰陰，官路逶迤綠草深。", "對酒已成千里客，望山空寄兩鄉心。"]'),
('30f8215a-0581-45e8-ac71-8d9cfec8e9a3','與從弟瑾同下第後出關言別 三','盧綸','唐','唐诗','tang','','[]','出關愁暮一沾裳，滿野蓬生古戰場。',32,'全唐诗/poet.tang.14000.json','["出關愁暮一沾裳，滿野蓬生古戰場。", "孤村樹色昏殘雨，遠寺鐘聲帶夕陽。"]'),
('fc228c0d-4d2a-45a3-a137-a3ca03b5d7f0','與從弟瑾同下第後出關言別 四','盧綸','唐','唐诗','tang','','[]','誰憐苦志已三冬，却欲躬耕學老農。',32,'全唐诗/poet.tang.14000.json','["誰憐苦志已三冬，却欲躬耕學老農。", "流水白雲尋不盡，期君何處得相逢。"]'),
('8dde890d-22b5-413a-8313-9654389d378b','赴虢州留別故人','盧綸','唐','唐诗','tang','','[]','世故相逢各未閑，百年多在別離間。',32,'全唐诗/poet.tang.14000.json','["世故相逢各未閑，百年多在別離間。", "昨夜秋風今夜雨，不知何處入空山。"]'),
('2d6eff0e-d937-4d1f-9e3b-91241dd3db27','冬夜贈別友人','盧綸','唐','唐诗','tang','','[]','愁聽千家流水聲，相思獨向月中行。',64,'全唐诗/poet.tang.14000.json','["愁聽千家流水聲，相思獨向月中行。", "侵堦暗草秋霜重，遍郭寒山夜月明。", "連年客舍唯多病，數畝田園又廢耕。", "更送乘軺歸上國，應憐貢禹未成名。"]'),
('23b5a36a-565c-4de0-96e7-ff360fcde230','送顧秘書獻書後歸岳州','盧綸','唐','唐诗','tang','','[]','黃葉落不盡，蒼苔隨雨生。',48,'全唐诗/poet.tang.14000.json','["黃葉落不盡，蒼苔隨雨生。", "當軒置尊酒，送客歸江城。", "竹裏聞機杼，舟中見弟兄。", "岳陽賢太守，應爲改鄉名。"]'),
('a3dfde1b-93ff-4904-9fcd-83d96b59d571','送衞司法河中覲省','盧綸','唐','唐诗','tang','','[]','出身因強學，不以外家榮。',48,'全唐诗/poet.tang.14000.json','["出身因強學，不以外家榮。", "年少無遺事，官閑有政聲。", "曉山臨野渡，落日照軍營。", "共賞高堂下，連行弟與兄。"]'),
('e99bb380-5ddb-463b-b67c-b5fa720022e8','送從叔牧永州','盧綸','唐','唐诗','tang','','[]','五侯軒蓋行何疾，零陵太守登車日。',128,'全唐诗/poet.tang.14000.json','["五侯軒蓋行何疾，零陵太守登車日。", "零陵太守淚盈巾，此日長安方欲春。", "虎符龍節照岐路，何苦愁爲江海人。", "彼方韶景無時節，山水諸花恣開發。", "客投津戍少聞猨，鴈過瀟湘更逢雪。", "郡齋無事好閑眠，秔稻油油綠滿川。", "浪裏爭迎三蜀貨，月中喧泊九江船。", "今朝小阮同夷老，欲聞明年借幾年。"]'),
('d27cb764-d288-47e1-b54b-f25af928338d','送趙真長歸夏縣舊山依陽徵君讀書','盧綸','唐','唐诗','tang','','[]','臨杯忽泫然，非是惡離弦。',48,'全唐诗/poet.tang.14000.json','["臨杯忽泫然，非是惡離弦。", "塵陌望松雪，我衰君少年。", "幽僧曝山果，寒鹿守冰泉。", "感物如有待，況依回也賢。"]'),
('89c8832d-ba40-4c6b-a471-bd201462693b','留別耿湋侯釗馮著','盧綸','唐','唐诗','tang','','[]','相識少相知，與君俱已衰。',48,'全唐诗/poet.tang.14000.json','["相識少相知，與君俱已衰。", "笙鏞新宅第，岐路古山陂。", "學道功難就，爲儒事本遲。", "惟當與漁者，終老遂其私。"]'),
('7d6ffe22-1ced-48bf-b342-2d447fc4e0b3','送渾鍊歸覲却赴闕庭','盧綸','唐','唐诗','tang','','[]','露幕擁簪裾，台庭餞伯魚。',120,'全唐诗/poet.tang.14000.json','["露幕擁簪裾，台庭餞伯魚。", "綵衣人競看，銀詔帝親書。", "知子當元老，爲臣餞二疎。", "執珪期已迫，捧膳步寧徐。", "而我誠愚者，夫君豈病諸。", "探題多決勝，饌玉每分餘。", "榮比成功後，恩同造化初。", "甑塵方欲合，籠翮或將舒。", "榆莢錢難比，楊花雪不如。", "明朝古隄路，心斷玉人車。"]'),
('850aa54a-b97e-4f5f-a3b7-c984856f50ed','送崔邠拾遺','盧綸','唐','唐诗','tang','','[]','皎潔無瑕清玉壺，曉乘華幰向天衢。',64,'全唐诗/poet.tang.14000.json','["皎潔無瑕清玉壺，曉乘華幰向天衢。", "石建每聞宗謹孝，劉歆不敢衒師儒。", "諫修郊廟開宸慮，議按休徵淺瑞圖。", "今日攀車復何者，轅門垂白一愚夫。"]'),
('1b9217ba-c0d2-4a35-88f6-2acfb5f47c6b','送渾別駕赴舒州','盧綸','唐','唐诗','tang','','[]','江平蘆荻齊，五兩貼檣低。',48,'全唐诗/poet.tang.14000.json','["江平蘆荻齊，五兩貼檣低。", "遶郭覆晴雪，滿船聞曙雞。", "鱣魴宜入貢，橘柚亦成蹊。", "還似海沂日，風清無鼓鼙。"]'),
('e9f73be3-747b-4f57-81d5-b45bbb2672fc','送從叔士準赴任潤州司士','盧綸','唐','唐诗','tang','','[]','雲起山城暮，沈沈江上天。',48,'全唐诗/poet.tang.14000.json','["雲起山城暮，沈沈江上天。", "風吹建業雨，浪入廣陵船。", "久是吳門客，嘗聞謝守賢。", "終悲去國遠，淚盡竹林前。"]'),
('823c919b-3ad6-47c7-bd05-3e89d7b74183','送尹樞令狐楚及第後歸覲','盧綸','唐','唐诗','tang','','[]','佳人比香草，君子即芳蘭。',48,'全唐诗/poet.tang.14000.json','["佳人比香草，君子即芳蘭。", "寶器金罍重，清音玉珮寒。", "貢文齊受寵，獻禮兩承歡。", "鞍馬幷汾地，爭迎陸與潘。"]'),
('3de6e3ed-1985-41b6-8f63-bb2d9ec70c4c','東潭宴餞河南趙少府','盧綸','唐','唐诗','tang','','[]','十載奉戎軒，日聞君子言。',72,'全唐诗/poet.tang.14000.json','["十載奉戎軒，日聞君子言。", "方將賀榮爵，遽乃愴離尊。", "岸轉臺閣麗，潭清弦管繁。", "松篁難晦節，雨露不私恩。", "坐使吏相勉，居爲儒所尊。", "可憐桃李樹，先發信陵門。"]'),
('bc5c830a-ae41-48d9-9316-d825950f2ad1','賦得館娃宮送王山人遊江東','盧綸','唐','唐诗','tang','','[]','蒼蒼楓樹林，草合廢宮深。',48,'全唐诗/poet.tang.14000.json','["蒼蒼楓樹林，草合廢宮深。", "越水風浪起，吳王歌管沈。", "燕歸巢已盡，鶴語塚難尋。", "旅泊彼何夜，希君抽玉琴。"]'),
('01dd8f01-0719-4251-b373-1ef5431694ed','送暢當還舊山','盧綸','唐','唐诗','tang','','[]','常逢明月馬塵間，是夜照君歸處山。',32,'全唐诗/poet.tang.14000.json','["常逢明月馬塵間，是夜照君歸處山。", "山中松桂花盡發，頭白屬君如等閑。"]'),
('4c269ef5-b94d-4fe7-ad07-da7baa370c63','斅顏魯公送挺贇歸翠微寺','盧綸','唐','唐诗','tang','','[]','挺贇惠學該儒釋，袖有顏徐真草跡。',64,'全唐诗/poet.tang.14000.json','["挺贇惠學該儒釋，袖有顏徐真草跡。", "一齋三請紀行詩，誚我垂鞭弄鳴鏑。", "寺懸金榜半山隅，石路荒涼松樹枯。", "虎跡印雪大如斗，閏月暮天過得無。"]'),
('30176746-2898-4ae6-be84-c496504a227b','送契玄法師赴內道場','盧綸','唐','唐诗','tang','','[]','昏昏醉老夫，灌頂遇醍醐。',48,'全唐诗/poet.tang.14000.json','["昏昏醉老夫，灌頂遇醍醐。", "嬪御呈心鏡，君王賜髻珠。", "降魔須戰否，問疾敢行無。", "深契何相秘，儒宗本不殊。"]'),
('3157dc45-54a2-4643-a4bd-9eec2441ca2c','送暢當赴山南幕','盧綸','唐','唐诗','tang','','[]','含情脫佩刀，持以佐賢豪。',48,'全唐诗/poet.tang.14000.json','["含情脫佩刀，持以佐賢豪。", "是月霜霰下，伊人行役勞。", "事將名共易，文與行空高。", "去矣奉戎律，悲君爲我曹。"]'),
('4bb57168-b7d4-4c36-9df0-e08236a5bf7d','顏侍御廳叢篁詠送薛存誠','盧綸','唐','唐诗','tang','','[]','玉幹百餘莖，生君此堂側。',36,'全唐诗/poet.tang.14000.json','["玉幹百餘莖，生君此堂側。", "拂簾寒雨響，擁砌深溪色。", "何事鳳皇雛，茲焉理歸翼。"]'),
('b0dc4078-378a-471e-8eb0-4343879ae9c9','秋晚河西縣樓送渾中允赴朝闕','盧綸','唐','唐诗','tang','','[]','高樓吹玉簫，車馬上河橋。',48,'全唐诗/poet.tang.14000.json','["高樓吹玉簫，車馬上河橋。", "岐路自奔隘，壺觴終寂寥。", "芳蘭生貴里，片玉立清朝。", "今日台庭望，心遙非地遙。"]'),
('af5c3f87-a819-4c5a-9960-4881d6d03273','達奚中丞東齋壁畫山水各賦一物得樹杪懸泉送長安趙元陽少府','盧綸','唐','唐诗','tang','','[]','素壁畫飛泉，從雲落樹顛。',48,'全唐诗/poet.tang.14000.json','["素壁畫飛泉，從雲落樹顛。", "練垂疑葉響，雲幷覺枝偏。", "利物得雙劒，爲儒當一賢。", "應思灑塵陌，調膳亦芳鮮。"]'),
('e1051bde-d8a9-4348-973a-c6acd003e327','送信州姚使君','盧綸','唐','唐诗','tang','','[]','朱幡徐轉候羣官，猨鳥無聲郡宇寬。',64,'全唐诗/poet.tang.14000.json','["朱幡徐轉候羣官，猨鳥無聲郡宇寬。", "楚國上腴收賦重，漢家良牧得人難。", "銅鉛滿穴山能富，鴻鴈連羣地亦寒。", "幾日政聲聞戶外，九江行旅得相歡。"]'),
('633c72af-1ed0-4cd5-8aac-00ecea86a65f','送暢當','盧綸','唐','唐诗','tang','','[]','四望無極路，千里流大河。',24,'全唐诗/poet.tang.14000.json','["四望無極路，千里流大河。", "秋風滿離袂，唯老事唯多。"]'),
('ffb3248c-abec-4a64-8c24-8577c6893fb7','送史兵曹判官赴樓煩','盧綸','唐','唐诗','tang','','[]','渥洼龍種散雲時，千里繁花乍別離。',64,'全唐诗/poet.tang.14000.json','["渥洼龍種散雲時，千里繁花乍別離。", "中有重臣承霈澤，外無輕虜犯旌旗。", "山川自與郊坰合，帳幕時因水草移。", "敢謝親賢得瓊玉，仲宣能賦亦能詩。"]'),
('cc316afd-c02e-4dfc-84c4-6b10d3d78219','送曇延法師講罷赴上都','盧綸','唐','唐诗','tang','','[]','金縷架裟國大師，能銷壞宅火燒時。',32,'全唐诗/poet.tang.14000.json','["金縷架裟國大師，能銷壞宅火燒時。", "復來擁膝說無住，知向人天何處期。"]'),
('88a9e2b4-fa9f-4951-ab79-8b92b6d1621b','送道士郄彝素歸內道場','盧綸','唐','唐诗','tang','','[]','病老正相仍，忽逢張道陵。',48,'全唐诗/poet.tang.14000.json','["病老正相仍，忽逢張道陵。", "羽衣風淅淅，仙貌玉稜稜。", "叱我問中壽，教人祈上昇。", "樓居五雲裏，幾與武皇登。"]'),
('ea61eaf5-a7f3-44da-aeb8-6d7ebe3c288c','賦得彭祖樓送楊德宗歸徐州幕','盧綸','唐','唐诗','tang','','[]','四戶八窗明，玲瓏逼上清。',48,'全唐诗/poet.tang.14000.json','["四戶八窗明，玲瓏逼上清。", "外欄黃鵠下，中柱紫芝生。", "每帶雲霞色，時聞簫管聲。", "望君兼有月，幢蓋儼層城。"]'),
('2e24d80f-7b9a-4fd8-896e-a34db37feb5e','送餞從叔辭豐州幕歸嵩陽舊居','盧綸','唐','唐诗','tang','','["\u9001\u522b"]','白鬚宗孫侍坐時，願持壽酒前致詞。',204,'全唐诗/poet.tang.14000.json','["白鬚宗孫侍坐時，願持壽酒前致詞。", "鄙詞何所擬，請自邊城始。", "邊城貴者李將軍，戰鼓遙疑天上聞。", "屯田布錦周千里，牧馬攢花溢萬羣。", "白雲本是喬松伴，來遶青營復飛散。", "三聲畫角咽不通，萬里蓬根一時斷。", "豐州聞說似涼州，沙塞晴明部落稠。", "行客已去依獨戍，主人猶自在高樓。", "夢親旌斾何由見，每阻清風一回面。", "洞裏先生那怪遲，人天無路自無期。", "砂泉丹井非同味，桂樹榆林不並枝。", "吾翁致身殊得計，地仙亦是三千歲。", "莫著戎衣期上清，東方曼倩逢人輕。"]'),
('95aa10ba-37dc-4e03-98d3-01b062a33b46','送靜居法師','盧綸','唐','唐诗','tang','','[]','五色香幢重復重，寶輿升座發神鐘。',64,'全唐诗/poet.tang.14000.json','["五色香幢重復重，寶輿升座發神鐘。", "薝蔔名花飄不斷，醍醐法味灑何濃。", "九天論道當宸眷，七祖傳心合聖蹤。", "願比靈山前世別，多生還得此相逢。"]'),
('9baa1d59-a041-4057-974b-b2b7a95fba87','送劉判官赴豐州','盧綸','唐','唐诗','tang','','[]','銜杯吹急管，滿眼起風砂。',48,'全唐诗/poet.tang.14000.json','["銜杯吹急管，滿眼起風砂。", "大漠山沈雪，長城草發花。", "策行須耻戰，虜在莫言家。", "余亦祈勳者，如何別左車。"]'),
('8335908b-31c3-42ea-86f1-79923f863695','將赴京留獻令公','盧綸','唐','唐诗','tang','','[]','沙鶴驚鳴野雨收，大河風物颯然秋。',32,'全唐诗/poet.tang.14000.json','["沙鶴驚鳴野雨收，大河風物颯然秋。", "力微恩重諒難報，不是行人不解愁。"]'),
('9e2719bc-e145-4d72-a9ed-344080a291ed','落第後歸山下舊居留別劉起居昆季','盧綸','唐','唐诗','tang','','[]','寂寞過朝昏，沈憂豈易論。',120,'全唐诗/poet.tang.14000.json','["寂寞過朝昏，沈憂豈易論。", "有時空卜命，無事可酬恩。", "寄食依鄰里，成家望子孫。", "風塵知世路，衰賤到君門。", "醉裏因多感，愁中欲強言。", "花林逢廢井，戰地識荒園。", "悵別臨晴野，悲春上古原。", "鳥歸山外樹，人過水邊村。", "潘岳方稱老，嵇康本厭喧。", "誰堪將落羽，迴首仰飛翻。"]'),
('38ac5aee-b8ad-4472-9514-957044c782b2','將赴閿鄉灞上留別錢起員外','盧綸','唐','唐诗','tang','','[]','暖景登橋望，分明春色來。',48,'全唐诗/poet.tang.14000.json','["暖景登橋望，分明春色來。", "離心自惆悵，車馬亦裴回。", "遠雪和霜積，高花占日開。", "從官竟何事，憂患已相催。"]'),
('f3d7f3b7-f997-4255-bbb2-aaaefc780b82','虢州逢侯釗同尋南觀因贈別','盧綸','唐','唐诗','tang','','[]','相見翻惆悵，應憐責廢官。',96,'全唐诗/poet.tang.14000.json','["相見翻惆悵，應憐責廢官。", "過深慙祿在，識淺賴刑寬。", "獨失耕農業，同思弟姪歡。", "衰貧羞客過，卑束會君難。", "放鶴登雲壁，澆花遶石壇。", "興遠江海上，跡在是非端。", "林密風聲細，山高雨色寒。", "悠然此中別，賓僕亦闌干。"]'),
('5dea3cc6-b281-4169-83bb-9a9391f826bf','赴池州拜覲舅氏留上考功郎中舅','盧綸','唐','唐诗','tang','','[]','孤賤易磋砣，其如酷似何。',48,'全唐诗/poet.tang.14000.json','["孤賤易磋砣，其如酷似何。", "衰榮同族少，生長外家多。", "別國桑楡在，沾衣血淚和。", "應憐失行鴈，霜霰寄煙波。"]'),
('27984721-9a86-47a3-b942-b6e1264f4d12','送從姪滁州覲省','盧綸','唐','唐诗','tang','','[]','愛爾似龍媒，翩翩千里迴。',48,'全唐诗/poet.tang.14000.json','["愛爾似龍媒，翩翩千里迴。", "書從外氏學，竹自晉時栽。", "擁棹逢鷗舞，憑闌見雨來。", "上堂多慶樂，不醉莫停杯。"]'),
('fb7ac565-d4bb-42c0-b034-033d94795030','奉和聖製麟德殿宴百僚','盧綸','唐','唐诗','tang','','[]','雲闢御筵張，山呼聖壽長。',72,'全唐诗/poet.tang.14000.json','["雲闢御筵張，山呼聖壽長。", "玉欄豐瑞草，金陛立神羊。", "台鼎資庖膳，天星奉酒漿。", "蠻夷陪作位，犀象舞成行。", "網已祛三面，歌因守四方。", "千秋不可極，花發滿宮香。"]'),
('eea43bd0-2636-4ca4-a38a-653a9bff0ba2','和考功王員外杪秋憶終南舊居','盧綸','唐','唐诗','tang','','[]','靜憶溪邊宅，知君許謝公。',96,'全唐诗/poet.tang.14000.json','["靜憶溪邊宅，知君許謝公。", "曉霜凝耒耜，初日照梧桐。", "澗鼠喧藤蔓，山禽竄石藂。", "白雲當嶺雨，黃葉遶堦風。", "野果垂橋上，高泉落水中。", "歡榮來自間，羸賤賞曾同。", "月滿珠藏海，天晴鶴在籠。", "餘陰如可寄，願得隱牆東。"]'),
('bbb02e08-ae97-4c87-b015-1db60f13b045','詶暢當尋嵩岳麻道士見寄','盧綸','唐','唐诗','tang','','[]','聞逐樵夫閑看棋，忽逢人世是秦時。',64,'全唐诗/poet.tang.14000.json','["聞逐樵夫閑看棋，忽逢人世是秦時。", "開雲種玉嫌山淺，渡海傳書怪鶴遲。", "陰洞石牀微有字，古壇松樹半無枝。", "煩君遠示青囊籙，願得相從一問師。"]'),
('93751d8f-6384-4713-abd4-bca9a7a64b29','詶李端長安寓居偶詠見寄','盧綸','唐','唐诗','tang','','[]','自別前峰隱，同爲外累侵。',120,'全唐诗/poet.tang.14000.json','["自別前峰隱，同爲外累侵。", "幾年親酒會，此日有僧尋。", "學稼功還棄，論邊事亦沈。", "衆歡徒滿目，專愛久離心。", "覽鬢絲垂鏡，彈琴淚灑襟。", "訪田悲洛下，寄宅憶山陰。", "薄溜漫青石，橫雲架碧林。", "壞簷藤障密，衰菜棘籬深。", "流散俱多故，憂傷併在今。", "唯當竢高躅，歸止共抽簪。"]'),
('3605101a-e5e1-49fb-b520-9f2279355a4f','和常舍人晚秋集賢院即事十二韻寄贈江南徐薛二侍郎','盧綸','唐','唐诗','tang','','[]','綸閣九華前，森沈綵仗連。',144,'全唐诗/poet.tang.14000.json','["綸閣九華前，森沈綵仗連。", "洞門開旭日，清禁肅秋天。", "霜滿朝容備，鐘餘漏唱傳。", "搖璫陪羽扇，端弁入爐煙。", "麟筆刪金篆，龍綃薦玉編。", "汲書荀勖定，漢史蔡邕專。", "御竹潛通筍，宮池暗瀉泉。", "亂藂縈弱蕙，墮葉灑枯蓮。", "列署齊遊日，重江並謫年。", "登封思議草，侍講憶同筵。", "滄海風濤廣，黝山瘴雨偏。", "唯應緘上寶，贈遠一呈妍。"]'),
('64e309ab-ec52-493a-80a5-205fb3ff8174','詶苗員外仲夏歸郊居遇雨見寄','盧綸','唐','唐诗','tang','','[]','雷響風仍急，人歸鳥亦還。',48,'全唐诗/poet.tang.14000.json','["雷響風仍急，人歸鳥亦還。", "亂雲方至水，驟雨已喧山。", "田鼠依林上，池魚戲草間。", "因茲屏埃霧，一詠一開顏。"]'),
('3f0f4f2b-3fc2-4db3-91c1-daf5136b080e','和太常王卿立秋日即事','盧綸','唐','唐诗','tang','','[]','嵩高雲日明，潘岳賦初成。',96,'全唐诗/poet.tang.14000.json','["嵩高雲日明，潘岳賦初成。", "籬槿花無色，堦桐葉有聲。", "絳紗垂簟淨，白羽拂衣輕。", "鴻鴈悲天遠，龜魚覺水清。", "別弦添楚思，牧馬動邊情。", "田雨農官問，林風苑吏驚。", "松篁終茂盛，蓬艾自衰榮。", "遙仰憑軒夕，惟應喜宋生。"]'),
('3f4a9b7f-91db-47bf-872c-ba4513834339','和李使君三郎早秋城北亭樓宴崔司士因寄關中弟張評事時遇','盧綸','唐','唐诗','tang','','[]','黃花古城路，上盡見青山。',72,'全唐诗/poet.tang.14000.json','["黃花古城路，上盡見青山。", "桑柘晴川口，牛羊落照間。", "野情隨卷幔，軍士隔重關。", "道合偏多賞，官微獨不閑。", "鶴分琴久罷，書到鴈應還。", "爲謝登龍客，瓊枝寄一攀。"]'),
('b065fd72-f420-4476-b08f-b1e469421154','和趙端公九日登石亭上和州家兄','盧綸','唐','唐诗','tang','','[]','洛浦想江津，悲懽共此辰。',48,'全唐诗/poet.tang.14000.json','["洛浦想江津，悲懽共此辰。", "採花湖岸菊，望國舊樓人。", "鴈別聲偏苦，松寒色轉新。", "傳書問漁叟，借寇爾何因。"]'),
('1f83eb9a-3855-4c71-b041-3930a9a7af6b','酬趙少尹戲示諸姪元陽等因以見贈','盧綸','唐','唐诗','tang','','[]','八龍三虎儼成行，瓊樹花開鶴翼張。',64,'全唐诗/poet.tang.14000.json','["八龍三虎儼成行，瓊樹花開鶴翼張。", "且請同觀舞鸜鵒，何須竟哂食檳榔。", "歸時每愛懷朱橘，戲處常聞佩紫囊。", "謬入阮家逢慶樂，竹林因得奉壺觴。"]'),
('089d0bcb-2a45-4012-b073-5ab3e3dabeb9','奉和戶曹叔夏夜寓直寄呈同曹諸公幷見示','盧綸','唐','唐诗','tang','','[]','歛板捧清詞，恭聞侍直時。',72,'全唐诗/poet.tang.14000.json','["歛板捧清詞，恭聞侍直時。", "暮塵歸衆騎，邃宇捨諸司。", "華月先燈至，清風與簟隨。", "亂螢光熠熠，行樹影離離。", "龍臥人寧識，鵬摶鷃豈知。", "便因當五夜，敢望竹林期。"]'),
('6e09aa83-4156-40d8-b632-18c601d5ddd4','和金吾裴將軍使往河北宣慰因訪張氏昆季舊居兼寄趙侍郎趙卿拜陵未迴','盧綸','唐','唐诗','tang','','[]','飛軒不駐輪，感激漢儒臣。',48,'全唐诗/poet.tang.14000.json','["飛軒不駐輪，感激漢儒臣。", "氣懾千夫勇，恩傳萬里春。", "古原收野燎，寒笛怨空鄰。", "書此達良友，五陵風雨頻。"]'),
('ba87093f-936d-411c-badb-8c3003ae0fdb','和太常李主簿秋中山下別墅即事','盧綸','唐','唐诗','tang','','[]','清秋來幾時，宋玉已先知。',48,'全唐诗/poet.tang.14000.json','["清秋來幾時，宋玉已先知。", "曠朗霞映竹，澄明山滿池。", "葺橋雙鶴赴，收果衆猨隨。", "韶樂方今奏，雲林徒蔽虧。"]'),
('5f12745a-3ef3-42fb-9a16-60e838ba3516','詶韋渚秋夜有懷見寄','盧綸','唐','唐诗','tang','','[]','蕭條良夜永，秋草對衰顏。',48,'全唐诗/poet.tang.14000.json','["蕭條良夜永，秋草對衰顏。", "露下鳥初定，月明人自閑。", "獨悲無舊業，共喜出時艱。", "爲問功成後，同遊何處山。"]'),
('ef4d4ca2-59ea-4c84-b360-b63252700998','同吉中孚夢桃源 一','盧綸','唐','唐诗','tang','','[]','春雨夜不散，夢中山亦陰。',36,'全唐诗/poet.tang.14000.json','["春雨夜不散，夢中山亦陰。", "雲中碧潭水，路暗紅花林。", "花水自深淺，無人知古今。"]'),
('738fc3d5-b2e3-4f00-8a81-496c103cdd58','同吉中孚夢桃源 二','盧綸','唐','唐诗','tang','','[]','夜靜春夢長，夢逐仙山客。',36,'全唐诗/poet.tang.14000.json','["夜靜春夢長，夢逐仙山客。", "園林滿芝朮，雞犬傍籬柵。", "幾處花下人，看予笑頭白。"]'),
('e7686a0a-7362-4c2f-94d2-e18d8640534a','同柳侍郎題侯釗侍郎新昌里','盧綸','唐','唐诗','tang','','[]','清源君子居，左右盡圖書。',48,'全唐诗/poet.tang.14000.json','["清源君子居，左右盡圖書。", "三逕春自足，一飄歡有餘。", "庭莎成野席，闌藥是家蔬。", "幽顯豈殊迹，昔賢徒病諸。"]'),
('47ea4507-5110-4770-beaf-12ff42e511b1','詶孫侍御春日見寄','盧綸','唐','唐诗','tang','','[]','經過里巷春，同是謝家鄰。',48,'全唐诗/poet.tang.14000.json','["經過里巷春，同是謝家鄰。", "願我覺衰早，荷君留醉頻。", "松高猶覆草，鶴起暫縈塵。", "始悟達人志，患名非患貧。"]'),
('c0ae1fbb-2b3a-43c9-818e-bf8bc851e13d','和王員外冬夜寓直','盧綸','唐','唐诗','tang','','[]','高步長裾錦帳郎，居然自是漢賢良。',64,'全唐诗/poet.tang.14000.json','["高步長裾錦帳郎，居然自是漢賢良。", "潘岳敘年因鬢髮，揚雄託諫在文章。", "九天韶樂飄寒月，萬戶香塵裛曉霜。", "坐見重門儼朝騎，可憐雲路獨翺翔。"]'),
('fa7b45a8-c4df-4a01-89e8-5e5578683daa','詶金部王郎中省中春日見寄','盧綸','唐','唐诗','tang','','[]','南宮樹色曉森森，雖有春光未有陰。',64,'全唐诗/poet.tang.14000.json','["南宮樹色曉森森，雖有春光未有陰。", "鶴侶正疑芳景引，玉人那爲簿書沈。", "山含瑞氣偏當日，鶯逐輕風不在林。", "更有阮郎迷路處，萬株紅樹一溪深。"]'),
('85e6b7b3-2a83-4c52-ad75-3cfc8dd085fb','奉和陝州十四翁中丞寄雷州二十翁司戶','盧綸','唐','唐诗','tang','','[]','聯飛獨不前，迥落海南天。',48,'全唐诗/poet.tang.14000.json','["聯飛獨不前，迥落海南天。", "賈傅竟行矣，邵公唯泫然。", "瘴開山更遠，路極水無邊。", "沈劣本多感，況聞原上篇。"]'),
('246d388f-1a6f-4b5d-a153-617a64578503','和李中丞詶萬年房署少府過汾州景雲觀因以寄上房與李早年同居此觀','盧綸','唐','唐诗','tang','','[]','顯晦澹無迹，賢哉常晏如。',96,'全唐诗/poet.tang.14000.json','["顯晦澹無迹，賢哉常晏如。", "如何警孤鶴，忽乃傳雙魚。", "敘以泉石舊，悵然風景餘。", "低回青油幕，夢寐白雲居。", "玉洞桂香滿，雪壇松影疎。", "沈思矚仙侶，紓組正軍書。", "積學早成道，感恩難遂初。", "梅生諒多感，歸止豈吾廬。"]'),
('015761cf-2c04-44fa-8974-aafe4fa19be3','詶陳翃郎中冬至攜柳郎竇郎歸河中舊居見寄','盧綸','唐','唐诗','tang','','[]','三旬一休沐，清景滿林廬。',60,'全唐诗/poet.tang.14000.json','["三旬一休沐，清景滿林廬。", "南郭羣儒從，東牀兩客居。", "燒煙浮雪野，麥隴潤冰渠。", "班白皆持酒，蓬茅盡有書。", "終期買寒渚，同此利蒲魚。"]'),
('07c2d6f0-617e-4bf9-a17b-470adf7131d7','詶李益端公夜宴見贈','盧綸','唐','唐诗','tang','','[]','戚戚一西東，十年今始同。',24,'全唐诗/poet.tang.14000.json','["戚戚一西東，十年今始同。", "可憐歌酒夜，相對兩衰翁。"]'),
('6727d4be-e69f-40c9-b0ce-f3c2e0c65143','和陳翃郎中拜本府少尹兼侍御史獻上侍中因呈同院諸公','盧綸','唐','唐诗','tang','','[]','金印垂鞍白馬肥，不同疏廣老方歸。',64,'全唐诗/poet.tang.14000.json','["金印垂鞍白馬肥，不同疏廣老方歸。", "三千士裏文章伯，四十年來錦繡衣。", "節比青松當澗直，心隨黃雀繞簷飛。", "鄉中賀者唯爭路，不識傳呼獬豸威。"]'),
('0dfa55a6-539d-4845-8345-a0b0ef54aabf','和王倉少尹暇日言懷','盧綸','唐','唐诗','tang','','[]','清秋多暇日，況乃是夫君。',48,'全唐诗/poet.tang.14000.json','["清秋多暇日，況乃是夫君。", "習靜通仙事，書空閱篆文。", "劒飛終上漢，鶴夢不離雲。", "無限煙霄路，何嗟迹未分。"]'),
('c653586e-9b23-4c63-999c-d0a29808e14b','和崔侍郎遊萬固寺','盧綸','唐','唐诗','tang','','[]','聞說中方高樹林，曙華先照囀春禽。',64,'全唐诗/poet.tang.14000.json','["聞說中方高樹林，曙華先照囀春禽。", "風雲才子冶遊思，蒲柳老人惆悵心。", "石路青苔花漫漫，雪簷垂溜玉森森。", "賀君此去君方至，河水東流西日沈。"]'),
('412f8f86-fdee-4f41-ac00-b5f134ea11c3','和裴延齡尚書寄題果州謝舍人仙居','盧綸','唐','唐诗','tang','','[]','飄然去謁八仙翁，自地從天香滿空。',64,'全唐诗/poet.tang.14000.json','["飄然去謁八仙翁，自地從天香滿空。", "紫蓋迥標雙鶴上，語音猶在五雲中。", "青溪不接漁樵路，丹井唯傳草木風。", "歌此因思捧金液，露盤長慶漢皇宮。"]'),
('65cf6d87-a180-405b-941e-9ed8a5ed7146','詶崔侍御早秋臥病書情見寄時君亦抱疾在假中','盧綸','唐','唐诗','tang','','[]','擲地金聲信有之，瑩然冰玉見清詞。',64,'全唐诗/poet.tang.14000.json','["擲地金聲信有之，瑩然冰玉見清詞。", "元凱癖成官始貴，相如渴甚貌逾衰。", "荒園每覺蟲鳴早，華館常聞客散遲。", "寂寞罷琴風滿樹，幾多黃葉落蛛絲。"]'),
('7aa8c472-79b3-4383-ab05-f1435539897a','詶靈澈上人','盧綸','唐','唐诗','tang','','[]','軍人奉役本無期，落葉花開總不知。',32,'全唐诗/poet.tang.14000.json','["軍人奉役本無期，落葉花開總不知。", "走馬城中頭雪白，若爲將面見湯師。"]'),
('a2e11c61-f2e3-455d-bbad-c8d74a3bc578','敬詶大府二十四舅覽詩卷因以見示','盧綸','唐','唐诗','tang','','[]','郄公憐戇亦憐愚，忽贈金盤徑寸珠。',64,'全唐诗/poet.tang.14000.json','["郄公憐戇亦憐愚，忽贈金盤徑寸珠。", "徹底碧潭滋涸溜，壓枝紅豔照枯株。", "九門洞啓延高論，百辟聯行挹大儒。", "顧己文章非酷似，敢將幽劣俟洪爐。"]'),
('e36ecfc7-f33c-4091-b1a1-ca0451106ac1','雨中酬友人','盧綸','唐','唐诗','tang','','[]','看山獨行歸竹院，水遶前堦草生遍。',32,'全唐诗/poet.tang.14000.json','["看山獨行歸竹院，水遶前堦草生遍。", "空林細雨暗無聲，唯有愁心兩相見。"]'),
('0524aa8b-ee7d-44e6-a9bb-d52e213faeb9','詶人失題','盧綸','唐','唐诗','tang','','[]','孤鸞將鶴羣，晴日麗春雲。',24,'全唐诗/poet.tang.14000.json','["孤鸞將鶴羣，晴日麗春雲。", "何幸晚飛者，清音長此聞。"]'),
('3963634a-eeb5-4f05-b1e4-05bf1aedeb0c','哭司農苗主簿','盧綸','唐','唐诗','tang','','[]','原頭殯御遶新塋，原下行人望哭聲。',32,'全唐诗/poet.tang.14000.json','["原頭殯御遶新塋，原下行人望哭聲。", "更想秋山連古木，唯應石上見君名。"]'),
('b4a1ab97-d8c8-4380-b75e-c95a9337f5c7','得耿湋司法書因敘長安故友零落兵部苗員外發祕省李校書端相次傾逝潞府崔功曹峒長林司空丞曙俱謫遠方余以搖落之時對書增歎因呈河中鄭倉曹暢參軍昆季','盧綸','唐','唐诗','tang','','[]','鬢似衰蓬心似灰，驚悲相集老相催。',64,'全唐诗/poet.tang.14000.json','["鬢似衰蓬心似灰，驚悲相集老相催。", "故友九泉留語別，逐臣千里寄書來。", "塵容帶病何堪問，淚眼逢秋不喜開。", "幸接野居宜屣步，冀君清夜一申哀。"]'),
('d75188bd-f549-459c-bdd6-61aec76cef31','同兵部李紓侍郎刑部包佶侍郎哭皇甫侍御曾','盧綸','唐','唐诗','tang','','[]','攀龍與泣麟，哀樂不同塵。',48,'全唐诗/poet.tang.14000.json','["攀龍與泣麟，哀樂不同塵。", "九陌霄漢侶，一燈冥漠人。", "舟沈驚海闊，蘭折怨霜頻。", "已矣復何見，故山應更春。"]'),
('b91ff41f-b0e8-404c-a50c-c0a288abe784','綸與吉侍郎中孚司空郎中曙苗員外發崔補闕峒耿拾遺湋李校書端風塵追遊向三十載數公皆負當時盛稱榮耀未幾俱沈下泉暢博士當感懷前蹤有五十韻見寄輙有所詶以申悲舊兼寄夏侯侍御審侯倉曹釗','盧綸','唐','唐诗','tang','','[]','稟命孤且賤，少爲病所嬰。',288,'全唐诗/poet.tang.14000.json','["稟命孤且賤，少爲病所嬰。", "八歲始讀書，四方遂有兵。", "童心幸不羈，此去負平生。", "是月胡入洛，明年天隕星。", "夜行登灞陵，惝怳靡所征。", "雲海一翻蕩，魚龍俱不寧。", "因浮襄江流，遠寄鄱陽城。", "鄱陽富學徒，誚我戇無營。", "諭以詩禮義，朂隨賓薦名。", "舟車更滯留，水陸互陰晴。", "曉望怯雲陣，夜愁驚鶴聲。", "淒淒指宋郊，浩浩入秦京。", "沴氣既風散，皇威如日明。", "方逢粟比金，未識公與卿。", "十上不可待，三年竟無成。", "偶爲達者知，揚我于王廷。", "素志且不立，青袍徒見縈。", "昏孱夙自保，靜躁本殊形。", "始趨甘棠陰，旋遇密人迎。", "考實績無取，責能才固輕。", "新豐古離宮，宮樹鎖雲扃。", "中復蒞茲邑，往惟曾所經。", "繚垣何逶迤，水殿亦崢嶸。", "夜雨滴金砌，陰風吹玉楹。"]'),
('2dd8df32-0601-4f93-b0d9-37ce1f01be95','詶李叔度秋夜喜相遇因傷關東僚友喪逝見贈','盧綸','唐','唐诗','tang','','[]','寒月照秋城，秋風泉澗鳴。',96,'全唐诗/poet.tang.14000.json','["寒月照秋城，秋風泉澗鳴。", "過時見蘭蕙，獨夜感衰榮。", "酒散同移疾，心悲似遠行。", "以愚求作友，何德敢稱兄。", "谷變波長急，松枯藥未成。", "恐看新鬢色，怯問故人名。", "野澤雲陰散，荒原日氣生。", "羈飛本難定，非是惡弦驚。"]'),
('a72524f5-d40b-4922-99ae-861a0fb0c509','同李益傷秋','盧綸','唐','唐诗','tang','','[]','歲去人頭白，秋來樹葉黃。',24,'全唐诗/poet.tang.14000.json','["歲去人頭白，秋來樹葉黃。", "搔頭向黃葉，與爾共悲傷。"]'),
('1092a9c6-64db-4054-aafb-291adc717d8a','白髮嘆','盧綸','唐','唐诗','tang','','[]','髮白曉梳頭，女驚妻淚流。',24,'全唐诗/poet.tang.14000.json','["髮白曉梳頭，女驚妻淚流。", "不知絲色後，堪得幾回秋。"]'),
('edb5c9df-2eb5-4dd6-bf38-0b01d4081f6d','逢病軍人','盧綸','唐','唐诗','tang','','["\u519b\u4eba", "\u6218\u4e89", "\u4f24\u6000"]','行多有病住無糧，萬里還鄉未到鄉。',32,'全唐诗/poet.tang.14000.json','["行多有病住無糧，萬里還鄉未到鄉。", "蓬鬢哀吟古城下，不堪秋氣入金瘡。"]'),
('2f1dce3e-e0f6-4da4-b110-e8686d1c1119','村南逢病叟','盧綸','唐','唐诗','tang','','[]','雙膝過頤頂在肩，四鄰知姓不知年。',32,'全唐诗/poet.tang.14000.json','["雙膝過頤頂在肩，四鄰知姓不知年。", "臥驅鳥雀惜禾黍，猶恐諸孫無社錢。"]'),
('b9402122-80d2-4755-9cf1-1a6bd5a9a6de','七夕詩','盧綸','唐','唐诗','tang','','[]','祥光若可求，閨女夜登樓。',48,'全唐诗/poet.tang.14000.json','["祥光若可求，閨女夜登樓。", "月露浩方下，河雲凝不流。", "鉛華潛警曙，機杼暗傳秋。", "迴想歛餘睠，人天俱是愁。"]'),
('6a2b993c-ca63-4e68-bcce-20f953689061','七夕詩','盧綸','唐','唐诗','tang','','[]','涼風吹玉露，河漢有幽期。',48,'全唐诗/poet.tang.14000.json','["涼風吹玉露，河漢有幽期。", "星彩光仍隱，雲容掩復離。", "良宵驚曙早，閏歲怨秋遲。", "何事金閨子，空傳得網絲。"]'),
('c7751487-3843-42df-a0ff-1dba49722fa7','長門怨','盧綸','唐','唐诗','tang','','[]','空空古廊殿，寒月落斜暉。',24,'全唐诗/poet.tang.14000.json','["空空古廊殿，寒月落斜暉。", "臥聽未央曲，滿箱歌舞衣。"]'),
('3d462584-b67d-405d-941a-a59f28f03d94','妾薄命','盧綸','唐','唐诗','tang','','[]','妾年初二八，兩度嫁狂夫。',24,'全唐诗/poet.tang.14000.json','["妾年初二八，兩度嫁狂夫。", "薄命今猶在，堅貞掃地無。"]'),
('8a49c55f-ed4f-4f9c-8662-db588b07163b','倫開府席上賦得詠美人名解愁','盧綸','唐','唐诗','tang','','[]','不敢苦相留，明知不自由。',48,'全唐诗/poet.tang.14000.json','["不敢苦相留，明知不自由。", "嚬眉乍欲語，歛笑又低頭。", "舞態兼些醉，歌聲似帶羞。", "今朝總見也，只不解人愁。"]'),
('25178caa-eeb3-44b5-a538-725e4ce06950','王評事駙馬花燭詩 一','盧綸','唐','唐诗','tang','','[]','萬條銀燭引天人，十月長安半夜春。',32,'全唐诗/poet.tang.14000.json','["萬條銀燭引天人，十月長安半夜春。", "步障三千隘將斷，幾多珠翠落香塵。"]'),
('869d28be-f4c6-4370-ad21-272fac45cfbf','王評事駙馬花燭詩 二','盧綸','唐','唐诗','tang','','[]','一人女壻萬人憐，一夜調疎抵百年。',32,'全唐诗/poet.tang.14000.json','["一人女壻萬人憐，一夜調疎抵百年。", "爲報司徒好將息，明珠解轉又能圓。"]'),
('7dfe365b-47f5-46c8-bde6-e49325ec8d9a','王評事駙馬花燭詩 三','盧綸','唐','唐诗','tang','','[]','人主人臣是親家，千秋萬歲保榮華。',32,'全唐诗/poet.tang.14000.json','["人主人臣是親家，千秋萬歲保榮華。", "幾時曾向高天上，得見今宵月裏花。"]'),
('70499d47-c193-4631-915f-262d7054f691','王評事駙馬花燭詩 四','盧綸','唐','唐诗','tang','','[]','比翼和鳴雙鳳皇，欲棲金帳滿城香。',32,'全唐诗/poet.tang.14000.json','["比翼和鳴雙鳳皇，欲棲金帳滿城香。", "平明却入天泉裏，日氣曈曨五色光。"]'),
('e7ac328e-9028-4ed3-9929-20caeac0360c','和趙給事白蠅拂歌','盧綸','唐','唐诗','tang','','[]','華堂多衆珍，白拂稱殊異。',156,'全唐诗/poet.tang.14000.json','["華堂多衆珍，白拂稱殊異。", "柄裁沈節香襲人，上結爲文下垂穗。", "霜縷霏微瑩且柔，虎鬚乍細龍髯稠。", "皎然素色不因染，淅爾涼風非爲秋。", "羣蠅青蒼恣遊息，廣庖萬品無顏色。", "金屏成點玉成瑕，晝眠宛轉空咨嗟。", "此時滿筵看一舉，荻花忽旋楊花舞。", "砉如寒隼驚暮禽，颯若繁埃得輕雨。", "主人說是故人留，每誡如新比白頭。", "若將揮玩閑臨水，願接波中一白鷗。"]'),
('504f86af-688b-4077-91e2-a7e62f7d8ebf','蕭常侍癭柏亭歌','盧綸','唐','唐诗','tang','','[]','柏之異者山中靈，何人斷絕爲君亭。',224,'全唐诗/poet.tang.14000.json','["柏之異者山中靈，何人斷絕爲君亭。", "雲翻浪卷不可識，鳥獸成形花倒植。", "莓苔舊點色尚青，霹靂殘痕節猶黑。", "金貂主人漢三老，構此窮年下朝早。", "心規目製不暫疲，匠者受之無一詞。", "清晨拂匣菱生鏡，落日憑闌星滿池。", "攢甍鬬拱無斤跡，根癭聯懸同素壁。", "數層亂瀉雲裏峯，萬片爭呈雪中石。", "重簾不動自飄香，似到瀛洲白玉堂。", "水精如意刁金色，雲母屏風透掩光。", "四堦綿綿被纖草，草上依微衆山道。", "松間汲井煙翠寒，洞裏圍碁天景好。", "愚儒敢欲賀成功，鸞鳳棲翔固不同。", "應念廢材今接地，一枝思寄戶庭中。"]'),
('1a62a396-b658-4be2-aa22-46516a64676d','慈恩寺石磬歌','盧綸','唐','唐诗','tang','','[]','靈山石磬生海西，海濤平處與山齊。',176,'全唐诗/poet.tang.14000.json','["靈山石磬生海西，海濤平處與山齊。", "長眉老僧同佛力，呪使鮫人往求得。", "珠穴沈成綠浪痕，天衣拂盡蒼苔色。", "星漢徘徊山有風，禪翁靜扣月明中。", "羣仙下雲龍出水，鸞鶴交飛半空裏。", "山精木魅不可聽，落葉秋砧一時起。", "花宮杳杳響泠泠，無數沙門昏夢醒。", "古廊燈下見行道，疎林池邊聞誦經。", "徒壯洪鐘祕高閣，萬金費盡工雕鑿。", "豈如全質挂青松，數葉殘雲一片峯。", "吾師寶之壽中國，願同劫石無終極。"]'),
('1c1df671-910d-4111-9d6b-b002d51f5dff','送張郎中還蜀歌','盧綸','唐','唐诗','tang','','[]','秦家御史漢家郎，親專兩印征殊方。',208,'全唐诗/poet.tang.14000.json','["秦家御史漢家郎，親專兩印征殊方。", "功成走馬朝天子，伏檻論邊若流水。", "曉離僊署趨紫微，夜接高儒讀青史。", "瀘南五將望君還，願以天書示百蠻。", "曲棧重江初過雨，前旌後騎不同山。", "迎車拜舞多耆老，舊卒新營遍青草。", "塞口雲生火候遲，煙中鶴唳軍行早。", "黃花川下水交橫，遠映孤霞蜀國晴。", "邛竹筍長椒瘴起，荔枝花發杜鵑鳴。", "迴首岷峨半天黑，傳觴接膝何由得。", "空令豪士仰威名，無復貧交恃顏色。", "垂楊不動雨紛紛，錦帳胡瓶爭送君。", "須臾醉起簫笳發，空見紅旌入白雲。"]'),
('1f79e6af-b9f2-4c6e-84d3-d345e546f87b','宴席賦得姚美人拍箏歌','盧綸','唐','唐诗','tang','','[]','出簾仍有鈿箏隨，見罷翻令恨識遲。',128,'全唐诗/poet.tang.14000.json','["出簾仍有鈿箏隨，見罷翻令恨識遲。", "微收皓腕纏紅袖，深遏朱弦低翠眉。", "忽然高張應繁節，玉指迴旋若飛雪。", "鳳簫韶管寂不喧，繡幕紗窗儼秋月。", "有時輕弄和郎歌，慢處聲遲情更多。", "已愁紅臉能佯醉，又恐朱門難再過。", "昭陽伴裏最聰明，出到人間纔長成。", "遙知禁曲難翻處，猶是君王說小名。"]'),
('7239ccda-ca26-4fdb-9542-8991cc908308','陳翃郎中北亭送侯釗侍御賦得帶冰流歌','盧綸','唐','唐诗','tang','','[]','溪中鳥鳴春景旦，一派寒冰忽開散。',88,'全唐诗/poet.tang.14000.json','["溪中鳥鳴春景旦，一派寒冰忽開散。", "璧方鏡員流不斷，白雲鱗鱗滿河漢。", "疊處淺，旋處深。", "撇捩寒魚上復沈，羣鵝鼓舞揚清音。", "主人有客簪白筆，玉壺貯水光如一。", "持此贈君君飲之，聖君識君冰玉姿。"]'),
('96ea27ae-1f85-4a5f-a9c8-9dc195803c00','棲巖寺隋文帝馬腦盞歌','盧綸','唐','唐诗','tang','','[]','天宮寶器隋朝物，鏁在金函比金骨。',128,'全唐诗/poet.tang.14000.json','["天宮寶器隋朝物，鏁在金函比金骨。", "開函捧之光乃發，阿修羅王掌中月。", "五雲如拳輕復濃，昔曾噀酒今藏龍。", "規形環影相透徹，亂雪繁花千萬重。", "可憐貞質無今名，可嘆隋陵一抔土。", "宮中豔女滿宮春，得親此寶能幾人。", "一留寒殿殿將壞，唯有幽光通隙塵。", "山中老僧眉似雪，忍死相傳保扃鐍。"]'),
('72b717c8-6254-4218-8b27-d4629e9e6e49','難綰刀子歌','盧綸','唐','唐诗','tang','','[]','黃金鞘裏青蘆葉，麗若翦成銛且翣。',96,'全唐诗/poet.tang.14000.json','["黃金鞘裏青蘆葉，麗若翦成銛且翣。", "輕冰薄玉狀不分，一尺寒光堪決雲。", "吹毛可試不可觸，似有蟲搜闕裂文。", "淬之幾墮前池水，焉知不是蛟龍子。", "割雞刺虎皆若空，願應君心逐君指。", "幷州難綰竟何人，每成此物如有神。"]'),
('1f707e02-465c-43ed-8090-97ddb552d49e','臘日觀咸寧王部曲娑勒擒豹歌','盧綸','唐','唐诗','tang','','[]','山頭曈曈日將出，山下獵圍照初日。',208,'全唐诗/poet.tang.14000.json','["山頭曈曈日將出，山下獵圍照初日。", "前林有獸未識名，將軍促騎無人聲。", "潛形踠伏草不動，雙鵰旋轉羣鴉鳴。", "陰方質子才三十，譯語受詞蕃語揖。", "捨鞍解甲疾如風，人忽虎蹲獸人立。", "歘然扼顙批其頤，爪牙委地涎淋漓。", "既蘇復吼拗仍怒，果叶英謀生致之。", "拖自深叢目如電，萬夫失容千馬戰。", "傳呼賀拜聲相連，殺氣騰凌陰滿川。", "始知縛虎如縛鼠，敗虜降羌生眼前。", "祝爾嘉詞爾無苦，獻爾將隨犀象舞。", "苑中流水禁中山，期爾攫搏開天顏。", "非熊之兆慶無極，願紀雄名傳百蠻。"]'),
('ef44f5be-493e-4ff9-b01a-5d98d783323f','賦得白鷗歌送李伯康歸使','盧綸','唐','唐诗','tang','','[]','積水深源，白鷗翻翻。',131,'全唐诗/poet.tang.14000.json','["積水深源，白鷗翻翻。", "倒影光素，于潭之間。", "銜魚魚落亂驚鳴，爭撲蓮藂蓮葉傾。", "爾不見波中鷗鳥閑無營，何必汲汲勞其生。", "柳花冥濛大堤口，悠揚相和乍無有。", "輕隨去浪杳不分，細舞清風亦何有。", "似君換得白鵝時，獨凭闌干雪滿池。", "今日還同看鷗鳥，如何羽翮復參差。", "復參差，海濤瀾漫何由期。"]'),
('0c05d199-be70-4e04-b2bc-f7161e7bd561','皇帝感詞 一','盧綸','唐','唐诗','tang','','[]','提劒風雷動，垂衣日月明。',48,'全唐诗/poet.tang.14000.json','["提劒風雷動，垂衣日月明。", "禁花呈瑞色，國老見星精。", "發棹魚先躍，窺巢鳥不驚。", "山呼一萬歲，直入九重城。"]'),
('02583ad3-2e64-4a5f-a99c-13177f8ef1da','皇帝感詞 二','盧綸','唐','唐诗','tang','','[]','天香五鳳彩，御馬六龍文。',48,'全唐诗/poet.tang.14000.json','["天香五鳳彩，御馬六龍文。", "雨露清馳道，風雷翊上軍。", "高旍花外轉，行漏樂前聞。", "時見金鞭舉，空中指瑞雲。"]'),
('28779907-c939-4880-95dd-473e44509ccc','皇帝感詞 三','盧綸','唐','唐诗','tang','','[]','妙算干戈止，神謀宇宙清。',48,'全唐诗/poet.tang.14000.json','["妙算干戈止，神謀宇宙清。", "兩堦文物盛，七德武功成。", "校獵長楊苑，屯軍細柳營。", "歸來獻明主，歌舞溢春城。"]'),
('a64c6d0c-5b69-4a33-a9e2-bbb487aba962','皇帝感詞 四','盧綸','唐','唐诗','tang','','[]','天樂下天中，雲輧儼在空。',48,'全唐诗/poet.tang.14000.json','["天樂下天中，雲輧儼在空。", "鉛黃豔河漢，笑語合笙鏞。", "已見長隨鳳，仍聞不避熊。", "君王親試舞，閶闔靜無風。"]'),
('4e4b5280-a671-4c3b-9274-9fcf7672b98a','天長久詞 一','盧綸','唐','唐诗','tang','','[]','玉砌紅花樹，香風不敢吹。',24,'全唐诗/poet.tang.14000.json','["玉砌紅花樹，香風不敢吹。", "春光解天意，偏發殿南枝。"]'),
('2603fcfa-7099-44ef-881b-c864e8ec60b5','天長久詞 二','盧綸','唐','唐诗','tang','','[]','虹橋千步廊，半在水中央。',24,'全唐诗/poet.tang.14000.json','["虹橋千步廊，半在水中央。", "天子方清暑，宮娃起夜妝。"]'),
('5f24c492-f3b5-4901-b453-def9efaf8a4c','天長久詞 三','盧綸','唐','唐诗','tang','','[]','辭輦復當熊，傾心奉六宮。',24,'全唐诗/poet.tang.14000.json','["辭輦復當熊，傾心奉六宮。", "君王若看貌，甘在衆妃中。"]'),
('9ffd8211-af0c-4f02-a289-527e3bcbdb55','天長久詞 四','盧綸','唐','唐诗','tang','','[]','雲日呈祥禮物殊，彤庭生獻五單于。',32,'全唐诗/poet.tang.14000.json','["雲日呈祥禮物殊，彤庭生獻五單于。", "塞垣萬里無飛鳥，可是邊城用郅都。"]'),
('7a46c844-7de3-401f-8809-f2cf8fcd9313','天長久詞 五','盧綸','唐','唐诗','tang','','[]','臺殿雲深秋色微，君王初賜六宮衣。',32,'全唐诗/poet.tang.14000.json','["臺殿雲深秋色微，君王初賜六宮衣。", "樓船泛罷歸猶早，行遣才人鬬射飛。"]'),
('ce491725-b96b-46a7-b83c-463d2094ef3f','和張僕射塞下曲 一','盧綸','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c06\u519b", "\u4e50\u5e9c", "\u9ad8\u4e2d\u53e4\u8bd7", "\u8fb9\u585e", "\u8d5e\u7f8e"]','鷲翎金僕姑，燕尾繡蝥弧。',24,'全唐诗/poet.tang.14000.json','["鷲翎金僕姑，燕尾繡蝥弧。", "獨立揚新令，千營共一呼。"]'),
('6d2e12c0-c1b8-4242-888c-9dba1a8f93ce','和張僕射塞下曲 二','盧綸','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5c06\u519b", "\u4e50\u5e9c", "\u8fb9\u585e", "\u8d5e\u7f8e", "\u72e9\u730e"]','林暗草驚風，將軍夜引弓。',24,'全唐诗/poet.tang.14000.json','["林暗草驚風，將軍夜引弓。", "平明尋白羽，沒在石稜中。"]'),
('ee2a3000-9127-43fa-8618-89a1937322cb','和張僕射塞下曲 三','盧綸','唐','唐诗','tang','','["\u6218\u4e89", "\u51ac\u5929", "\u5c06\u519b", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u8fb9\u585e"]','月黑鴈飛高，單于夜遁逃。',24,'全唐诗/poet.tang.14000.json','["月黑鴈飛高，單于夜遁逃。", "欲將輕騎逐，大雪滿弓刀。"]'),
('9a4d3eae-fe01-46c7-a28b-8b518614a508','和張僕射塞下曲 四','盧綸','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c", "\u5bb4\u996e", "\u8fb9\u585e", "\u8d5e\u9882", "\u5c06\u58eb"]','野幕敞瓊筵，羌戎賀勞旋。',24,'全唐诗/poet.tang.14000.json','["野幕敞瓊筵，羌戎賀勞旋。", "醉和金甲舞，雷鼓動山川。"]'),
('abb62728-c9c8-473d-b1f7-0fafd4bb9772','和張僕射塞下曲 五','盧綸','唐','唐诗','tang','','[]','調箭又呼鷹，俱聞出世能。',24,'全唐诗/poet.tang.14000.json','["調箭又呼鷹，俱聞出世能。", "奔狐將迸雉，掃盡古丘陵。"]'),
('14e3ec52-8f20-404d-9e4a-6c4580075a7a','和張僕射塞下曲 六','盧綸','唐','唐诗','tang','','[]','亭亭七葉貴，蕩蕩一隅清。',24,'全唐诗/poet.tang.14000.json','["亭亭七葉貴，蕩蕩一隅清。", "他日題麟閣，唯應獨不名。"]'),
('4271d12f-c540-4b19-be04-f2d71fb82f40','古豔詩 一','盧綸','唐','唐诗','tang','','[]','殘妝色淺髻鬟開，笑映朱簾覰客來。',32,'全唐诗/poet.tang.14000.json','["殘妝色淺髻鬟開，笑映朱簾覰客來。", "推醉誰知弄花鈿，潘郎不敢使人催。"]'),
('fbb7faec-a27f-49e5-bbed-967ea1c2bd96','古豔詩 二','盧綸','唐','唐诗','tang','','[]','自拈裙帶結同心，暖處偏知香氣深。',32,'全唐诗/poet.tang.14000.json','["自拈裙帶結同心，暖處偏知香氣深。", "愛捉狂夫問閑事，不知歌舞用黃金。"]'),
('e908c7aa-5607-4668-b79d-7ec2e1eb7cf9','孤松吟詶渾贊善','盧綸','唐','唐诗','tang','','[]','深山荒松枝，雪壓半離披。',96,'全唐诗/poet.tang.14000.json','["深山荒松枝，雪壓半離披。", "朱門青松樹，萬葉承清露。", "露重色逾鮮，吟風似遠泉。", "天寒香自發，日麗影常圓。", "陰郊一夜雪，榆柳皆枯折。", "迴首望君家，翠蓋滿瓊花。", "捧君青松曲，自顧同衰木。", "曲罷不相親，深山頭白人。"]'),
('d7488a1f-8791-4a51-8205-264270e8afc4','從軍行','盧綸','唐','唐诗','tang','','[]','二十在邊城，軍中得勇名。',72,'全唐诗/poet.tang.14000.json','["二十在邊城，軍中得勇名。", "卷旗收敗馬，占磧擁殘兵。", "覆陣烏鳶起，燒山草木明。", "塞閑思遠獵，師老厭分營。", "雪嶺無人跡，冰河足鴈聲。", "李陵甘此沒，惆悵漢公卿。"]'),
('db9b77d3-ce1e-4143-8d08-d5c4e741988a','和馬郎中畫鶴贊','盧綸','唐','唐诗','tang','','[]','高高華亭，有鶴在屏。',60,'全唐诗/poet.tang.14000.json','["高高華亭，有鶴在屏。", "削玉點漆，乘軒姓丁。", "暮雲冥冥，雙垂雪翎。", "晨光炯炯，一直朱頂。", "含音儼容，絕粒遺影。", "君以爲真，相期緱嶺。"]'),
('0a6a4a34-3991-49ca-becb-b58ca5a1ec17','送朝長史赴荆南舊幕','盧綸','唐','唐诗','tang','','[]','元瑜思舊幕，幾夜夢旌旃。',48,'全唐诗/poet.tang.14000.json','["元瑜思舊幕，幾夜夢旌旃。", "暑退蒹葭雨，秋生鼓角天。", "月明三峽路，浪裏九江船。", "囗囗囗囗囗，囗囗囗囗囗。"]'),
('98faa139-30a5-497b-af90-9d87ff063d29','送渭南崔少府歸徐郎中幕','盧綸','唐','唐诗','tang','','[]','葉下山邊路，行人見自悲。',48,'全唐诗/poet.tang.14000.json','["葉下山邊路，行人見自悲。", "夜寒逢雪處，日暖到村時。", "語少心常苦，愁深醉自遲。", "囗囗囗囗囗，羨有幕中期。"]'),
('514e7fd5-3b68-497c-a61e-4f1764d76286','寄鄭七綱','盧綸','唐','唐诗','tang','','[]','小來落托復迍邅，一辱君知二十年。',64,'全唐诗/poet.tang.14000.json','["小來落托復迍邅，一辱君知二十年。", "舍去形骸容傲慢，引隨兄弟共團圓。", "羈遊不定同雲聚，薄宦相縈若網牽。", "他日吳公如記問，願將黃綬比青氈。"]'),
('8148f2cb-e975-4ab1-9757-569da2556693','逢南中使因寄嶺外故人','盧綸','唐','唐诗','tang','','[]','見說南來處，蒼梧接桂林。',72,'全唐诗/poet.tang.14000.json','["見說南來處，蒼梧接桂林。", "過秋天更暖，邊海日長陰。", "巴路緣雲出，蠻鄉入洞深。", "信迴人自老，夢到月應沈。", "碧水通春色，青山寄遠心。", "炎方難久客，爲爾一沾襟。"]'),
('6c117e63-4e0e-4a74-b897-56dbdb49d296','代員將軍罷戰後歸舊里贈朔北故人','盧綸','唐','唐诗','tang','','[]','結髮事疆場，全生俱到鄉。',96,'全唐诗/poet.tang.14000.json','["結髮事疆場，全生俱到鄉。", "連雲防鐵嶺，同日破漁陽。", "牧馬胡天晚，移軍磧路長。", "枕戈眠古戍，吹角立繁霜。", "歸老勳仍在，酬恩虜未亡。", "獨行過邑里，多病對農桑。", "雄劒依塵橐，陰符寄藥囊。", "空餘麾下將，猶逐羽林郎。"]'),
('72e1b5ac-d83c-483c-a5eb-5b33172fc16f','江北憶崔汶','盧綸','唐','唐诗','tang','','[]','夜問江西客，還知在楚鄉。',72,'全唐诗/poet.tang.14000.json','["夜問江西客，還知在楚鄉。", "全身出部伍，盡室逐漁商。", "晴日遊瓜步，新年對漢陽。", "月昏驚浪白，瘴起覺雲黃。", "望嶺家何處，登山淚幾行。", "閩中傳有雪，應且住南康。"]'),
('4db414e3-350f-44a1-9898-10a15365b4ec','早春歸盩厔舊居却寄耿拾遺湋李校書端','盧綸','唐','唐诗','tang','','[]','野日初晴麥壠分，竹園相接鹿成羣。',64,'全唐诗/poet.tang.14000.json','["野日初晴麥壠分，竹園相接鹿成羣。", "幾家廢井生青草，一樹繁花傍古墳。", "引水忽驚冰滿澗，向田空見石和雲。", "可憐荒歲青山下，惟有松枝好寄君。"]'),
('d0d5a4c2-3ee0-4e9a-bd93-e60c3124915b','春日山中憶崔峒吉中孚','盧綸','唐','唐诗','tang','','[]','延步愛清晨，空山日照春。',48,'全唐诗/poet.tang.14000.json','["延步愛清晨，空山日照春。", "蜜房那有主，石室自無鄰。", "泉急魚依藻，花繁鳥近人。", "誰言失徒侶，唯與老相親。"]'),
('59aa6d87-8666-4bf0-bb92-e3e3e8d811f4','客舍喜崔補闕司空拾遺訪宿','盧綸','唐','唐诗','tang','','[]','步月訪諸鄰，蓬居宿近臣。',48,'全唐诗/poet.tang.14000.json','["步月訪諸鄰，蓬居宿近臣。", "烏裘先醉客，清鏡早朝人。", "壞壁煙垂網，香街火照塵。", "悲榮俱是分，吾亦樂吾貧。"]'),
('816a135b-333b-4c37-a2b7-96f5e40e34c9','苦雨聞包諫議欲見訪戲贈','盧綸','唐','唐诗','tang','','[]','草氣廚煙咽不開，繞牀連壁盡生苔。',32,'全唐诗/poet.tang.14000.json','["草氣廚煙咽不開，繞牀連壁盡生苔。", "常時多病因多雨，那敢煩君車馬來。"]'),
('a9b5f760-c5a9-4cf9-a751-00bf3b79857e','客舍苦雨即事寄錢起郎士元二員外','盧綸','唐','唐诗','tang','','[]','積雨暮淒淒，羈人狀鳥棲。',120,'全唐诗/poet.tang.14000.json','["積雨暮淒淒，羈人狀鳥棲。", "響空宮樹接，覆水野雲低。", "穴蟻多隨草，巢蜂半墜泥。", "遶池牆蘚合，擁溜瓦松齊。", "舊圃平如海，新溝曲似溪。", "壞闌留衆蝶，欹棟止羣雞。", "莠盛終無實，槎枯返有荑。", "綠萍藏廢井，黃葉隱危堤。", "閭里歡將絕，朝昏望亦迷。", "不知霄漢侶，何路可相攜。"]'),
('e4d4c69a-9803-4863-bb93-8b0be8420bbd','郊居對雨寄趙涓給事包佶郎中','盧綸','唐','唐诗','tang','','[]','暑雨青山裏，隨風到野居。',120,'全唐诗/poet.tang.14000.json','["暑雨青山裏，隨風到野居。", "亂漚浮曲砌，懸溜響前除。", "塵鏡愁多掩，蓬頭嬾更梳。", "夜窗淒枕席，陰壁潤圖書。", "蕭颯宜新竹，龍鐘拾野蔬。", "石泉空自咽，藥圃不堪鋤。", "濁水淙深轍，荒蘭擁敗渠。", "繁枝留宿鳥，碎浪出寒魚。", "桑屐時登望，荷衣自卷舒。", "應憐在泥滓，無路託高車。"]'),
('6a9162d7-ab6c-4cd2-9f64-b2883eef14c1','藍溪期蕭道士採藥不至','盧綸','唐','唐诗','tang','','[]','春風生百藥，幾處术苗香。',48,'全唐诗/poet.tang.14000.json','["春風生百藥，幾處术苗香。", "人遠花空落，溪深日復長。", "病多知藥性，老近憶仙方。", "清節何由見，三山桂自芳。"]'),
('c5b30b4f-a9d1-4c84-8cd9-fdf6a29b7e86','雪謗後書事上皇甫大夫','盧綸','唐','唐诗','tang','','[]','盛德總羣英，高標仰國楨。',192,'全唐诗/poet.tang.14000.json','["盛德總羣英，高標仰國楨。", "獨安巡狩日，曾掩趙張名。", "業就難辭寵，朝回更授兵。", "曉川分牧馬，夜雪覆連營。", "長策威殊俗，嘉謀翊聖明。", "畫圖規陣勢，夢筆紀山行。", "綬拂池中影，珂搖竹外聲。", "賜歡徵妓樂，陪醉問公卿。", "却憶經前事，翻疑得此生。", "分深存沒感，恩在子孫榮。", "覽鏡愁將老，捫心喜復驚。", "豈言沈族重，但覺殺身輕。", "有淚沾墳典，無家集弟兄。", "東西遭世難，流浪識交情。", "閱古宗文舉，推才慕正平。", "應憐守貧賤，又欲事躬耕。"]'),
('48e78cd3-673f-4831-8941-a3a83d59514b','春日憶司空文明','盧綸','唐','唐诗','tang','','[]','桃李風多日欲陰，百勞飛處落花深。',32,'全唐诗/poet.tang.14000.json','["桃李風多日欲陰，百勞飛處落花深。", "貧居靜久難逢信，知隔春山不可尋。"]'),
('0b80351f-2530-4619-a607-1bb4968bbf41','臥病寓居龍興觀枉馮十七著作書知罷攝洛陽赴緱氏因題十四韻寄馮生幷贈喬尊師','盧綸','唐','唐诗','tang','','[]','乞假依山宅，蹉跎屬歲周。',168,'全唐诗/poet.tang.14000.json','["乞假依山宅，蹉跎屬歲周。", "弱荑輕採拾，鈍質稱歸休。", "潘岳衰將至，劉楨病未瘳。", "步遲乘羽客，起晏滯書郵。", "幸以編方驗，終貽骨肉憂。", "灼龜爐氣冷，曝藥樹陰稠。", "語命心堪醉，傷離夢亦愁。", "葷羶居已絕，鸞鶴見無由。", "世累如塵積，年光劇水流。", "躡雲知有路，濟海豈無舟。", "倚玉翻成難，投磚敢望詶。", "卑棲君就祿，羸憊我逢秋。", "腐葉填荒轍，陰螢出古溝。", "依然在遐想，願子勵風猷。"]'),
('f1fc49eb-32c7-4240-85bf-8a8d80e95d87','秋夜寄馮著作','盧綸','唐','唐诗','tang','','[]','河漢淨無雲，鴻聲此夜聞。',48,'全唐诗/poet.tang.14000.json','["河漢淨無雲，鴻聲此夜聞。", "素心難比石，蒼鬢欲如君。", "露槿月中落，風螢池上分。", "何言千載友，同迹不同羣。"]'),
('b0a1fb5f-9390-4ccb-b4e2-9bde13822508','洛陽早春憶吉中孚校書司空曙主簿因寄清江上人','盧綸','唐','唐诗','tang','','[]','值迥逢高駐馬頻，雪晴閑看洛陽春。',64,'全唐诗/poet.tang.14000.json','["值迥逢高駐馬頻，雪晴閑看洛陽春。", "鶯聲報遠同芳信，柳色邀歡似故人。", "酒貌昔將花共豔，鬢毛今與草爭新。", "年來百事皆無緒，唯與湯師結淨因。"]'),
('7be8852b-d630-40f1-9584-590cb6839e9c','偶逢姚校書憑附書達河南郄推官因以戲贈','盧綸','唐','唐诗','tang','','[]','寄書常切到常遲，今日憑君君莫辭。',32,'全唐诗/poet.tang.14000.json','["寄書常切到常遲，今日憑君君莫辭。", "若問玉人殊易識，蓮花府裏最清羸。"]'),
('144549cb-a706-4f83-b11f-b49271de13be','夜中得循州趙司馬侍郎書因寄回使','盧綸','唐','唐诗','tang','','[]','瘴海寄雙魚，中宵達我居。',48,'全唐诗/poet.tang.14000.json','["瘴海寄雙魚，中宵達我居。", "兩行燈下淚，一紙嶺南書。", "地說炎蒸極，人稱老病餘。", "殷勤報賈傅，莫共酒杯疎。"]'),
('18734c96-6ba5-4e4d-9150-fa5d31b646d9','晚次新豐北野老家書事呈贈韓質明府','盧綸','唐','唐诗','tang','','[]','機鳴舂響日暾暾，雞犬相和漢古村。',64,'全唐诗/poet.tang.14000.json','["機鳴舂響日暾暾，雞犬相和漢古村。", "數派清泉黃菊盛，一林寒露紫棃繁。", "衰翁正席矜新社，稚子齊襟讀古論。", "共說年來但無事，不知何者是君恩。"]'),
('57d1c18b-c3b4-406e-affa-137bbd0fb0f8','書情上大尹十兄','盧綸','唐','唐诗','tang','','[]','紫陌絕纖埃，油幢千騎來。',120,'全唐诗/poet.tang.14000.json','["紫陌絕纖埃，油幢千騎來。", "剖辭紛若雨，犇吏殷成雷。", "聖澤初憂壅，羣心本在台。", "海鱗方潑刺，雲翼暫徘徊。", "芳室芝蘭茂，春蹊桃李開。", "江湖餘派少，鴻鴈遠聲哀。", "命厭蓍龜誘，年驚弟姪催。", "磨鉛慙砥礪，揮策愧駑駘。", "玉管能喧谷，金爐可變灰。", "應憐費思者，銜淚亦銜枚。"]'),
('fc9bd94a-0f69-47d0-a149-3b2e50cf6b65','春思貽李方陵','盧綸','唐','唐诗','tang','','[]','長安三月春，難別復難親。',48,'全唐诗/poet.tang.14000.json','["長安三月春，難別復難親。", "不識冶遊伴，多逢憔悴人。", "漸知歡澹薄，轉覺老殷勤。", "去矣盡如此，此辭悲未陳。"]'),
('67b58530-a019-48b3-b7a8-02193f503ea8','驛中望山戲贈渭南陸贄主簿','盧綸','唐','唐诗','tang','','[]','官微多懼事多同，拙性偏無主驛功。',32,'全唐诗/poet.tang.14000.json','["官微多懼事多同，拙性偏無主驛功。", "山在門前登不得，鬢毛衰盡路塵中。"]'),
('07b36cb0-42da-4635-a1f9-3d2b48c3abae','太白西峯偶宿車祝二尊師石室晨登前巘憑眺書懷即事寄呈鳳翔齊員外張侍御','盧綸','唐','唐诗','tang','','[]','弱齡誠昧鄙，遇勝惟求止。',180,'全唐诗/poet.tang.14000.json','["弱齡誠昧鄙，遇勝惟求止。", "如何羈滯中，得步青冥裏。", "青冥有桂藂，冰雪兩仙翁。", "毛節未歸海，丹梯閑倚空。", "逍遙擬上清，洞府不知名。", "醮罷雨雷至，客辭山忽明。", "山明鳥聲樂，日氣生嵓壑。", "嵓壑樹脩脩，白雲如水流。", "白雲消散盡，隴塞儼然秋。", "積阻關河固，綿聯烽戍稠。", "五營承廟略，四野失邊愁。", "吁嗟繫塵役，又負靈仙迹。", "芝朮自芳香，泥沙幾沈溺。", "書此欲沾衣，平生事每違。", "煙霄不可仰，鸞鶴自追隨。"]'),
('5fa4a1c0-0475-4a90-9027-3432d0f578b1','贈韓山人','盧綸','唐','唐诗','tang','','[]','見君何事不慙顏，白髮生來未到山。',32,'全唐诗/poet.tang.14000.json','["見君何事不慙顏，白髮生來未到山。", "更嘆無家又無藥，往來唯在酒徒間。"]'),
('1c3f9214-bf48-47ef-b538-8056b8eefe55','贈李果毅','盧綸','唐','唐诗','tang','','[]','向日磨金鏃，當風著錦衣。',24,'全唐诗/poet.tang.14000.json','["向日磨金鏃，當風著錦衣。", "上城邀賊語，走馬截鵰飛。"]'),
('7242db95-41ec-4932-af0b-3d5d9b362775','春日書情贈別司空曙','盧綸','唐','唐诗','tang','','[]','壯志隨年盡，謀身意未安。',48,'全唐诗/poet.tang.14000.json','["壯志隨年盡，謀身意未安。", "風塵交契闊，老大別離難。", "臘近晴多暖，春遲夜却寒。", "誰堪少兄弟，三十又無官。"]'),
('312f2a22-db98-4759-9025-9ef361ae82b7','冬曉呈鄰里','盧綸','唐','唐诗','tang','','[]','終夜寢衣冷，開門思曙光。',48,'全唐诗/poet.tang.14000.json','["終夜寢衣冷，開門思曙光。", "空堦一藂葉，華室四鄰霜。", "望闕覺天迥，憶山愁路荒。", "途中一留滯，雙鬢颯然蒼。"]'),
('04fda886-d1fd-4fc8-828d-86e1a0e1fe94','首冬寄河東昭德里書事貽鄭損倉曹','盧綸','唐','唐诗','tang','','[]','清冬和暖天，老鈍晝多眠。',48,'全唐诗/poet.tang.14000.json','["清冬和暖天，老鈍晝多眠。", "日愛閭巷靜，每聞官吏賢。", "寒葅供家食，腐葉宿廚煙。", "且復執杯酒，無煩輕議邊。"]'),
('2605b02f-f4c1-40c3-b7ae-aba62fbd5605','渾贊善東齋戲贈陳歸','盧綸','唐','唐诗','tang','','[]','長裾珠履颯輕塵，閒以琴書列上賓。',32,'全唐诗/poet.tang.14000.json','["長裾珠履颯輕塵，閒以琴書列上賓。", "公子無讐可邀請，侯嬴此坐是何人。"]'),
('8d11f731-4427-4c00-b5d4-57ae9a74d472','春日臥病示趙季黃','盧綸','唐','唐诗','tang','','[]','病中饒淚眼常昏，聞說花開亦閉門。',64,'全唐诗/poet.tang.14000.json','["病中饒淚眼常昏，聞說花開亦閉門。", "語少漸知琴思苦，臥多唯覺鳥聲喧。", "黃埃滿市圖書賤，黑霧連山虎豹尊。", "今日支離顧形影，向君凡在幾重恩。"]'),
('b02c0f61-8c1a-42b9-9a22-2e361bf9add4','秋幕中夜獨坐遲明因陪陳翃郎中晨謁上公因書即事兼呈同院諸公','盧綸','唐','唐诗','tang','','[]','風淒露泫然，明月在山巔。',144,'全唐诗/poet.tang.14000.json','["風淒露泫然，明月在山巔。", "獨倚古庭樹，仰看深夜天。", "葉翻螢不定，蟲思草無邊。", "南舍機杼發，東方雲景鮮。", "簪裘肅已整，車騎儼將前。", "百雉拱雙戟，萬夫尊一賢。", "琳瑯多謀蘊，律呂更相宣。", "曉桂香浥露，新鴻晴滿川。", "熙熙造化功，穆穆唐堯年。", "顧己草同賤，誓心金匪堅。", "蹇辭慙自寡，渴病老難痊。", "書此更何問，邊韶唯晝眠。"]'),
('d8efaf10-41da-4520-91e5-5835a4b4275a','寄贈庫部王郎中','盧綸','唐','唐诗','tang','','[]','諤諤漢名臣，從天令若春。',120,'全唐诗/poet.tang.14000.json','["諤諤漢名臣，從天令若春。", "敘辭皆詔旨，稱宦即星辰。", "草木承風偃，雲雷施澤均。", "威懲治粟尉，恩洽讓田人。", "泉貨方將散，京坻自此陳。", "五營俱益竈，千里不停輪。", "未遠金門籍，旋清玉塞塵。", "碩儒推慶重，良友頌公頻。", "鶴髮逢新鏡，龍門躍舊鱗。", "荷君偏有問，深感浩難申。"]'),
('c24d615c-41c3-459a-9a8c-cfa6e31c1843','寄贈暢當山居','盧綸','唐','唐诗','tang','','[]','古村荒石路，歲晏獨言歸。',48,'全唐诗/poet.tang.14000.json','["古村荒石路，歲晏獨言歸。", "山雪厚三尺，社楡麄十圍。", "虯龍寧守蟄，鸞鶴豈矜飛。", "君子固安分，毋聽勞者譏。"]'),
('67bc6252-c7b9-4c64-a664-c6ae86126ca7','偶宿山中憶暢當','盧綸','唐','唐诗','tang','','[]','深山夜雪晴，坐憶曉山明。',48,'全唐诗/poet.tang.14000.json','["深山夜雪晴，坐憶曉山明。", "讀易罷三卷，彈琴當五更。", "薜蘿枯有影，嵓壑凍無聲。", "此夕一相望，君應知我誠。"]'),
('80a012a1-ef54-45a4-91f1-c144d22f0d43','秋中野望寄舍弟綬兼令呈上西川尚書舅','盧綸','唐','唐诗','tang','','[]','憂來思遠望，高處殊非愜。',144,'全唐诗/poet.tang.14000.json','["憂來思遠望，高處殊非愜。", "夜露濕蒼山，秋陂滿黃葉。", "人隨鴈迢遰，棧與雲重疊。", "骨肉暫分離，形神遂疲薾。", "紅旌渭陽騎，幾日勞登涉。", "蜀道藹松筠，巴江盛舟檝。", "小生即何限，簡誨偏盈篋。", "舊恨尚填膺，新悲復縈睫。", "因求種瓜利，自喜歸耕捷。", "井臼賴依鄰，兒童亦勝汲。", "塵容不在照，雪鬢那堪鑷。", "唯有飡霞心，知夫與天接。"]'),
('3a6e3ba4-efc2-445e-93c9-e317ea169438','行藥前軒呈董山人','盧綸','唐','唐诗','tang','','[]','不覺老將至，瘦來方自驚。',48,'全唐诗/poet.tang.14000.json','["不覺老將至，瘦來方自驚。", "朝昏多病色，起坐有勞聲。", "腠暖苦肌痒，藏虛唯耳鳴。", "桑公富靈術，一爲保餘生。"]'),
('c976833f-2332-4e4d-9c60-77d9f498cded','翫春因寄馮衞二補闕戲呈李益','盧綸','唐','唐诗','tang','','[]','掖垣春色自天來，紅藥當堦次第開。',32,'全唐诗/poet.tang.14000.json','["掖垣春色自天來，紅藥當堦次第開。", "萱草藂藂爾何物，等閑穿破綠莓苔。"]'),
('5b58e563-cbb2-432f-a622-8585c5fdd32b','新移北廳因貽同院諸公兼呈暢博士','盧綸','唐','唐诗','tang','','[]','華軒邇台座，顧影忝時倫。',48,'全唐诗/poet.tang.14000.json','["華軒邇台座，顧影忝時倫。", "弱質偃彌曠，清風來亦頻。", "恩輝坐凌邁，景物恣芳新。", "終乃愧吾友，無容私此身。"]'),
('46366210-a3b7-4846-84b4-4883a5abbabb','與張擢對酌','盧綸','唐','唐诗','tang','','[]','張翁對盧叟，一榼山村酒。',108,'全唐诗/poet.tang.14000.json','["張翁對盧叟，一榼山村酒。", "傾酒請予歌，忽蒙張翁呵。", "呵予官非屈，曲有怨詞多。", "歌罷謝張翁，所思殊不同。", "予悲方爲老，君責一何空。", "曾看樂官錄，向是悲翁曲。", "張老聞此詞，汪汪泪盈目。", "盧叟醉言麄，一杯凡數呼。", "迴頭顧張老，敢欲戲爲儒。"]'),
('7db767b4-e9a3-4828-ad37-1ae91a54e510','喜從弟激初至','盧綸','唐','唐诗','tang','','[]','儒服策羸車，惠然過我廬。',48,'全唐诗/poet.tang.14000.json','["儒服策羸車，惠然過我廬。", "敘年慙已長，稱從意何疎。", "作吏清無比，爲文麗有餘。", "應嗤受恩者，頭白讀兵書。"]'),
('4bf4a9ee-ba26-46f5-89b3-320d9435bcb0','尋賈尊師','盧綸','唐','唐诗','tang','','[]','玉洞秦時客，焚香映綠蘿。',48,'全唐诗/poet.tang.14000.json','["玉洞秦時客，焚香映綠蘿。", "新傳左慈訣，曾與右軍鵝。", "井臼陰苔遍，方書古字多。", "成都今日雨，應與酒相和。"]'),
('1f1ed996-f5c2-4358-8bcf-4a2d8ad4ef32','秋中過獨孤郊居','盧綸','唐','唐诗','tang','','[]','開園過水到郊居，共引家童拾野蔬。',64,'全唐诗/poet.tang.14000.json','["開園過水到郊居，共引家童拾野蔬。", "高樹夕陽連古巷，菊花棃葉滿荒渠。", "秋山近處行過寺，夜雨寒時起讀書。", "帝里諸親別來久，豈知王粲愛樵漁。"]'),
('46784cdb-ab3d-4172-ab28-7c8bfb346b81','同耿拾遺春中題第四郎新修書院','盧綸','唐','唐诗','tang','','[]','得接西園會，多因野性同。',72,'全唐诗/poet.tang.14000.json','["得接西園會，多因野性同。", "引藤連樹影，移石間花叢。", "學就晨昏外，歡生禮樂中。", "春遊隨墨客，夜宿伴潛公。", "散帙燈驚燕，開簾月帶風。", "朝朝在門下，自與五侯通。"]'),
('7c1155dc-ba1e-4236-9fc5-af57baed0d94','春日題杜叟山下別業','盧綸','唐','唐诗','tang','','[]','白鳥羣飛山半晴，渚田相接有泉聲。',64,'全唐诗/poet.tang.14000.json','["白鳥羣飛山半晴，渚田相接有泉聲。", "園中曉露青叢合，橋上春風綠野明。", "雲影斷來峯影出，林花落盡草花生。", "今朝醉舞同君樂，始信幽人不愛榮。"]'),
('50c438e3-3f13-4895-9f90-c59ce043671d','過終南柳處士','盧綸','唐','唐诗','tang','','[]','五老正相尋，圍棋到煮金。',72,'全唐诗/poet.tang.14000.json','["五老正相尋，圍棋到煮金。", "石摧丹井閉，月過洞門深。", "猨鳥三時下，藤蘿十里陰。", "綠泉多草氣，青壁少花林。", "自愧非仙侶，何言見道心。", "悠哉宿山口，雷雨夜沈沈。"]'),
('36b0f871-802e-4fe6-bfac-0b56699e8e5c','宿澄上人院','盧綸','唐','唐诗','tang','','[]','竹窗聞遠水，月出似溪中。',48,'全唐诗/poet.tang.14000.json','["竹窗聞遠水，月出似溪中。", "香覆經年火，幡飄後夜風。", "性昏知道晚，學淺喜言同。", "一悟歸身處，何山路不通。"]'),
('6ab3a8e1-1960-4bb1-baf7-44b161d9c7fe','題李沆林園','盧綸','唐','唐诗','tang','','[]','古巷牛羊出，重門接柳陰。',48,'全唐诗/poet.tang.14000.json','["古巷牛羊出，重門接柳陰。", "閑看入竹路，自有向山心。", "種藥齊幽石，耕田到遠林。", "願同詞賦客，得興謝家深。"]'),
('424be0b8-1f41-4659-9e87-3e9bcbb7cab9','過司空曙村居','盧綸','唐','唐诗','tang','','[]','南北與山鄰，蓬菴庇一身。',48,'全唐诗/poet.tang.14000.json','["南北與山鄰，蓬菴庇一身。", "繁霜疑有雪，枯草似無人。", "遂性在耕稼，所交唯賤貧。", "何言張掾傲，每重德璋親。"]'),
('19030dce-1827-4555-8798-1204b4e5f797','題念濟寺暈上人院','盧綸','唐','唐诗','tang','','[]','泉響竹瀟瀟，潛公居處遙。',72,'全唐诗/poet.tang.14000.json','["泉響竹瀟瀟，潛公居處遙。", "虛空聞偈夜，清淨雨花朝。", "放鶴臨山閣，降龍步石橋。", "世塵徒委積，劫火定焚燒。", "苔壁雲難聚，風篁露易搖。", "浮生亦無著，況乃是芭蕉。"]'),
('3764f95f-0f5c-4dcd-96f9-2fab476f9018','題楊虢縣竹亭','盧綸','唐','唐诗','tang','','[]','夜宿密公室，話馀將晝興。',48,'全唐诗/poet.tang.14000.json','["夜宿密公室，話馀將晝興。", "遶堦三逕雪，當戶一池冰。", "家訓資風化，心源隱政能。", "明朝復何見，萊草古溝堘。"]'),
('f4515056-4457-4190-88e6-403c600a3cb4','過樓觀李尊師','盧綸','唐','唐诗','tang','','[]','城闕望煙霞，常悲仙路賒。',72,'全唐诗/poet.tang.14000.json','["城闕望煙霞，常悲仙路賒。", "寧知樵子徑，得到葛洪家。", "犬吠松間月，人行洞裏花。", "留詩千歲鶴，送客五雲車。", "訪世山空在，觀棋日未斜。", "不知塵俗士，誰解種胡麻。"]'),
('17d4774b-0b97-4392-8dbb-7449b91a4f61','雪謗後逢李叔度','盧綸','唐','唐诗','tang','','[]','相逢空握手，往事不堪思。',48,'全唐诗/poet.tang.14000.json','["相逢空握手，往事不堪思。", "見少情難盡，愁深語自遲。", "草生分路處，雨散出山時。", "強得寬離恨，唯當說後期。"]'),
('960d0408-85e2-4cda-a276-cf679352a25d','春日過李侍御','盧綸','唐','唐诗','tang','','[]','高柳滿春城，東園有鳥聲。',48,'全唐诗/poet.tang.14000.json','["高柳滿春城，東園有鳥聲。", "折花朝露滴，漱石野泉清。", "心許陶家醉，詩逢謝客呈。", "應憐末行吏，曾是魯諸生。"]'),
('2b05a92e-9007-448e-9ba1-69f8f5adfb84','出山逢耿湋','盧綸','唐','唐诗','tang','','[]','雲雪離披山萬里，別來曾住最高峰。',32,'全唐诗/poet.tang.14000.json','["雲雪離披山萬里，別來曾住最高峰。", "暫到人間歸不得，長安陌上又相逢。"]'),
('c4654a06-5fba-4ba0-9957-82ddd3ca77bb','題金吾郭將軍石伏茅堂','盧綸','唐','唐诗','tang','','[]','雲戟曙沈沈，軒墀清且深。',96,'全唐诗/poet.tang.14000.json','["雲戟曙沈沈，軒墀清且深。", "家傳成棟美，堯寵結茅心。", "玉佩多依石，油幢亦在林。", "爐香諸洞暖，殿影衆山陰。", "草奏風生筆，筵開雪滿琴。", "客從龍闕至，僧自虎溪尋。", "蕭灑延清賞，風流會素襟。", "終朝息塵步，一醉間華簪。"]'),
('c41b9e42-1d4c-4670-8488-88ee2f887cc4','題賈山人園林','盧綸','唐','唐诗','tang','','[]','竹影朦朧松影長，素琴清簟好風涼。',64,'全唐诗/poet.tang.14000.json','["竹影朦朧松影長，素琴清簟好風涼。", "連春詩會煙花滿，半夜酒醒蘭蕙香。", "五字每將稱玉友，一尊曾不顧金囊。", "長沙流謫君非遠，莫遣英名負洛陽。"]'),
('f895e219-77e0-401e-a8e2-66f105ac7f60','秋夜同暢當宿藏公院','盧綸','唐','唐诗','tang','','[]','禮足一垂淚，醫王知病由。',48,'全唐诗/poet.tang.14000.json','["禮足一垂淚，醫王知病由。", "風螢方喜夜，露槿已傷秋。", "顧以兒童愛，每從仁者求。", "將祈竟何得，滅跡在緇流。"]'),
('8146d939-bf5f-4866-9216-20e78ee0808b','重同暢當奘公院聞琴','盧綸','唐','唐诗','tang','','[]','悞以音聲祈遠公，請將徽軫付秋風。',32,'全唐诗/poet.tang.14000.json','["悞以音聲祈遠公，請將徽軫付秋風。", "漾漾硤流吹不盡，月華如在白波中。"]'),
('ea84eeff-95f0-4013-a68c-12fe776e74e9','同耿湋宿陸澧旅舍','盧綸','唐','唐诗','tang','','[]','當軒雲月開，清夜故人桮。',48,'全唐诗/poet.tang.14000.json','["當軒雲月開，清夜故人桮。", "擁褐覺霜下，抱琴聞鴈來。", "迎風君顧步，臨路我遲迴。", "雙鬢共如此，此懽非易陪。"]'),
('0bec6ec5-bac0-4fc3-9c26-c1ef63cd1d0a','題苗員外竹間亭','盧綸','唐','唐诗','tang','','[]','高甃絕行塵，開簾似有春。',48,'全唐诗/poet.tang.14000.json','["高甃絕行塵，開簾似有春。", "風傾竹上雪，山對酒邊人。", "步暖先逢日，書空遠見鄰。", "還同內齋暇，登賞及諸姻。"]'),
('ce177fb4-f5f7-4f41-b4c8-d9721f8b26cf','奉陪侍中登白樓','盧綸','唐','唐诗','tang','','[]','高樓倚玉梯，朱檻與雲齊。',48,'全唐诗/poet.tang.14000.json','["高樓倚玉梯，朱檻與雲齊。", "顧盼親霄漢，談諧息鼓鼙。", "洪河斜更直，野雨急仍低。", "今日陪尊俎，唯當醉似泥。"]'),
('390ef3f6-deb4-4314-80b7-6603639ce19a','九日奉陪侍郎登白樓','盧綸','唐','唐诗','tang','','[]','碧霄孤鶴發清音，上宰因添望闕心。',64,'全唐诗/poet.tang.14000.json','["碧霄孤鶴發清音，上宰因添望闕心。", "睥睨三層連步障，茱萸一朵映華簪。", "紅霞似綺河如帶，白露團珠菊散金。", "此日所從何所問，儼然冠劍擁成林。"]'),
('50d2c736-138a-4997-86dd-687edad966a0','春日喜雨奉和馬侍中宴白樓','盧綸','唐','唐诗','tang','','[]','鸛鶴相呼綠野寬，鼎臣閑倚玉欄干。',64,'全唐诗/poet.tang.14000.json','["鸛鶴相呼綠野寬，鼎臣閑倚玉欄干。", "洪河擁沫流仍急，蒼嶺和雲色更寒。", "豔豔風光呈瑞歲，泠泠歌頌振琱盤。", "今朝醉舞共鄉老，不覺傾欹獬豸冠。"]'),
('36534c86-ee76-44e0-88ab-a7c682f052d9','奉陪侍中遊石笋溪十二韻','盧綸','唐','唐诗','tang','','[]','朝日照靈山，山溪浩紛錯。',144,'全唐诗/poet.tang.14000.json','["朝日照靈山，山溪浩紛錯。", "圖書無舊記，鯀禹應新鑿。", "雙壁瀉天河，一峰吐蓮萼。", "潭心亂雪卷，嵓腹繁珠落。", "彩蛤攢錦囊，芳蘿嫋花索。", "猨羣曝陽嶺，龍穴腥陰壑。", "靜得漁者言，閑聞洞仙博。", "欹松倚朱幰，廣石屯油幕。", "國泰事留侯，山春縱康樂。", "間關殊狀鳥，爛熳無名藥。", "欲驗少君方，還吟大隱作。", "旌幢不可駐，古塞新沙漠。"]'),
('ef5a8a19-778e-4be1-8298-06a118996ada','九日奉陪侍中宴白樓','盧綸','唐','唐诗','tang','','[]','露白菊氛氳，西樓盛襲文。',48,'全唐诗/poet.tang.14000.json','["露白菊氛氳，西樓盛襲文。", "玉筵秋令節，金鉞漢元勳。", "說劍風生座，抽琴鶴遶雲。", "謏儒無以荅，願得備前軍。"]'),
('0e996578-5146-498d-be5f-60db1a241d10','九日奉陪侍中宴後亭','盧綸','唐','唐诗','tang','','[]','玉壺傾菊酒，一顧得淹留。',48,'全唐诗/poet.tang.14000.json','["玉壺傾菊酒，一顧得淹留。", "彩筆徵枚叟，花筵舞莫愁。", "管弦能駐景，松桂不停秋。", "爲謝蓬蒿輩，如何霜霰稠。"]'),
('7b1fdef6-f900-4fbc-8542-43c3cdd6eab7','九日奉陪令公登白樓同詠菊','盧綸','唐','唐诗','tang','','[]','瓊尊猶有菊，可以獻留侯。',48,'全唐诗/poet.tang.14000.json','["瓊尊猶有菊，可以獻留侯。", "願比三花秀，非同百卉秋。", "金英分蘂細，玉露結房稠。", "黃雀知恩在，銜飛亦上樓。"]'),
('8850438a-1e84-4df0-910c-08684407652a','奉陪渾侍中上巳日泛渭河','盧綸','唐','唐诗','tang','','[]','青舸錦帆開，浮天接上台。',48,'全唐诗/poet.tang.14000.json','["青舸錦帆開，浮天接上台。", "晚鶯和玉笛，春浪動金罍。", "舟檝方朝海，鯨鯢自曝腮。", "應憐似萍者，空逐榜人回。"]'),
('a5b524fd-d865-49c7-9c91-25375f7fd9d5','奉陪侍中春日過武安君廟','盧綸','唐','唐诗','tang','','[]','長裾間貔虎，遺廟盛攀登。',72,'全唐诗/poet.tang.14000.json','["長裾間貔虎，遺廟盛攀登。", "白羽三千騎，紅林一萬層。", "元臣達幽契，祝史告明徵。", "撫坐悲今古，瞻容感廢興。", "迴風卷藂栢，驟雨濕諸陵。", "倏忽煙花霽，當營看月生。"]'),
('2b60a93e-e8d1-42fd-a650-0fdcf911cd33','過玉[真]公主影殿','盧綸','唐','唐诗','tang','','[]','夕照臨窗起暗塵，青松繞殿不知春。',32,'全唐诗/poet.tang.14000.json','["夕照臨窗起暗塵，青松繞殿不知春。", "君看白髮誦經者，半是宮中歌舞人。"]'),
('d03f1cdd-2f8b-45b0-adfc-6cbbd85fcf44','題嘉祥殿南溪印禪師壁畫影堂','盧綸','唐','唐诗','tang','','[]','雙屐參差錫杖斜，衲衣交膝對天花。',32,'全唐诗/poet.tang.14000.json','["雙屐參差錫杖斜，衲衣交膝對天花。", "瞻容悟問修持劫，似指前溪無數沙。"]'),
('b2684095-6f5c-47ed-9950-a38e96c24156','題伯夷廟','盧綸','唐','唐诗','tang','','[]','中條山下黃礓石，壘作夷齊廟裏神。',32,'全唐诗/poet.tang.14000.json','["中條山下黃礓石，壘作夷齊廟裏神。", "落葉滿堦塵滿座，不知澆酒爲何人。"]'),
('d741dfa2-f686-4dd7-be3d-9a60077fd371','早春遊樊川野居却寄李端校書兼呈崔峒補闕司空曙主簿耿湋拾遺','盧綸','唐','唐诗','tang','','[]','白水遍溝堘，青山對杜陵。',168,'全唐诗/poet.tang.14000.json','["白水遍溝堘，青山對杜陵。", "晴明人望鶴，曠野鹿隨僧。", "古柳連巢折，荒堤帶草崩。", "陰橋全覆雪，瀑溜半垂冰。", "鬬鼠搖松影，遊龜落石層。", "韶光偏不待，衰敗巧相仍。", "桂樹曾爭折，龍門幾共登。", "琴師阮校尉，詩和柳吳興。", "舐筆求書扇，張屏看畫蠅。", "卜鄰空遂約，問卦獨無徵。", "投足經危路，收才遇直繩。", "守農窮自固，行樂病何能。", "掩帙蓬蒿晚，臨川景氣澄。", "颯然成一叟，誰更慕騫騰。"]'),
('90e5874b-7c28-4b1b-b4b9-b5aacb5c8bb1','同錢郎中晚春過慈恩寺','盧綸','唐','唐诗','tang','','[]','不見僧中舊，仍逢雨後春。',24,'全唐诗/poet.tang.14000.json','["不見僧中舊，仍逢雨後春。", "惜花將愛寺，俱是白頭人。"]'),
('86d77a6c-e09f-48a5-ab62-2dca745fa59d','曲江春望 一','盧綸','唐','唐诗','tang','','[]','菖蒲飜葉柳交枝，暗上蓮舟鳥不知。',32,'全唐诗/poet.tang.14000.json','["菖蒲飜葉柳交枝，暗上蓮舟鳥不知。", "更到無花最深處，玉樓金殿影參差。"]'),
('3cd29a52-42a8-470f-b8b5-a5108ebe4a8e','曲江春望 二','盧綸','唐','唐诗','tang','','[]','翠黛紅粧畫鷁中，共驚雲色帶微風。',32,'全唐诗/poet.tang.14000.json','["翠黛紅粧畫鷁中，共驚雲色帶微風。", "簫管曲長吹未盡，花南水北雨濛濛。"]'),
('a9b5cac2-ccf5-4765-92c2-ffef34039480','曲江春望 三','盧綸','唐','唐诗','tang','','[]','泉聲遍野入芳洲，擁沫吹花草上流。',32,'全唐诗/poet.tang.14000.json','["泉聲遍野入芳洲，擁沫吹花草上流。", "落日行人漸無路，巢烏乳燕滿高樓。"]'),
('3b3edd72-f585-43a7-b9bd-fc7d08ec5e8b','春日陪李庶子遵善寺東院曉望','盧綸','唐','唐诗','tang','','[]','映竹水田分，當山起鴈羣。',48,'全唐诗/poet.tang.14000.json','["映竹水田分，當山起鴈羣。", "陽峰高對寺，陰井下通雲。", "雪晝唯逢鶴，花時此見君。", "由來禪誦地，多有謝公文。"]'),
('967b8be5-0c22-4b50-a5b5-413ccfa8781d','華清宮 一','盧綸','唐','唐诗','tang','','[]','漢家天子好經過，白日青山宮殿多。',32,'全唐诗/poet.tang.14000.json','["漢家天子好經過，白日青山宮殿多。", "見說只今生草處，禁泉荒石已相和。"]'),
('8235c933-4770-43e6-a451-9a6053db5ffb','華清宮 二','盧綸','唐','唐诗','tang','','[]','水氣朦朧滿畫梁，一迴開殿滿山香。',32,'全唐诗/poet.tang.14000.json','["水氣朦朧滿畫梁，一迴開殿滿山香。", "宮娃幾許經歌舞，白首翻令憶建章。"]'),
('cac6b68c-0089-4377-9105-9792eff20509','題興善寺後池','盧綸','唐','唐诗','tang','','[]','隔窗棲白鶴，似與鏡湖鄰。',48,'全唐诗/poet.tang.14000.json','["隔窗棲白鶴，似與鏡湖鄰。", "月照何年樹，花逢幾遍人。", "岸莎青有路，苔徑綠無塵。", "永願容依止，僧中老此身。"]'),
('ab3a1e4c-6c93-48e3-84bd-7f16820ef72f','陪中書李紓舍人夜泛東池','盧綸','唐','唐诗','tang','','[]','看月復聽琴，移舟出樹陰。',48,'全唐诗/poet.tang.14000.json','["看月復聽琴，移舟出樹陰。", "夜村機杼急，秋水芰荷深。", "石靜龜潛上，萍開果暗沈。", "何言奉杯酒，得見五湖心。"]'),
('ed5457e6-fca7-481b-9ae1-bb2f00266eb5','宴趙氏昆季書院因與會文幷率爾投贈','盧綸','唐','唐诗','tang','','[]','詩禮挹餘波，相懽在琢磨。',72,'全唐诗/poet.tang.14000.json','["詩禮挹餘波，相懽在琢磨。", "琴尊方會集，珠玉忽駢羅。", "謝族風流盛，于門福慶多。", "花攢騏驥櫪，錦絢鳳凰窠。", "詠雪因饒妹，書經爲愛鵝。", "仍聞廣練被，更有遠儒過。"]'),
('4b9e95f6-5336-4b11-b52d-7be1ed7e9fd2','題天華觀','盧綸','唐','唐诗','tang','','[]','峰嶂徘徊霞景新，一潭寒水絕纖鱗。',64,'全唐诗/poet.tang.14000.json','["峰嶂徘徊霞景新，一潭寒水絕纖鱗。", "朱字靈書千萬軸，蒼髯道士兩三人。", "芝童解說壺中事，玉管能留天上春。", "眼見仙丹求不得，漢家簪紱在羸身。"]'),
('e254317e-0b37-455b-80dd-7e78ddd2f518','宿石甕寺','盧綸','唐','唐诗','tang','','[]','殿有寒燈草有螢，千林萬壑寂無聲。',64,'全唐诗/poet.tang.14000.json','["殿有寒燈草有螢，千林萬壑寂無聲。", "烟凝積水龍蛇蟄，露濕空山星漢明。", "昏靄霧中悲世界，曙霞光裏見王城。", "迴瞻相好因垂淚，苦海波濤何日平。"]'),
('48e181d6-bcec-4b0e-8128-8345f2a0793e','題悟真寺','盧綸','唐','唐诗','tang','','[]','萬峯交掩一峰開，曉色常從天上來。',32,'全唐诗/poet.tang.14000.json','["萬峯交掩一峰開，曉色常從天上來。", "似到西方諸佛國，蓮花影裏數樓臺。"]'),
('507c8bf7-2f91-4ee5-9849-118d47567db3','題雲際寺上方','盧綸','唐','唐诗','tang','','[]','松高蘿蔓輕，中有石牀平。',48,'全唐诗/poet.tang.14000.json','["松高蘿蔓輕，中有石牀平。", "下界水長急，上方燈自明。", "空門不易啓，初地本無程。", "迴步忽山盡，萬緣從此生。"]'),
('814b7a6c-d3a8-49c6-8166-82839b954c03','九日同司直九叔崔侍御登寶雞南樓','盧綸','唐','唐诗','tang','','[]','把菊歎將老，上樓悲未還。',48,'全唐诗/poet.tang.14000.json','["把菊歎將老，上樓悲未還。", "短長新白髮，重疊舊青山。", "霜氣清衿袖，琴聲引醉顏。", "竹林唯七友，何幸亦登攀。"]'),
('bcf88d70-488c-40a7-b7bf-febc7ab7c797','同王員外雨後登開元寺南樓因寄西巖警上人','盧綸','唐','唐诗','tang','','[]','過雨開樓看晚虹，白雲相逐水相通。',64,'全唐诗/poet.tang.14000.json','["過雨開樓看晚虹，白雲相逐水相通。", "寒蟬噪暮野無日，古樹傷秋天有風。", "數穗遠煙凝壠上，一枝繁果憶山中。", "何言暫別東林友，惆悵人間事不同。"]'),
('3e2c3ead-9db7-4794-a163-eb9068df4f7e','同趙進馬元陽春日登長春宮古城望河中因寄鄭損倉曹','盧綸','唐','唐诗','tang','','[]','城頭春靄曉濛濛，指望關橋滿袖風。',64,'全唐诗/poet.tang.14000.json','["城頭春靄曉濛濛，指望關橋滿袖風。", "雲騎閑嘶宮柳外，玉人愁立草花中。", "鐘分寺路山光綠，河繞軍州日氣紅。", "跡忝已成方戀賞，此時離恨與君同。"]'),
('3dd839a3-a410-4f62-adf6-f4e991320d05','同崔峒補闕慈恩寺避暑','盧綸','唐','唐诗','tang','','[]','寺涼高樹合，臥石綠陰中。',48,'全唐诗/poet.tang.14000.json','["寺涼高樹合，臥石綠陰中。", "伴鶴慙僊侶，依僧學老翁。", "魚沈荷葉露，鳥散竹林風。", "始悟塵居者，應將火宅同。"]'),
('22b294c9-0f25-43d0-80bd-33b10735013f','春日登樓有懷','盧綸','唐','唐诗','tang','','[]','花正濃時人正愁，逢花却欲替花羞。',32,'全唐诗/poet.tang.14000.json','["花正濃時人正愁，逢花却欲替花羞。", "年來笑伴皆歸去，今日晴明獨上樓。"]'),
('584ceb64-f0cf-4ac3-a353-922b9fe4df37','長安春望','盧綸','唐','唐诗','tang','','["\u601d\u4e61", "\u5199\u666f", "\u767b\u9ad8"]','東風吹雨過青山，却望千門草色閑。',64,'全唐诗/poet.tang.14000.json','["東風吹雨過青山，却望千門草色閑。", "家在夢中何日到，春生江上幾人還。", "川原繚繞浮雲外，宮闕參差落照間。", "誰念爲儒逢世難，獨將衰鬢客秦關。"]'),
('331717a0-f3ea-4ed4-a496-75786a54add0','冬日登城樓有懷因贈程騰','盧綸','唐','唐诗','tang','','[]','生涯何事多羈束，賴此登臨暢心目。',207,'全唐诗/poet.tang.14000.json','["生涯何事多羈束，賴此登臨暢心目。", "郭南郭北無數山，萬井逶迤流水間。", "彈琴對酒不知暮，岸幘題詩身自閑。", "風聲肅肅鴈飛絕，雲色茫茫欲成雪。", "遙思海客天外歸，坐想征人兩頭別。", "世情多以風塵隔，泣盡無因畫籌策。", "誰知白首窗下人，不接朱門坐中客。", "賤亦不足歎，貴亦不足陳。", "長卿未遇楊朱泣，蔡澤無媒原憲貧。", "如今萬乘方用武，國命天威借貔虎。", "窮達皆爲身外名，公侯可廢刀頭取。", "君不見漢家邊將在邊庭，白羽三千出井陘。", "當風看獵擁珠翠，豈在終年窮一經。"]'),
('074be5cc-8238-4abc-8d7a-8e99aaf09e8a','過仙遊寺','盧綸','唐','唐诗','tang','','[]','上方下方雪中路，白雲流水如閑步。',32,'全唐诗/poet.tang.14000.json','["上方下方雪中路，白雲流水如閑步。", "數峰行盡猶未歸，寂寞經聲竹陰暮。"]'),
('0c856ebd-7d5a-4bda-83e4-4d4489ee133f','同路郎中韓侍御春日題野寺','盧綸','唐','唐诗','tang','','[]','寺前山遠古陂寬，寺裏人稀春草寒。',32,'全唐诗/poet.tang.14000.json','["寺前山遠古陂寬，寺裏人稀春草寒。", "何事最堪悲色相，折花將與老僧看。"]'),
('c0e7eab5-45c4-40db-9181-579644ec9319','奉和李益遊栖巖寺','盧綸','唐','唐诗','tang','','[]','林香雨氣新，山寺綠無塵。',72,'全唐诗/poet.tang.14000.json','["林香雨氣新，山寺綠無塵。", "遂結雲外賞，共遊天上春。", "鶴鳴金闕麗，僧語竹房鄰。", "待月水流急，惜花風起頻。", "何方非壞境，此地有歸人。", "迴首空門路，皤然一幻身。"]'),
('9a1104b2-9609-4824-ba0a-3680acb44f5c','秋夜同暢當宿潭上西亭','盧綸','唐','唐诗','tang','','[]','圓月出山頭，七賢林下遊。',48,'全唐诗/poet.tang.14000.json','["圓月出山頭，七賢林下遊。", "梢梢寒葉墜，灩灩月波流。", "鳧鵠共思曉，菰蒲相與秋。", "明當此中別，一爲望汀洲。"]'),
('aae5d437-93ed-47e5-9f38-ea37b07ca0d0','山中一絕','盧綸','唐','唐诗','tang','','[]','飢食松花渴飲泉，偶從山後到山前。',32,'全唐诗/poet.tang.14000.json','["飢食松花渴飲泉，偶從山後到山前。", "陽坡軟草厚如織，因與鹿麛相伴眠。"]'),
('f71fa681-8a48-4641-ba97-d18e5fec888a','與暢當夜泛秋潭','盧綸','唐','唐诗','tang','','[]','螢火颺蓮叢，水涼多夜風。',24,'全唐诗/poet.tang.14000.json','["螢火颺蓮叢，水涼多夜風。", "離人將落葉，俱在一船中。"]'),
('f6e69558-07fd-4006-9af0-7d1acd2881ad','秋夜宴集陳翃郎中圃亭美校書郎張正元歸鄉','盧綸','唐','唐诗','tang','','[]','泉清蘭菊稠，紅果落城溝。',48,'全唐诗/poet.tang.14000.json','["泉清蘭菊稠，紅果落城溝。", "保慶臺榭古，感時琴瑟秋。", "碩儒歡頗至，名士禮能周。", "爲謝邑中少，無驚池上鷗。"]'),
('2286a23a-2f64-4c07-8b16-b0197951c174','春遊東潭','盧綸','唐','唐诗','tang','','[]','移舟試望家，漾漾似天涯。',24,'全唐诗/poet.tang.14000.json','["移舟試望家，漾漾似天涯。", "日暮滿潭雪，白鷗和柳花。"]'),
('502e2867-98a2-4e87-8a7b-a4b253c9ac36','同薛存誠登栖巖寺','盧綸','唐','唐诗','tang','','[]','衰蹇步難前，上山如上天。',48,'全唐诗/poet.tang.14000.json','["衰蹇步難前，上山如上天。", "塵泥來自晚，猨鶴到何先。", "萬壑應孤磬，百花通一泉。", "蒼蒼此明月，下界正沈眠。"]'),
('c077aa12-36d4-4881-92ed-c3836023cab8','河中府崇福寺看花','盧綸','唐','唐诗','tang','','[]','聞道山花如火紅，平明登寺已經風。',32,'全唐诗/poet.tang.14000.json','["聞道山花如火紅，平明登寺已經風。", "老僧無見亦無說，應與看人心不同。"]'),
('5d9bfae7-0969-4230-959d-e668e926a474','冬日宴郭監林亭','盧綸','唐','唐诗','tang','','[]','玉勒聚如雲，森森鸞鶴羣。',48,'全唐诗/poet.tang.14000.json','["玉勒聚如雲，森森鸞鶴羣。", "據梧花罽接，沃盥石泉分。", "華味慙初識，新聲喜盡聞。", "此山招老賤，敢不謝夫君。"]'),
('7d406ba9-ada0-4d04-a7c4-349cc4f486fb','奉和李舍人昆季詠玫瑰花寄贈徐侍郎','盧綸','唐','唐诗','tang','','[]','獨鶴寄煙霜，雙鸞思晚芳。',96,'全唐诗/poet.tang.14000.json','["獨鶴寄煙霜，雙鸞思晚芳。", "舊陰依謝宅，新豔出蕭牆。", "蝶散搖輕露，鶯銜入夕陽。", "雨朝勝濯錦，風夜劇焚香。", "斷日千層豔，孤霞一片光。", "密來驚葉少，動處覺枝長。", "布影期高賞，留春爲遠方。", "嘗聞贈瓊玖，叨和愧升堂。"]'),
('1cff4821-416d-4899-bf9d-fd1020452c94','同耿湋司空曙二拾遺題韋員外東齋花樹','盧綸','唐','唐诗','tang','','[]','綠砌紅花樹，狂風獨未吹。',48,'全唐诗/poet.tang.14000.json','["綠砌紅花樹，狂風獨未吹。", "光中疑有燄，密處似無枝。", "鳥動香輕發，人愁影屢移。", "今朝數片落，爲報漢郎知。"]'),
('311a0b0d-e31a-46d4-8524-10a809e299b6','觀袁修侍郎漲新池','盧綸','唐','唐诗','tang','','[]','引水香山近，穿雲復遶林。',48,'全唐诗/poet.tang.14000.json','["引水香山近，穿雲復遶林。", "纔聞籬外響，已覺石邊深。", "滿處侵苔色，澄來見柳陰。", "微風月明夜，知有五湖心。"]'),
('ea2ee88a-1def-4bda-833b-762f75314d5d','和徐法曹贈崔洛陽斑竹杖以詩見荅','盧綸','唐','唐诗','tang','','[]','玉幹一尋餘，苔花錦不如。',48,'全唐诗/poet.tang.14000.json','["玉幹一尋餘，苔花錦不如。", "勁堪和醉倚，輕好向空書。", "采拂稽山曲，因依釋氏居。", "方辰將獨步，豈與此君疎。"]'),
('c59271a8-1f19-433e-b66f-4af6de7f383d','早秋望華清宮中樹因以成詠','盧綸','唐','唐诗','tang','','[]','可憐雲木藂，滿禁碧濛濛。',120,'全唐诗/poet.tang.14000.json','["可憐雲木藂，滿禁碧濛濛。", "色潤靈泉近，陰清輦路通。", "玉壇標八桂，金井識雙桐。", "交映凝寒露，相和起夜風。", "數枝盤石上，幾葉落雲中。", "燕拂宜秋霽，蟬鳴覺晝空。", "翠屏更隱見，珠綴共玲瓏。", "雷雨生成早，樵蘇禁令雄。", "野藤高助綠，仙果迥呈紅。", "惆悵繚垣暮，茲山聞暗蛩。"]'),
('55933b19-ff43-40e9-9579-56ad52c53ec3','小魚詠寄涇州楊侍郎','盧綸','唐','唐诗','tang','','[]','蓮花影裏暫相離，纔出浮萍值罟師。',32,'全唐诗/poet.tang.14000.json','["蓮花影裏暫相離，纔出浮萍值罟師。", "上得龍門還失浪，九江何處是歸期。"]'),
('859029cc-5ab7-4855-9de7-68c231882523','賊中與嚴越卿曲江看花','盧綸','唐','唐诗','tang','','[]','紅枝欲折紫枝殷，隔水連宮不用攀。',32,'全唐诗/poet.tang.14000.json','["紅枝欲折紫枝殷，隔水連宮不用攀。", "會待長風吹落盡，始能開眼向青山。"]'),
('8faefeef-eb7b-4616-8d11-874633dee69d','同暢當詠蒲團','盧綸','唐','唐诗','tang','','[]','團團錦花結，乃是前溪蒲。',36,'全唐诗/poet.tang.14000.json','["團團錦花結，乃是前溪蒲。", "擁坐稱儒褐，倚眠宜病夫。", "唯當學禪寂，終老與之俱。"]'),
('35b59fb5-75cd-4bf0-ac6e-86b0dd9cb22a','焦籬店醉題','盧綸','唐','唐诗','tang','','[]','洛下渠頭百卉新，滿筵歌笑獨傷春。',32,'全唐诗/poet.tang.14000.json','["洛下渠頭百卉新，滿筵歌笑獨傷春。", "何須更弄邵翁伯，即我此身如此人。"]'),
('42cc8c7e-4053-4201-a328-74623b23f242','陳翃中丞東齋賦白玉簪','盧綸','唐','唐诗','tang','','[]','美矣新成太華峰，翠蓮枝折葉重重。',64,'全唐诗/poet.tang.14000.json','["美矣新成太華峰，翠蓮枝折葉重重。", "松陰滿澗閑飛鶴，潭影通雲暗上龍。", "漠漠水香風頗馥，涓涓乳溜味何濃。", "因聲遠報浮丘子，不奏登封時不容。"]'),
('767fa394-5a2e-4ccc-8be4-d4a4b71d6fa5','新茶詠寄上西川相公二十三舅大夫二十舅','盧綸','唐','唐诗','tang','','[]','三獻蓬萊始一嘗，日調金鼎閱芳香。',32,'全唐诗/poet.tang.14000.json','["三獻蓬萊始一嘗，日調金鼎閱芳香。", "貯之玉合才半餅，寄與阿連題數行。"]'),
('e54bd063-69d0-46b6-9605-a83abb8faa2b','泊揚子江岸','盧綸','唐','唐诗','tang','','[]','山映南徐暮，千帆入古津。',48,'全唐诗/poet.tang.14000.json','["山映南徐暮，千帆入古津。", "魚驚出浦火，月照渡江人。", "清鏡催雙鬢，滄波寄一身。", "空憐莎草色，長接故園春。"]'),
('fae577a5-da28-4672-83ff-94c97ae2a4a4','晚次鄂州','盧綸','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u6218\u4e89", "\u5199\u666f", "\u6292\u60c5", "\u4e03\u8a00\u5f8b\u8bd7", "\u601d\u4e61"]','雲開遠見漢陽城，猶是孤帆一日程。',64,'全唐诗/poet.tang.14000.json','["雲開遠見漢陽城，猶是孤帆一日程。", "估客晝眠知浪靜，舟人夜語覺潮生。", "三湘衰鬢逢秋色，萬里歸心對月明。", "舊業已隨征戰盡，更堪江上鼓鼙聲。"]'),
('a854ae25-d815-46d8-b949-5b76c5eb4594','夜投豐德寺謁海上人','盧綸','唐','唐诗','tang','','[]','半夜中峰有磬聲，偶逢樵者問山名。',64,'全唐诗/poet.tang.14000.json','["半夜中峰有磬聲，偶逢樵者問山名。", "上方月曉聞僧語，下路林疎見客行。", "野鶴巢邊松最老，毒龍潛處水偏清。", "願得遠公知姓字，焚香洗鉢過浮生。"]'),
('d6482fd9-283a-4d2c-a384-c56a0c5c5046','江行次武昌縣','盧綸','唐','唐诗','tang','','[]','家寄五湖間，扁舟往復還。',48,'全唐诗/poet.tang.14000.json','["家寄五湖間，扁舟往復還。", "年年生白髮，處處上青山。", "去國空知遠，安身竟不閑。", "更悲江畔柳，長是北人攀。"]'),
('79046181-9ccc-498e-a1e0-555113a039f4','夜泊金陵','盧綸','唐','唐诗','tang','','[]','圓月出高城，蒼蒼照水營。',48,'全唐诗/poet.tang.14000.json','["圓月出高城，蒼蒼照水營。", "江中正吹笛，樓上又無更。", "洛下仍傳箭，關西欲進兵。", "誰知五湖外，諸將但爭名。"]'),
('d1e556ef-941e-4f51-be7d-7c635b0cd372','渡浙江','盧綸','唐','唐诗','tang','','[]','前船後船未相及，五兩頭平北風急。',32,'全唐诗/poet.tang.14000.json','["前船後船未相及，五兩頭平北風急。", "飛沙卷地日色昏，一半征帆浪花濕。"]'),
('f4301f96-e872-4eae-aa51-0d12328059d1','李端公','盧綸','唐','唐诗','tang','','["\u51ac\u5929", "\u53cb\u60c5", "\u9001\u522b", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u5f8b\u8bd7", "\u4f24\u6000"]','故關衰草遍，離別自堪悲。',48,'全唐诗/poet.tang.14000.json','["故關衰草遍，離別自堪悲。", "路出寒雲外，人歸暮雪時。", "少孤爲客早，多難識君遲。", "掩淚空相向，風塵何處期。"]'),
('574ee2e4-2ebf-4d3a-9ee0-336beac25b92','秋晚山中別業','盧綸','唐','唐诗','tang','','[]','樹老野泉清，幽人好獨行。',48,'全唐诗/poet.tang.14000.json','["樹老野泉清，幽人好獨行。", "去閑知路靜，歸晚喜山明。", "蘭芰通荒井，牛羊出古城。", "茂陵秋最冷，誰念一書生。"]'),
('dc62ad3d-4687-456b-beda-287839883f6a','關口逢徐邁','盧綸','唐','唐诗','tang','','[]','廢寺連荒壘，那知見子真。',48,'全唐诗/poet.tang.14000.json','["廢寺連荒壘，那知見子真。", "關城夜有雪，冰渡曉無人。", "酒裏唯多病，山中願作鄰。", "常聞兄弟樂，誰肯信家貧。"]'),
('c57cf8e6-e45e-4d01-a101-87fbeef75b15','山中詠古木','盧綸','唐','唐诗','tang','','[]','高木已蕭索，夜雨復秋風。',48,'全唐诗/poet.tang.14000.json','["高木已蕭索，夜雨復秋風。", "墜葉鳴藂竹，斜根擁斷蓬。", "半侵山色裏，長在水聲中。", "此地何人到，雲門去亦通。"]'),
('0e2cc19c-6e43-47ad-834b-44694dc75180','詶李端公野寺病居見寄','盧綸','唐','唐诗','tang','','[]','野寺鐘昏山正陰，亂藤高竹水聲深。',64,'全唐诗/poet.tang.14000.json','["野寺鐘昏山正陰，亂藤高竹水聲深。", "田夫就餉還依草，野雉驚飛不過林。", "齋沫暫思同靜室，清羸已覺助禪心。", "寂寞日長誰問疾，料君惟取古方尋。"]'),
('0d3e1549-4887-4b3b-b8d3-4725128a32f0','送少微上人遊蜀','盧綸','唐','唐诗','tang','','[]','瓶鉢繞禪衣，連宵宿翠微。',48,'全唐诗/poet.tang.14000.json','["瓶鉢繞禪衣，連宵宿翠微。", "樹開巴水遠，山曉蜀星稀。", "識遍中朝貴，多諳外學非。", "何當一傳付，道侶願知歸。"]'),
('6d7717b2-cc2b-46c0-a6b6-fbeaee2d9e7d','送寧國夏侯丞','盧綸','唐','唐诗','tang','','[]','楚國青蕪上，秋雲似白波。',48,'全唐诗/poet.tang.14000.json','["楚國青蕪上，秋雲似白波。", "五湖長路少，九派亂山多。", "謝守通詩宴，陶公許醉過。", "憮然餞離阻，年鬢兩蹉跎。"]'),
('4be3da1b-06f3-4630-83a5-9bdd9940630b','送袁偁','盧綸','唐','唐诗','tang','','[]','諫獵名空久，多因病與貧。',48,'全唐诗/poet.tang.14000.json','["諫獵名空久，多因病與貧。", "買書行幾市，帶雨別何人。", "客路山連水，軍州日映塵。", "淒涼一分手，俱恨老相親。"]'),
('7d9e9be5-962b-42d5-9190-c156201650f8','贈別李紛','盧綸','唐','唐诗','tang','','[]','頭白乘驢懸布囊，一迴言別泪千行。',32,'全唐诗/poet.tang.15000.json','["頭白乘驢懸布囊，一迴言別泪千行。", "兒孫滿眼無歸處，唯到尊前似故鄉。"]'),
('c438d6af-aceb-4d5a-a283-02262f35a793','罪所送苗員外上都','盧綸','唐','唐诗','tang','','[]','謀身當議罪，寧遣友朋聞。',48,'全唐诗/poet.tang.15000.json','["謀身當議罪，寧遣友朋聞。", "禍近防難及，愁長事未分。", "寂寥驚遠語，幽閉望歸雲。", "親戚如相見，唯應泣向君。"]'),
('dd4b60d2-ed07-456f-bb82-2db027e705ed','送李校書赴東川幕','盧綸','唐','唐诗','tang','','[]','泥坂望青城，浮雲與棧平。',48,'全唐诗/poet.tang.15000.json','["泥坂望青城，浮雲與棧平。", "字形知國號，眉勢識山名。", "編簡塵封閣，戈鋋雪照營。", "男兒須聘用，莫信筆堪耕。"]'),
('82a9fe1c-3f19-4351-9b6a-13d690a366ed','至德中贈內兄劉贊','盧綸','唐','唐诗','tang','','[]','時難訪親戚，相見喜還悲。',48,'全唐诗/poet.tang.15000.json','["時難訪親戚，相見喜還悲。", "好學年空在，從戎事已遲。", "聽琴泉落處，步履雪深時。", "惆悵多邊信，青山共有期。"]'),
('34368466-3d81-438a-a69a-039f47eff812','春日灞亭同苗員外寄皇甫侍御','盧綸','唐','唐诗','tang','','[]','坐見春雲暮，無因報所思。',48,'全唐诗/poet.tang.15000.json','["坐見春雲暮，無因報所思。", "川平人去遠，日暖鴈飛遲。", "對酒山長在，看花鬢自衰。", "誰堪登灞岸，還作舊鄉悲。"]'),
('c44d1d7b-e055-4100-8dfd-3b4760edd8e4','送顏推官遊銀夏謁韓大夫','盧綸','唐','唐诗','tang','','[]','叢篁叫寒笛，滿眼塞山青。',48,'全唐诗/poet.tang.15000.json','["叢篁叫寒笛，滿眼塞山青。", "才子尊前畫，將軍石上銘。", "獵聲雲外響，戰血雨中腥。", "苦樂從來事，因君一涕零。"]'),
('dacfff7a-fffe-423e-9c52-14f2efccae80','咸陽送房濟侍御歸太原幕','盧綸','唐','唐诗','tang','','[]','舊居無舊鄰，似見故鄉春。',48,'全唐诗/poet.tang.15000.json','["舊居無舊鄰，似見故鄉春。", "復對別離酒，欲成衰老人。", "客衣頻染淚，軍旅亦多塵。", "握手重相勉，平生心所因。"]'),
('dda04c39-322e-4e47-9a9c-9b5854795efb','寶泉寺送李益端公歸邠寧幕','盧綸','唐','唐诗','tang','','[]','參差巖障東，雲日晃龍宮。',72,'全唐诗/poet.tang.15000.json','["參差巖障東，雲日晃龍宮。", "石淨非因雨，松涼不爲風。", "戀泉將鶴並，偷果與猨同。", "眼界塵雖染，心源蔽已通。", "蓮花國何限，貝葉字無窮。", "早晚登麟閣，慈門欲付公。"]'),
('357b89f6-fc6f-4aa2-b158-6da38f820c6b','送何召下第後歸蜀','盧綸','唐','唐诗','tang','','[]','襃斜行客過，棧道響危空。',48,'全唐诗/poet.tang.15000.json','["襃斜行客過，棧道響危空。", "路濕雲初上，山明日正中。", "水程通海貨，地利雜吳風。", "一別金門遠，何人復薦雄。"]'),
('37d82fab-d24d-41ee-9547-b828eec2e945','宿定陵寺','盧綸','唐','唐诗','tang','','[]','古塔荒臺出禁牆，磬聲初盡漏聲長。',64,'全唐诗/poet.tang.15000.json','["古塔荒臺出禁牆，磬聲初盡漏聲長。", "雲生紫殿幡花濕，月照青山松栢香。", "禪室夜聞風過竹，奠筵朝啓露霑裳。", "誰悟威靈同寂滅，更堪砧杵發昭陽。"]'),
('ddf8afda-8f2c-4bbb-8180-7055321d4a6f','送彭開府往雲中覲使君兄','盧綸','唐','唐诗','tang','','[]','一門三代貴，非是主恩偏。',72,'全唐诗/poet.tang.15000.json','["一門三代貴，非是主恩偏。", "破虜山銘在，承家劍藝全。", "奪旗貂帳側，射虎雪林前。", "鴈塞逢兄弟，雲州發管弦。", "凍河光帶日，枯草淨無煙。", "儒者曾修武，因貽上將篇。"]'),
('ae03dbb4-7244-43ef-97a9-920813e9c679','送李緗','盧綸','唐','唐诗','tang','','[]','舊國仍連五將營，儒衣何處謁公卿。',64,'全唐诗/poet.tang.15000.json','["舊國仍連五將營，儒衣何處謁公卿。", "波翻遠水蒹葭動，路入寒村機杼鳴。", "嵇康書論多歸興，謝氏家風有學名。", "爲問西來雨中客，空山幾處是前程。"]'),
('dba31336-8f07-4f4c-809f-06894ceb9ce5','送內弟韋宗仁歸信州覲省','盧綸','唐','唐诗','tang','','[]','常嗟外族兄弟稀，轉覺心孤是送歸。',64,'全唐诗/poet.tang.15000.json','["常嗟外族兄弟稀，轉覺心孤是送歸。", "醉掩壺觴人有淚，夢驚波浪日無輝。", "烹魚綠岸煙浮草，摘橘青溪露濕衣。", "聞說江樓長卷幔，幾回風起望胡威。"]'),
('87b6f483-98c5-4ec5-a715-87e36110e96b','長安疾後首秋夜即事','盧綸','唐','唐诗','tang','','[]','九重深鎖禁城秋，月過南宮漸映樓。',64,'全唐诗/poet.tang.15000.json','["九重深鎖禁城秋，月過南宮漸映樓。", "紫陌夜深槐露滴，碧空雲盡火星流。", "清風刻漏傳三殿，甲第歌鐘樂五侯。", "楚客病來鄉思苦，寂寥燈下不勝愁。"]'),
('6d8d65c5-372c-4d4d-afae-5ada1d1ff2c7','送崔琦赴宣州幕','盧綸','唐','唐诗','tang','','[]','五馬臨流待幕賓，羨君談笑出風塵。',64,'全唐诗/poet.tang.15000.json','["五馬臨流待幕賓，羨君談笑出風塵。", "身閑就養寧辭遠，世難移家莫厭貧。", "天際曉山三峽路，津頭臘市九江人。", "何處遙知最惆悵，滿湖青草鴈聲春。"]'),
('a7eef0a3-b6c6-41bf-9943-ac00dc60f57a','送楊皞東歸','盧綸','唐','唐诗','tang','','[]','登樓掩泣話歸期，楚樹荆雲發遠思。',64,'全唐诗/poet.tang.15000.json','["登樓掩泣話歸期，楚樹荆雲發遠思。", "日裏揚帆聞戍鼓，舟中酹酒見山祠。", "西江風浪何時盡，北客音書欲寄誰。", "若說湓城楊司馬，知君望國有新詩。"]'),
('6846805b-01f3-442f-b7be-220466bd9c57','至德中途中書事却寄李僴','盧綸','唐','唐诗','tang','','[]','亂離無處不傷情，況復看碑對古城。',64,'全唐诗/poet.tang.15000.json','["亂離無處不傷情，況復看碑對古城。", "路遶寒山人獨去，月臨秋水鴈空驚。", "顏衰重喜歸鄉國，身賤多慚問姓名。", "今日主人還共醉，應憐世故一儒生。"]'),
('776db07f-66d2-4776-bd49-70f44b8aa67f','奉和太常王卿酬中書李舍人中書寓直春夜對月見寄','盧綸','唐','唐诗','tang','','[]','露如輕雨月如霜，不見星河見鴈行。',64,'全唐诗/poet.tang.15000.json','["露如輕雨月如霜，不見星河見鴈行。", "虛暈入池波自泛，滿輪當苑桂多香。", "春臺幾望黃龍闕，雲路寧分白玉郎。", "是夜巴歌應金石，豈殊螢影對清光。"]'),
('4dbaf1a5-195f-4924-845c-b61746bb3d3f','詶包佶郎中覽拙卷後見寄','盧綸','唐','唐诗','tang','','[]','令伯支離晚讀書，豈知詞賦稱相如。',64,'全唐诗/poet.tang.15000.json','["令伯支離晚讀書，豈知詞賦稱相如。", "枉逢花木無新思，拙就溪潭損舊居。", "禁路看山歌自緩，雲司玩月漏應疎。", "沈憂敢望金門召，空媿巴歈並子虛。"]'),
('23abc995-8b4c-4993-adc8-2ed76d03a09a','送史寀滑州謁賈僕射','盧綸','唐','唐诗','tang','','[]','朱門洞啓儼行車，金鐍裝囊半是書。',32,'全唐诗/poet.tang.15000.json','["朱門洞啓儼行車，金鐍裝囊半是書。", "君向東州問徐胤，羊公何事滅吹魚。"]'),
('90bab4dd-df1b-4079-9c1d-16b826f242ab','送鮑中丞赴太原','盧綸','唐','唐诗','tang','','[]','分路引鳴騶，喧喧似隴頭。',72,'全唐诗/poet.tang.15000.json','["分路引鳴騶，喧喧似隴頭。", "暫移西掖望，全解北門憂。", "專幕臨都護，分曹制督郵。", "積冰營不下，盛雪獵方休。", "白草連胡帳，黃雲擁戍樓。", "今朝送旌斾，一減魯儒羞。"]'),
('02bb777a-fa66-4121-9551-be32bea452df','送耿拾遺湋充括圖書使往江淮','盧綸','唐','唐诗','tang','','[]','傳令收遺籍，諸儒喜餞君。',48,'全唐诗/poet.tang.15000.json','["傳令收遺籍，諸儒喜餞君。", "孔家唯有地，禹穴但生雲。", "編簡知還續，蟲魚亦自分。", "如逢北山隱，一爲謝移文。"]'),
('933c7d8b-2648-46ac-8159-f7788a50d6e6','送郭判官赴振武','盧綸','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河九曲流，繚繞古邊州。',48,'全唐诗/poet.tang.15000.json','["黃河九曲流，繚繞古邊州。", "鳴鴈飛初夜，羌胡正晚秋。", "淒涼金管思，迢遰玉人愁。", "七葉推多慶，須懷殺敵憂。"]'),
('31b1a00e-1ae0-42d5-9996-e5bf8beecbb6','春江夕望','盧綸','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','洞庭芳草遍，楚客莫思歸。',48,'全唐诗/poet.tang.15000.json','["洞庭芳草遍，楚客莫思歸。", "經難人空老，逢春鴈自飛。", "東西兄弟遠，存沒友朋稀。", "獨立還垂淚，天南一布衣。"]'),
('f2c41f70-3904-4f90-b029-bd8d00145d33','送元昱尉義興','盧綸','唐','唐诗','tang','','[]','欲成雲海別，一夜夢天涯。',48,'全唐诗/poet.tang.15000.json','["欲成雲海別，一夜夢天涯。", "白浪緣江雨，青山繞縣花。", "風標當劇部，冠帶稱儒家。", "去矣謝親愛，知予髮已華。"]'),
('4cf72563-5645-4422-a473-c3629ecfe6b5','送黎兵曹往陝府結親','盧綸','唐','唐诗','tang','','[]','郎馬兩如龍，春朝上路逢。',48,'全唐诗/poet.tang.15000.json','["郎馬兩如龍，春朝上路逢。", "鴛鴦初集水，薜荔欲依松。", "步帳歌聲轉，妝臺燭影重。", "何言在陰者，得是戴侯宗。"]'),
('a239b10c-5bf9-4567-b4e4-981c1cdccc2f','送樂平苗明府','盧綸','唐','唐诗','tang','','[]','累職比柴桑，清秋入楚鄉。',48,'全唐诗/poet.tang.15000.json','["累職比柴桑，清秋入楚鄉。", "一船燈照浪，兩岸樹凝霜。", "亭吏趨寒霧，山城斂曙光。", "無辭折腰久，仲德在鴛行。"]'),
('4a648ac2-fe66-438d-b082-2da34f651fe6','晚到盩厔耆老家','盧綸','唐','唐诗','tang','','[]','老翁曾舊識，相引出柴門。',72,'全唐诗/poet.tang.15000.json','["老翁曾舊識，相引出柴門。", "苦話別時事，因尋溪上村。", "數年何處客，近日幾家存。", "冒雨看禾黍，逢人憶子孫。", "亂藤穿井口，流水到籬根。", "惆悵不堪住，空山月又昏。"]'),
('6817cfc5-e3fb-4b7a-bfad-2c0834b25fbd','臥病書懷','盧綸','唐','唐诗','tang','','[]','苦心三十載，白首遇艱難。',48,'全唐诗/poet.tang.15000.json','["苦心三十載，白首遇艱難。", "舊地成孤客，全家賴釣竿。", "貌衰緣藥盡，起晚爲山寒。", "老病今如此，無人更問看。"]'),
('9f9a289a-d34d-4eb2-b088-101ad715f873','落第後歸終南別業','盧綸','唐','唐诗','tang','','[]','久爲名所誤，春盡始歸山。',48,'全唐诗/poet.tang.15000.json','["久爲名所誤，春盡始歸山。", "落羽羞言命，逢人強破顏。", "交疎貧病裏，身老是非間。", "不及東溪月，漁翁夜往還。"]'),
('bc7ab474-3bbf-45d3-8a4c-e93cb4f7cf26','送朝邑張明府','盧綸','唐','唐诗','tang','','[]','千室暮山西，浮雲與樹齊。',48,'全唐诗/poet.tang.15000.json','["千室暮山西，浮雲與樹齊。", "剖辭雲落紙，擁吏雪成泥。", "野火蘆千頃，河田水萬畦。", "不知琴月夜，誰得聽烏啼。"]'),
('2bf05512-c1a2-4b61-9003-836641e6d37a','送李方東歸','盧綸','唐','唐诗','tang','','[]','故交三四人，聞別共霑巾。',48,'全唐诗/poet.tang.15000.json','["故交三四人，聞別共霑巾。", "舉目是陳事，滿城無至親。", "身從喪日病，家自儉年貧。", "此去何堪遠，遺孤在舊鄰。"]'),
('90fc2eea-4a5c-4bca-8720-23c04d7f523d','秋晚霽後野望憶夏侯審','盧綸','唐','唐诗','tang','','[]','天晴禾黍平，暢目亦傷情。',48,'全唐诗/poet.tang.15000.json','["天晴禾黍平，暢目亦傷情。", "野店雲日麗，孤莊砧杵鳴。", "川原唯寂寞，岐路自縱橫。", "前後無儔侶，此懷誰與呈。"]'),
('0d07bc17-063e-495e-bb05-f70bb9af671f','送王尊師','盧綸','唐','唐诗','tang','','[]','夢別一仙人，霞衣滿鶴身。',48,'全唐诗/poet.tang.15000.json','["夢別一仙人，霞衣滿鶴身。", "旌幢天路晚，桃杏海山春。", "種玉非求稔，燒金不爲貧。", "自憐頭白早，難與葛洪親。"]'),
('2eb449c7-94b0-48e5-a152-5037b4d7f78b','送撫州周使君','盧綸','唐','唐诗','tang','','[]','周郎三十餘，天子賜魚書。',48,'全唐诗/poet.tang.15000.json','["周郎三十餘，天子賜魚書。", "龍節隨雲水，金鐃動里閭。", "松聲三楚遠，鄉思百花初。", "若轉弘農守，蕭咸事不如。"]'),
('dffd705d-29d2-422f-883a-36ae86876fce','贈別司空曙','盧綸','唐','唐诗','tang','','[]','有月曾同賞，無秋不共悲。',24,'全唐诗/poet.tang.15000.json','["有月曾同賞，無秋不共悲。", "如何與君別，又是菊花時。"]'),
('8101e679-7510-483b-b032-75f6bfb5529d','送王錄事赴任蘇州','盧綸','唐','唐诗','tang','','[]','古堤迎拜路，萬里一帆前。',48,'全唐诗/poet.tang.15000.json','["古堤迎拜路，萬里一帆前。", "潮作澆田雨，雲成煮海煙。", "吏閑唯重法，俗富不憂邊。", "西掖今宵詠，還應寄阿連。"]'),
('8bd2b585-be71-4b37-be22-a8ce63972b65','大梵山寺院奉呈趣上人趙中丞','盧綸','唐','唐诗','tang','','[]','漸欲休人事，僧房學閉關。',48,'全唐诗/poet.tang.15000.json','["漸欲休人事，僧房學閉關。", "伴魚浮水上，看鶴向林間。", "寺古秋仍早，松深暮更閑。", "月中隨道友，夜夜坐空山。"]'),
('e1255db2-ff1c-49ff-b4b0-9914fbad280e','送恆操上人歸江外覲省','盧綸','唐','唐诗','tang','','[]','依佛不違親，高堂與寺鄰。',48,'全唐诗/poet.tang.15000.json','["依佛不違親，高堂與寺鄰。", "問安雙樹曉，求膳一僧貧。", "持呪過龍廟，翻經化海人。", "還同惠休去，儒者亦霑巾。"]'),
('d8592aae-e77c-4393-91b5-30a4db50c8e3','上巳日陪齊相公花樓宴','盧綸','唐','唐诗','tang','','[]','鍾陵暮春月，飛觀延羣英。',72,'全唐诗/poet.tang.15000.json','["鍾陵暮春月，飛觀延羣英。", "晨霞耀中軒，滿席羅金瓊。", "持杯凝遠睇，觸物結幽情。", "樹色參差綠，湖光瀲灩明。", "禮卑瞻絳帳，恩浹廁華纓。", "徒記山陰興，祓禊乃爲榮。"]'),
('64e506a0-6664-49b3-bd7d-826cc4629274','寒食','盧綸','唐','唐诗','tang','','[]','孤客飄飄歲載華，況逢寒食倍思家。',64,'全唐诗/poet.tang.15000.json','["孤客飄飄歲載華，況逢寒食倍思家。", "鶯啼遠墅多從柳，人哭荒墳亦有花。", "濁水秦渠通渭急，黃埃京洛上原斜。", "驅車西近長安好，宮觀參差半隱霞。"]'),
('6367bd53-1d65-492f-afae-57db79e5c812','舟中寒食','盧綸','唐','唐诗','tang','','[]','寒食空江曲，孤舟渺水前。',48,'全唐诗/poet.tang.15000.json','["寒食空江曲，孤舟渺水前。", "鬬雞沙鳥異，禁火岸花然。", "日霽開愁望，波喧警醉眠。", "因看數莖鬢，倍欲惜芳年。"]'),
('a2db743e-ffb6-4ad8-8afe-87d0b5a79633','元日早朝呈故省諸公','盧綸','唐','唐诗','tang','','[]','萬戟淩霜布，森森瑞氣間。',48,'全唐诗/poet.tang.15000.json','["萬戟淩霜布，森森瑞氣間。", "垂衣當曉日，上壽對南山。", "濟濟延多士，躚躚舞百蠻。", "小臣無事諫，空愧伴鳴環。"]'),
('4f637cfe-2766-4d58-925a-fe3e4ae6b864','元日朝迴中夜書情寄南宮二故人','盧綸','唐','唐诗','tang','','[]','鳴珮隨鵷鷺，登堦見冕旒。',48,'全唐诗/poet.tang.15000.json','["鳴珮隨鵷鷺，登堦見冕旒。", "無能裨聖代，何事別滄洲。", "閑夜貧還醉，浮名老漸羞。", "鳳城春欲晚，郎吏憶同遊。"]'),
('2072e6c8-0902-4c2b-aa89-9fc077a928c2','裴給事宅白牡丹','盧綸','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u7261\u4e39", "\u82b1", "\u8d5e\u7f8e", "\u5199\u82b1"]','長安豪貴惜春殘，爭翫街西紫牡丹。',32,'全唐诗/poet.tang.15000.json','["長安豪貴惜春殘，爭翫街西紫牡丹。", "別有玉盤承露冷，無人起就月中看。"]'),
('95551421-c7e5-4b3b-9524-2b16e2adfffb','送韋判官得雨中山','盧綸','唐','唐诗','tang','','[]','前峰後嶺碧濛濛，草擁驚泉樹帶風。',32,'全唐诗/poet.tang.15000.json','["前峰後嶺碧濛濛，草擁驚泉樹帶風。", "人語馬嘶聽不得，更堪長路在雲中。"]'),
('1d9d13a9-948b-485d-ad51-4f562bcddd7a','送宛丘任少府','盧綸','唐','唐诗','tang','','[]','帶綬別鄉親，東爲千里人。',48,'全唐诗/poet.tang.15000.json','["帶綬別鄉親，東爲千里人。", "俗訛唯競祭，地古不留春。", "野戍雲藏火，軍城樹擁塵。", "少年何所重，才子又清貧。"]'),
('c7116858-e5b8-49df-a243-7e9b469fd55d','送永陽崔明府','盧綸','唐','唐诗','tang','','[]','鶴唳蒹葭曉，中流見楚城。',48,'全唐诗/poet.tang.15000.json','["鶴唳蒹葭曉，中流見楚城。", "浪清風乍息，山白月猶明。", "廢路開荒木，歸人種古營。", "懸聞正訛俗，邴曼更知名。"]'),
('19710654-694f-4c8b-a46f-7eaf13ff8570','割飛二刀子歌','盧綸','唐','唐诗','tang','','[]','我家有翦刀，人云鬼國鐵。',156,'全唐诗/poet.tang.15000.json','["我家有翦刀，人云鬼國鐵。", "裁羅裁綺無鈍時，用來三年一股折。", "南中匠人淳用鋼，再令盤屈隨手傷。", "改鍛割飛二刀子，色迎霽雪鋒含霜。", "兩條神物秋冰薄，刃淬初蟾鞘金錯。", "越戟吳鉤不足誇，斬犀切玉應懷怍。", "日試曾磨漢水邊，掌中恄慄聲冷然。", "神驚魄悸却收得，刃頭已吐微微煙。", "刀乎刀乎何燁燁，魑魅須藏怪須懾。", "若非良工變爾形，只向裁縫委箱篋。"]'),
('95282845-ccd2-4adb-983d-c05d7bd69b1d','送郎士元使君赴郢州','盧綸','唐','唐诗','tang','','[]','賜衣兼授節，行日郢中聞。',48,'全唐诗/poet.tang.15000.json','["賜衣兼授節，行日郢中聞。", "花發登山廟，天晴閱水軍。", "漁商三楚接，郡邑九江分。", "高興應難遂，元戎有大勳。"]'),
('d0732778-7a5f-428b-b5dd-3b0d4b6b4d57','春詞','盧綸','唐','唐诗','tang','','[]','北苑羅裙帶，塵衢錦繡鞵。',24,'全唐诗/poet.tang.15000.json','["北苑羅裙帶，塵衢錦繡鞵。", "醉眠芳樹下，半被落花埋。"]'),
('0522c67c-f6ed-413b-8e0f-03b1f1d2c8bf','清如玉壺冰','盧綸','唐','唐诗','tang','','[]','玉壺冰始結，循吏政初成。',72,'全唐诗/poet.tang.15000.json','["玉壺冰始結，循吏政初成。", "既有虛心鑒，還如照膽清。", "瑤池慙洞澈，金鏡讓澄明。", "氣若朝霜動，形隨夜月盈。", "臨人能不蔽，待物本無情。", "怯對圓光裹，妍蚩自此呈。"]'),
('682673fa-3fe9-4902-bb0a-0588c23ec54e','山店','盧綸','唐','唐诗','tang','','[]','登登山路行時盡，決決溪泉到處聞。',32,'全唐诗/poet.tang.15000.json','["登登山路行時盡，決決溪泉到處聞。", "風動葉聲山犬吠，一家松火隔秋雲。"]'),
('6efc7239-d114-47bd-b94d-f5742d60101b','長至日上公獻壽','崔琮','唐','唐诗','tang','','[]','應律三陽首，朝天萬國同。',72,'全唐诗/poet.tang.15000.json','["應律三陽首，朝天萬國同。", "斗邊看子月，臺上候祥風。", "五夜鐘初動，千門日正融。", "玉階文物盛，仙仗武貔雄。", "率舞皆羣辟，稱觴即上公。", "南山爲聖壽，長對未央宮。"]'),
('276ff801-6047-46aa-9382-61cb0b824e5d','長至日上公獻壽','李竦','唐','唐诗','tang','','[]','候曉金門闢，乘時玉曆長。',74,'全唐诗/poet.tang.15000.json','["候曉金門闢，乘時玉曆長。", "羽儀瞻上宰，雲物麗初陽。", "漢禮方傳珮，堯年正捧觴。", "日行臨觀闕，帝錫洽珪璋。", "盛美超三代，洪休降百祥。", "自憐朝末坐，空此詠無[疆]。"]'),
('d8d7e9ee-237a-4b42-b9a8-bf55b3c66246','賦得西戎獻白玉環','李竦','唐','唐诗','tang','','[]','當時無外守，方物四夷通。',72,'全唐诗/poet.tang.15000.json','["當時無外守，方物四夷通。", "列土金河北，朝天玉塞東。", "自將荆璞比，不與鄭環同。", "正朔雖傳漢，衣冠尚帶戎。", "幸承提佩寵，多媿琢磨功。", "絕域知文教，爭趨上國風。"]'),
('489af613-f3cc-42ad-b304-a4f928917a4e','新安江行','章八元','唐','唐诗','tang','','[]','江源南去永，野渡暫維梢。',48,'全唐诗/poet.tang.15000.json','["江源南去永，野渡暫維梢。", "古戍懸魚網，空林露鳥巢。", "雪晴山脊見，沙淺浪痕交。", "自笑無媒者，逢人作解嘲。"]'),
('1d371211-04bf-43d5-a5fd-39d664a176b7','酬劉員外月下見寄','章八元','唐','唐诗','tang','','[]','夜涼河漢白，卷箔出南軒。',48,'全唐诗/poet.tang.15000.json','["夜涼河漢白，卷箔出南軒。", "過月鴻爭遠，辭枝葉暗翻。", "獨謠聞麗曲，緩步接清言。", "宣室思前席，行看拜主恩。"]'),
('5c228217-7f18-441d-9c3b-539338458cf9','寄都官劉員外','章八元','唐','唐诗','tang','','[]','舊宅平津邸，槐陰接漢宮。',48,'全唐诗/poet.tang.15000.json','["舊宅平津邸，槐陰接漢宮。", "鳴騶馳道上，寒日直廬中。", "白雪歌偏麗，青雲宦早通。", "悠然一縫掖，千里限清風。"]'),
('a82531fb-9915-49a7-bb2d-0fc4cec6fd2f','題慈恩寺塔','章八元','唐','唐诗','tang','','[]','十層突兀在虛空，四十門開面面風。',64,'全唐诗/poet.tang.15000.json','["十層突兀在虛空，四十門開面面風。", "却怪鳥飛平地上，自驚人語半天中。", "迴梯暗踏如穿洞，絕頂初攀似出籠。", "落日鳳城佳氣合，滿城春樹雨濛濛。"]'),
('3f350588-b1b6-455d-b871-e6703f228cea','歸桐廬舊居寄嚴長史','章八元','唐','唐诗','tang','','[]','昨辭夫子櫂歸舟，家在桐廬憶舊丘。',64,'全唐诗/poet.tang.15000.json','["昨辭夫子櫂歸舟，家在桐廬憶舊丘。", "三月暖時花競發，兩溪分處水爭流。", "近聞江老傳鄉語，遙見家山減旅愁。", "或在醉中逢夜雪，懷賢應向剡川遊。"]'),
('90dbe859-93fb-4ccb-a5b0-1896eb2da0bb','天台道中示同行','章八元','唐','唐诗','tang','','[]','八重巖崿疊晴空，九色煙霞遶洞宮。',32,'全唐诗/poet.tang.15000.json','["八重巖崿疊晴空，九色煙霞遶洞宮。", "仙道多因迷路得，莫將心事問樵翁。"]'),
('1a6a438f-ee84-40e8-8e66-56ccc4ace6df','元日望含元殿御扇開合','章八元','唐','唐诗','tang','','[]','萬國來朝歲，千年覲聖君。',72,'全唐诗/poet.tang.15000.json','["萬國來朝歲，千年覲聖君。", "輦迎仙杖出，扇匝御香焚。", "俯對朝容近，先知曙色分。", "冕旒開處見，鐘磬合時聞。", "影動承朝日，花攢似慶雲。", "蒲葵那可比，徒用隔炎氛。"]'),
('732defb7-3b46-41cb-b01f-6b77a1bb875b','清明日賜百僚新火','史延','唐','唐诗','tang','','[]','上苑連侯第，清明及暮春。',72,'全唐诗/poet.tang.15000.json','["上苑連侯第，清明及暮春。", "九天初改火，萬井屬良辰。", "頒賜恩逾洽，承時慶自均。", "翠煙和柳嫩，紅焰出花新。", "寵命尊三老，祥光燭萬人。", "太平當此日，空復荷陶甄。"]'),
('f7648c0c-9b9c-48ce-8737-a857b49d55c4','清明日賜百僚新火','韓濬','唐','唐诗','tang','','[]','朱騎傳紅燭，天廚賜近臣。',72,'全唐诗/poet.tang.15000.json','["朱騎傳紅燭，天廚賜近臣。", "火隨黃道見，煙遶白榆新。", "榮耀分他日，恩光共此辰。", "更調金鼎膳，還暖玉堂人。", "灼灼千門曉，輝輝萬井春。", "應憐螢聚夜，瞻望及東鄰。"]'),
('0c7fe215-f78d-409a-ad00-d0c425df5775','清明日賜百僚新火','韓濬','唐','唐诗','tang','','[]','改火清明後，優恩賜近臣。',72,'全唐诗/poet.tang.15000.json','["改火清明後，優恩賜近臣。", "漏殘丹禁晚，燧發白榆新。", "瑞彩來雙闕，神光煥四鄰。", "氣回侯第暖，煙散帝城春。", "利用調羹鼎，餘輝燭縉紳。", "皇明如照隱，願及聚螢人。"]'),
('07921a7f-dd01-4929-852f-8b2d6d213b34','清明日賜百僚新火','韓濬','唐','唐诗','tang','','[]','御火傳香殿，華光及侍臣。',72,'全唐诗/poet.tang.15000.json','["御火傳香殿，華光及侍臣。", "星流中使馬，燭耀九衢人。", "轉影連金屋，分輝麗錦茵。", "焰迎紅蘂發，煙染綠條春。", "助律和風早，添爐煖氣新。", "誰憐一寒士，猶望照東鄰。"]'),
('09615497-a813-43c2-bcd9-39dc6d386646','投珠於泉','獨孤綬','唐','唐诗','tang','','[]','至道歸淳樸，明珠被棄捐。',72,'全唐诗/poet.tang.15000.json','["至道歸淳樸，明珠被棄捐。", "天真來照乘，成性却沈泉。", "不是靈蛇吐，非緣合浦還。", "岸傍隨月落，波底共星懸。", "致遠終無脛，懷貪遂息肩。", "欲知恭儉德，所寶在惟賢。"]'),
('41960329-86d2-4636-83cf-80292b6d1bb9','秦鏡','獨孤綬','唐','唐诗','tang','','[]','萬古秦時鏡，從來抱至精。',72,'全唐诗/poet.tang.15000.json','["萬古秦時鏡，從來抱至精。", "依臺月自吐，在匣水常清。", "爛爛金光發，澄澄物象生。", "雲天皆洞鑒，表裏盡虛明。", "但見人窺膽，全勝響應聲。", "妍媸定可識，何處更逃情。"]'),
('f0aea48b-98b5-42de-8986-3d2e80540dd5','秦鏡','張佐','唐','唐诗','tang','','[]','樓上秦時鏡，千秋獨有名。',72,'全唐诗/poet.tang.15000.json','["樓上秦時鏡，千秋獨有名。", "菱花寒不落，冰質夏長清。", "龍在形難掩，人來膽易呈。", "昇臺宜遠照，開匣乍藏明。", "皎色新磨出，圓規舊鑄成。", "愁容如可鑒，當欲拂塵纓。"]'),
('2b8ded04-d94a-4096-abd3-73993cce7fcf','憶遊天台寄道流','張佐','唐','唐诗','tang','','[]','憶昨天台到赤城，幾朝仙籟耳中生。',64,'全唐诗/poet.tang.15000.json','["憶昨天台到赤城，幾朝仙籟耳中生。", "雲龍出水風聲急，海鶴鳴臯日色清。", "石笋半山移步險，桂花當澗拂衣輕。", "今來盡是人間夢，劉阮茫茫何處行。"]'),
('3e3f5d61-6068-4103-b470-5bccf1eb5127','龜負圖','張佐','唐','唐诗','tang','','[]','天意將垂象，神龜出負圖。',72,'全唐诗/poet.tang.15000.json','["天意將垂象，神龜出負圖。", "五方行有配，八卦義寧孤。", "作瑞旌君德，披文叶帝謨。", "乘流喜得路，逢聖幸存軀。", "蓮葉池通泛，桃花水自浮。", "還尋九江去，安肯曳泥途。"]'),
('a8ad6062-6360-4804-8a85-e123e41c7058','上元日夢王母獻白玉環','張佐','唐','唐诗','tang','','[]','夢中朝上日，闕下拜天顏。',72,'全唐诗/poet.tang.15000.json','["夢中朝上日，闕下拜天顏。", "彷彿瞻王母，分明獻玉環。", "靈姿趨甲帳，悟道契玄關。", "似見霜姿白，如看月彩彎。", "霓裳歸物外，鳳曆曉人寰。", "仙聖非相遠，昭昭寤寐間。"]'),
('1c2a1bfc-9b0c-48ef-a5f1-c6a028bc0837','良田無晚歲','張佐','唐','唐诗','tang','','[]','人功雖未及，地力信非常。',72,'全唐诗/poet.tang.15000.json','["人功雖未及，地力信非常。", "不任耕耘早，偏宜黍稷良。", "無年皆有獲，後種亦先芳。", "膴膴盈千畝，青青保萬箱。", "何須祭田祖，詎要察農祥。", "況是春三月，和風日又長。"]'),
('1595f1a9-d8fb-4b39-a406-c242b0e47ba7','下第獻座主張謂','閻濟美','唐','唐诗','tang','','[]','謇諤王臣直，文明雅量全。',72,'全唐诗/poet.tang.15000.json','["謇諤王臣直，文明雅量全。", "望爐金自躍，應物鏡何偏。", "南國幽沈盡，東堂禮樂宣。", "轉令遊藝士，更惜至公年。", "芳樹歡新景，青雲泣暮天。", "唯愁鳳池拜，孤賤更誰憐。"]'),
('b39ea5db-c0a2-4ff9-8f7c-a77e66c902fe','天津橋望洛城殘雪','閻濟美','唐','唐诗','tang','','[]','新霽洛城端，千家積雪寒。',24,'全唐诗/poet.tang.15000.json','["新霽洛城端，千家積雪寒。", "未收清禁色，偏向上陽殘。"]'),
('67390431-5c05-4de2-8fbc-2fbe19f363b2','尚書郎上直聞春漏','張少博','唐','唐诗','tang','','[]','建禮含香處，重城待漏辰。',72,'全唐诗/poet.tang.15000.json','["建禮含香處，重城待漏辰。", "徐聲傳鳳闕，曉唱辨雞人。", "銀箭聽將盡，銅壺滴更新。", "催籌當五夜，移刻及三春。", "杳杳從天遠，泠泠出禁頻。", "直廬殘響曙，肅穆對鉤陳。"]'),
('2fa31522-6b7d-4c10-b9a4-ee278d17a714','雪夜觀象闕待漏','張少博','唐','唐诗','tang','','[]','殘雪初睛後，鳴珂奉闕庭。',72,'全唐诗/poet.tang.15000.json','["殘雪初睛後，鳴珂奉闕庭。", "九門傳曉漏，五夜候晨扃。", "北斗橫斜漢，東方落曙星。", "煙氛初動色，簪佩未分形。", "雪重猶垂白，山遙不辨青。", "雞人更唱處，偏入此時聽。"]'),
('c0837426-530d-494d-aa6f-65251b567723','尚書郎上直聞春漏','周徹','唐','唐诗','tang','','[]','建禮通華省，含香直紫宸。',72,'全唐诗/poet.tang.15000.json','["建禮通華省，含香直紫宸。", "靜聞銅史漏，暗識桂宮春。", "滴瀝疑將絕，清泠發更新。", "寒聲臨鴈沼，疎韻應雞人。", "迥入千門徹，行催五夜頻。", "高臺閑自聽，非是駐征輪。"]'),
('128d20fe-45cc-41dc-8fd2-681d12c4d178','及第後贈試官','高拯','唐','唐诗','tang','','[]','公子求賢未識真，欲將毛遂比常倫。',32,'全唐诗/poet.tang.15000.json','["公子求賢未識真，欲將毛遂比常倫。", "當時不及三千客，今日何如十九人。"]'),
('8a23377a-f7fc-46c8-adae-1c1c24983c9e','賦得花發上林','王表','唐','唐诗','tang','','[]','御苑春何早，繁花已繡林。',72,'全唐诗/poet.tang.15000.json','["御苑春何早，繁花已繡林。", "笑迎明主仗，香拂美人簪。", "地接樓臺近，天垂雨露深。", "晴光來戲蝶，夕景動棲禽。", "欲托凌雲勢，先開捧日心。", "方知桃李樹，從此別成陰。"]'),
('e9ff4727-4dec-4fd8-ab61-336c693af7c3','清明日登城春望寄大夫使君','王表','唐','唐诗','tang','','[]','春城閑望愛睛天，何處風光不眼前。',64,'全唐诗/poet.tang.15000.json','["春城閑望愛睛天，何處風光不眼前。", "寒食花開千樹雪，清明日出萬家煙。", "興來促席唯同舍，醉後狂歌盡少年。", "聞說鶯啼却惆悵，詩成不見謝臨川。"]'),
('c6a5ff18-3608-4a2e-8303-9bce326fe4f4','成德樂','王表','唐','唐诗','tang','','[]','趙女乘春上畫樓，一聲歌發滿城秋。',32,'全唐诗/poet.tang.15000.json','["趙女乘春上畫樓，一聲歌發滿城秋。", "無端更唱關山曲，不是征人亦淚流。"]'),
('07539a31-da11-4f18-a70f-8218274f6e23','花發上林','獨孤授','唐','唐诗','tang','','[]','上苑韶容早，芳菲正吐花。',72,'全唐诗/poet.tang.15000.json','["上苑韶容早，芳菲正吐花。", "無言向春日，閑笑任年華。", "潤色籠輕靄，睛光豔晚霞。", "影連千戶竹，香散萬人家。", "幸遶樓臺近，仍懷雨露賒。", "願君垂採摘，不使落風沙。"]'),
('f20723e8-6704-4fad-8888-66ca7ddda248','賦得花發上林','王儲','唐','唐诗','tang','','[]','東陸和風至，先開上苑花。',72,'全唐诗/poet.tang.15000.json','["東陸和風至，先開上苑花。", "穠枝藏宿鳥，香蘂拂行車。", "散白憐睛日，舒紅愛晚霞。", "桃間留御馬，梅處入胡笳。", "城郭連增媚，樓臺映轉華。", "豈同幽谷草，春至發猶賒。"]'),
('32b0c752-58ae-419d-abc2-c4bbc69e0632','賦得花發上林','周渭','唐','唐诗','tang','','[]','灼灼花凝雪，春來發上林。',72,'全唐诗/poet.tang.15000.json','["灼灼花凝雪，春來發上林。", "向風初散蘂，垂葉欲成陰。", "人過香隨遠，煙晴色自深。", "淨時空結霧，疎處未藏禽。", "菶茸何年植，間關幾日吟。", "一枝如可冀，不負折芳心。"]'),
('022a1d72-1028-493e-897e-42b6cdb47e84','贈龍興觀主吳崇岳','周渭','唐','唐诗','tang','','[]','楮爲冠子布爲裳，吞得丹霞壽最長。',64,'全唐诗/poet.tang.15000.json','["楮爲冠子布爲裳，吞得丹霞壽最長。", "混俗性靈常樂道，出塵風格早休糧。", "枕中經妙誰傳與，肘後方新自寫將。", "百尺松梢幾飛步，鶴棲板上禮虛皇。"]'),
('515db1b8-0e77-479d-b284-337960ed594c','從軍有苦樂行','李益','唐','唐诗','tang','','[]','勞者且莫歌，我欲送君觴。',216,'全唐诗/poet.tang.15000.json','["勞者且莫歌，我欲送君觴。", "從軍有苦樂，此曲樂未央。", "僕居在隴上，隴水斷人腸。", "東過秦宮路，宮路入咸陽。", "時逢漢帝出，諫獵至長楊。", "詎馳遊俠窟，非結少年場。", "一旦承嘉惠，輕身重恩光。", "秉筆參帷帟，從軍至朔方。", "邊地多陰風，草木自淒涼。", "斷絕海雲去，出沒胡沙長。", "參差引雁翼，隱轔騰軍裝。", "劒文夜如水，馬汗凍成霜。", "俠氣五都少，矜功六郡良。", "山河起目前，睚眥死路傍。", "北逐驅獯虜，西臨復舊疆。", "昔還賦餘資，今出乃贏糧。", "一矢弢夏服，我弓不再張。", "寄語丈夫雄，苦樂身自當。"]'),
('b9fa15f5-c7ac-40b3-998f-6ae03ba52122','登長城','李益','唐','唐诗','tang','','[]','漢家今上郡，秦塞古長城。',36,'全唐诗/poet.tang.15000.json','["漢家今上郡，秦塞古長城。", "有日雲長慘，無風沙自驚。", "當今聖天子，不戰四夷平。"]'),
('ab07dac2-299a-485a-bc5f-41450e4a41e0','雜曲','李益','唐','唐诗','tang','','[]','妾本蠶家女，不識貴門儀。',288,'全唐诗/poet.tang.15000.json','["妾本蠶家女，不識貴門儀。", "藁砧持玉斧，交結五陵兒。", "十日或一見，九日在路岐。", "人生此夫壻，富貴欲何爲。", "楊柳徒可折，南山不可移。", "婦人貴結髮，寧有再嫁資。", "嫁女莫望高，女心願所宜。", "寧從賤相守，不願貴相離。", "藍葉鬱重重，藍花若榴色。", "少婦歸少年，華光自相得。", "誰言配君子，以奉百年身。", "有義即夫壻，無義還他人。", "愛如寒爐火，棄若秋風扇。", "山嶽起面前，相看不相見。", "丈夫非小兒，何用強相知。", "不見朝生菌，易成還易衰。", "征客欲臨路，居人還出門。", "北風河梁上，四野愁雲繁。", "豈不戀我家，夫壻多感恩。", "前程有日月，勳績在河源。", "少婦馬前立，請君聽一言。", "春至草亦生，誰能無別情。", "殷勤展心素，見新莫忘故。", "遙望孟門山，殷勤報君子。"]'),
('d9afbbdc-a953-44c7-93c6-dd133a03a2cd','送遼陽使還軍','李益','唐','唐诗','tang','','[]','征人歌且行，北上遼陽城。',72,'全唐诗/poet.tang.15000.json','["征人歌且行，北上遼陽城。", "二月戎馬息，悠悠邊草生。", "青山出塞斷，代地入雲平。", "昔者匈奴戰，多聞殺漢兵。", "平生報國憤，日夜角弓鳴。", "勉君萬里去，勿使虜塵驚。"]'),
('3ca620fc-0a9c-426b-95f1-041c6091da71','賦得早燕送別','李益','唐','唐诗','tang','','[]','碧草縵如綫，去來雙[飛燕]。',62,'全唐诗/poet.tang.15000.json','["碧草縵如綫，去來雙[飛燕]。", "長門未有春，先入班姬殿。", "梁空繞不息，簷寒窺欲遍。", "今至隨紅萼，昔還悲素扇。", "一別與秋鴻，差池詎相見。"]'),
('ee2d9ff4-6312-41b4-b3b1-51096b8bfac7','秋晚溪中寄懷大理齊司直','李益','唐','唐诗','tang','','[]','鳳翔屬明代，羽翼文葳蕤。',121,'全唐诗/poet.tang.15000.json','["鳳翔屬明代，羽翼文葳蕤。", "崑崙進琪樹，飛舞下瑤池。", "振儀自西睠，東夏復分釐。", "國典唯平法，伊人方在斯。", "荒嶽寧桁楊肅，芳輝蘭玉滋。", "明質鶩高景，飄颻服纓綏。", "天寒清洛苑，秋夕白雲司。", "況復空巖側，蒼蒼幽桂期。", "歲寒坐流霰，山川猶別離。", "浩思憑尊酒，氛氳獨含辭。"]'),
('8ea0d141-1f1f-4a54-b38e-bc62fb19b466','溪中月下寄楊子尉封亮','李益','唐','唐诗','tang','','[]','蘅若奪幽色，銜思恍無悰。',96,'全唐诗/poet.tang.15000.json','["蘅若奪幽色，銜思恍無悰。", "宵長霜霧多，歲晏淮海風。", "團團山中月，三五離夕同。", "露凝朱弦絕，觴至蘭玉空。", "清光液流波，盛明難再逢。", "嘗恐河漢遠，坐窺烟景窮。", "小人諒處陰，君子樹大功。", "永願厲高翼，慰我丹桂叢。"]'),
('e70823e0-fc5f-4037-be83-4cbe7c64dbe4','春晚賦得餘花落','李益','唐','唐诗','tang','','[]','留春春竟去，春去花如此。',48,'全唐诗/poet.tang.15000.json','["留春春竟去，春去花如此。", "蝶舞遶應稀，鳥驚飛詎已。", "衰紅辭故萼，繁綠扶彫蕊。", "自委不勝愁，庭風那更起。"]'),
('ad33b922-6943-43a1-9359-c07d8d9b5901','聞亡友王七嘉禾寺得素琴','李益','唐','唐诗','tang','','[]','故人惜此去，留琴明月前。',60,'全唐诗/poet.tang.15000.json','["故人惜此去，留琴明月前。", "今來我訪舊，淚灑白雲天。", "詎欲匣孤響，送君歸夜泉。", "撫琴猶可絕，況此故無弦。", "何必雍門奏，然後淚潺湲。"]'),
('ade51752-8b55-4531-a8c5-d791afa59916','校書郎楊凝往年以古鏡貺別今追贈以詩','李益','唐','唐诗','tang','','[]','明鏡出匣時，明如雲間月。',48,'全唐诗/poet.tang.15000.json','["明鏡出匣時，明如雲間月。", "一別青春鑑，回光照華髪。", "美人昔自愛，鞶帶手中結。", "願以三五期，經天無玷缺。"]'),
('bb5e5716-f3f4-4b1f-9f73-f0468647a683','置酒行','李益','唐','唐诗','tang','','[]','置酒命所歡，憑觴遂爲戚。',96,'全唐诗/poet.tang.15000.json','["置酒命所歡，憑觴遂爲戚。", "日往不再來，茲辰坐成昔。", "百齡非久長，五十將半百。", "胡爲勞我形，已鬚還復白。", "西山鸞鶴羣，矯矯煙霧翮。", "明霞發金丹，陰洞潛水碧。", "安得凌風羽，崦嵫駐靈魄。", "無然坐衰老，慙歎東陵柏。"]'),
('733b1783-2f55-486d-9ee8-92ac305b8f87','長社竇明府宅夜送王屋道士常究子','李益','唐','唐诗','tang','','[]','旦隨三鳥去，羽節凌霞光。',48,'全唐诗/poet.tang.15000.json','["旦隨三鳥去，羽節凌霞光。", "暮與雙鳧宿，雲車下紫陽。", "天壇臨月近，洞水出山長。", "海嶠年年別，丘陵徒自傷。"]'),
('1d330002-71b0-4c14-a73d-ed005b3fd550','觀回軍三韻','李益','唐','唐诗','tang','','[]','行行上隴頭，隴月暗悠悠。',36,'全唐诗/poet.tang.15000.json','["行行上隴頭，隴月暗悠悠。", "萬里將軍沒，回旌隴戍秋。", "誰令嗚咽水，重入故營流。"]'),
('a993cb9d-5032-49bc-be23-e9e3fda3de76','華山南廟','李益','唐','唐诗','tang','','[]','陰山臨古道，古廟閉山碧。',72,'全唐诗/poet.tang.15000.json','["陰山臨古道，古廟閉山碧。", "落日春草中，搴芳薦瑤席。", "明靈達精意，髣髴如不隔。", "巖雨神降時，回飆入松栢。", "常聞坑儒後，此地返秦璧。", "自古害忠良，神其輔宗祏。"]'),
('a3a39ad1-5f25-463c-a4a3-09c0dd7c814c','喜邢校書遠至對雨同賦遠晚飯阮返五韻','李益','唐','唐诗','tang','','[]','雀噪空城陰，木衰羇思遠。',60,'全唐诗/poet.tang.15000.json','["雀噪空城陰，木衰羇思遠。", "已蔽青山望，徒悲白雲晚。", "別離千里風，雨中同一飯。", "開徑說逢康，臨觴方接阮。", "旅宦竟何如，勞飛思自返。"]'),
('44e15dd3-3621-46ff-be2a-145555ed2593','城西竹園送裴佶王達','李益','唐','唐诗','tang','','[]','葳蕤凌風竹，寂寞離人觴。',36,'全唐诗/poet.tang.15000.json','["葳蕤凌風竹，寂寞離人觴。", "愴懷非外至，沈鬱自中腸。", "遠行從此始，別袂重淒霜。"]'),
('a47b1955-1d2d-4229-abd2-13f63dc48b33','月下喜邢校書至自洛','李益','唐','唐诗','tang','','[]','天河夜未央，漫漫復蒼蒼。',48,'全唐诗/poet.tang.15000.json','["天河夜未央，漫漫復蒼蒼。", "重君遠行至，及此明目光。", "華星暎衰柳，暗水入寒塘。", "客心定何似，餘歡方自長。"]'),
('8500c255-d23f-45d9-9e39-740d3db74207','北至太原','李益','唐','唐诗','tang','','[]','炎祚昔昏替，皇基此鬱盤。',96,'全唐诗/poet.tang.15000.json','["炎祚昔昏替，皇基此鬱盤。", "玄命久已集，撫運良乃艱。", "南阨羊腸險，北走雁門寒。", "始於一戎定，垂此億世安。", "唐風本憂思，王業寔艱難。", "中曆雖橫潰，天紀未可干。", "聖明所興國，靈嶽固不殫。", "咄咄薄遊客，斯言殊不刊。"]'),
('d093922e-8afb-4b35-a3dd-be3fca63e29c','入華山訪隱者經仙人石壇','李益','唐','唐诗','tang','','[]','三考四嶽下，官曹少休沐。',204,'全唐诗/poet.tang.15000.json','["三考四嶽下，官曹少休沐。", "久負青山諾，今還獲所欲。", "嘗聞玉清洞，金簡受玄籙。", "夙駕昇天行，雲遊恣霞宿。", "平明矯輕策，捫石入空曲。", "仙人古石壇，苔遶青瑤局。", "陽桂凌煙紫，陰蘿冒水綠。", "隔世聞丹經，懸泉注明玉。", "前驚羽人會，白日天居肅。", "問我將致辭，笑之自相目。", "竦身雲遂起，仰見雙白鵠。", "墮其一紙書，文字類鳥足。", "視之了不識，三返又三復。", "歸來問方士，舉世莫解讀。", "何必若蜉蝣，然後爲跼促。", "鄙哉宦遊子，身志俱降辱。", "再往不及期，勞歌叩山木。"]'),
('ad4dd7c8-f86a-44ec-b83c-bd90010336ac','罷鏡','李益','唐','唐诗','tang','','[]','手中青銅鏡，照我少年時。',48,'全唐诗/poet.tang.15000.json','["手中青銅鏡，照我少年時。", "衰颯一如此，清光難復持。", "欲令孤月掩，從遣半心疑。", "縱使逢人見，猶勝自見悲。"]'),
('a42e87f4-178e-4efe-b243-97c7c076921b','華陰東泉同張處士詣藏律師兼簡縣內同官因寄齊中書','李益','唐','唐诗','tang','','[]','蒼崖抱寒泉，淪照洞金碧。',192,'全唐诗/poet.tang.15000.json','["蒼崖抱寒泉，淪照洞金碧。", "潛鱗孕明晦，山靈閟幽賾。", "前峯何其詭，萬變窮日夕。", "松老風易悲，山秋雲更白。", "故人邑中吏，五里仙霧隔。", "美質簡瓊瑤，英聲鏗金石。", "煩君竟相問，問我此何適。", "我因贊時理，書寄西飛翮。", "哲匠熙百工，日月被光澤。", "大國本多士，荆岑無遺璧。", "高網彌八紘，皇圖明四闢。", "羣材既兼暢，顧我在草澤。", "貴無身外名，賤有區中役。", "忽忽百齡內，殷殷千慮迫。", "人生已如寄，在寄復爲客。", "舊國不得歸，風塵滿阡陌。"]'),
('c2e57bc6-5287-4794-a099-e361b004ff83','答郭黃中孤雲首章見贈','李益','唐','唐诗','tang','','[]','孤雲生西北，從風東南飄。',48,'全唐诗/poet.tang.15000.json','["孤雲生西北，從風東南飄。", "帝鄉日已遠，蒼梧無還飆。", "已矣玄鳳歎，嚴霜集靈苕。", "君其勉我懷，歲暮孰不彫。"]'),
('0412e81a-6c61-423a-9822-8c728327f315','合源溪期張計不至','李益','唐','唐诗','tang','','[]','霜露肅時序，緬然方獨尋。',60,'全唐诗/poet.tang.15000.json','["霜露肅時序，緬然方獨尋。", "暗溪遲仙侶，寒澗聞松禽。", "寂歷茲夜永，清明秋序深。", "微波澹澄夕，煙景含虛林。", "素志久淪否，幽懷方自吟。"]'),
('8bfe2432-2fa9-4733-a72a-45030c30a391','竹溪','李益','唐','唐诗','tang','','[]','訪竹越雲崖，即林若溪絕。',48,'全唐诗/poet.tang.15000.json','["訪竹越雲崖，即林若溪絕。", "寧知修幹下，漠漠秋苔潔。", "清光溢空曲，茂色臨幽澈。", "採摘愧芳鮮，奉君歲暮節。"]'),
('5994ba67-0113-4080-9b77-0cb3ef0f6c68','送諸曁王主簿之任','李益','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u666f"]','別愁已萬緒，離曲方三奏。',60,'全唐诗/poet.tang.15000.json','["別愁已萬緒，離曲方三奏。", "遠宦一辭鄉，南天異風候。", "秦城歲芳老，越國春山秀。", "落日望寒濤，公門閉清晝。", "何用慰相思，裁書寄關右。"]'),
('cae9a08c-a98f-44c7-a836-499214f972c7','罷秩後入華山採茯苓逢道者','李益','唐','唐诗','tang','','["\u534e\u5c71"]','委綬來名山，觀奇恣所停。',204,'全唐诗/poet.tang.15000.json','["委綬來名山，觀奇恣所停。", "山中若有聞，言此不死庭。", "遂逢五老人，一謂西嶽靈。", "或聞樵人語，飛去入昴星。", "授我出雲路，蒼然凌石屏。", "視之有文字，乃古黃庭經。", "左右長松列，動搖風露零。", "上蟠千年枝，陰虯負青冥。", "下結九秋霰，流膏爲茯苓。", "取之砂石間，異若龜鶴形。", "況聞秦宮女，華髮變已青。", "有如上帝心，與我千萬齡。", "始疑有仙骨，鍊魂可永寧。", "何事逐豪遊，飲啄以羶腥。", "神物亦自閟，風雷護此扃。", "欲傳山中寶，回策忽已暝。", "乃悲世上人，求醒終不醒。"]'),
('b3ccab07-1c3c-458b-97ef-db1e536c324e','自朔方還與鄭式瞻崔稱鄭子周岑贊同會法雲寺三門避暑','李益','唐','唐诗','tang','','[]','予本疎放士，朅來非外矯。',96,'全唐诗/poet.tang.15000.json','["予本疎放士，朅來非外矯。", "誤落邊塵中，愛山見山少。", "始投清涼宇，門值煙岫表。", "參差互明滅，彩翠竟昏曉。", "泠泠遠風來，過此羣木杪。", "英英二三彥，襟曠去煩擾。", "遊川出潛魚，息陰倦飛鳥。", "徇物不可窮，唯於此心了。"]'),
('4a4e193a-a232-4a00-b6b2-65e8489a0853','來從竇車騎行','李益','唐','唐诗','tang','','[]','束髮逢世屯，懷恩抱明義。',228,'全唐诗/poet.tang.15000.json','["束髮逢世屯，懷恩抱明義。", "讀書良有感，學劒慙非智。", "遂別魯諸生，來從竇車騎。", "追兵赴邊急，絡馬黃金轡。", "出入燕南陲，由來重意氣。", "自經臯蘭戰，又破樓煩地。", "西北護三邊，東南留一尉。", "時過歘如雲，參差不自意。", "將軍失恩澤，萬事從此異。", "置酒高臺上，薄暮秋風至。", "長戟與我歸，歸來同棄置。", "自酌還自飲，非名又非利。", "歌出易水寒，琴下雍門淚。", "出逢平樂舊，言在天階侍。", "問我從軍苦，自陳少年貴。", "丈夫交四海，徒論身自致。", "漢將不封侯，蘇卿勞遠使。", "今我終此曲，此曲誠不易。", "貴人難識心，何由知忌諱。"]'),
('7a6b502b-cb9c-497a-9d54-9ba097e0ea2d','夜發軍中','李益','唐','唐诗','tang','','[]','邊馬櫪上驚，雄劒匣中鳴。',60,'全唐诗/poet.tang.15000.json','["邊馬櫪上驚，雄劒匣中鳴。", "半夜軍書致，匈奴寇六城。", "中堅分暗陣，太乙起神兵。", "出沒風雲合，蒼黃豺虎爭。", "今日邊庭戰，緣賞不緣名。"]'),
('cedafb62-7ae2-4a70-a2db-f48facd08f36','將赴朔方早發漢武泉','李益','唐','唐诗','tang','','[]','弭蓋出故關，窮秋首邊路。',84,'全唐诗/poet.tang.15000.json','["弭蓋出故關，窮秋首邊路。", "問我此何爲，平生重一顧。", "風吹山下草，繫馬河邊樹。", "奉役良有期，回瞻終未屢。", "去鄉幸未遠，戎衣今已故。", "豈惟幽朔寒，念我機中素。", "去矣勿復言，所酬知音遇。"]'),
('a9438f77-6c30-4d0d-bd59-8048625585a1','城傍少年','李益','唐','唐诗','tang','','[]','長生邊城傍，出身事弓馬。',48,'全唐诗/poet.tang.15000.json','["長生邊城傍，出身事弓馬。", "少年有膽氣，獨獵陰山下。", "偶與匈奴逢，曾擒射鵰者。", "名懸壯士籍，請君少相假。"]'),
('c50617c3-db50-4e02-a04f-c875072e9a89','游子吟','李益','唐','唐诗','tang','','[]','女羞夫壻薄，客耻主人賤。',72,'全唐诗/poet.tang.15000.json','["女羞夫壻薄，客耻主人賤。", "遭遇同衆流，低回媿相見。", "君非青銅鏡，何事空照面。", "莫以衣上塵，不謂心如練。", "人生當榮盛，待士勿言倦。", "君看白日馳，何異弦上箭。"]'),
('a299bc6f-f1c3-49dd-b450-c6a86c070155','飲馬歌','李益','唐','唐诗','tang','','[]','百馬飲一泉，一馬爭上游。',60,'全唐诗/poet.tang.15000.json','["百馬飲一泉，一馬爭上游。", "一馬噴成泥，百馬飲濁流。", "上有滄浪客，對之空歎息。", "自顧纓上塵，裴回終日夕。", "爲問泉上翁，何時見沙石。"]'),
('3c0f4e33-d046-48ce-bf7f-0aaf1d7f85dc','蓮塘驛','李益','唐','唐诗','tang','','[]','五月渡淮水，南行遶山陂。',96,'全唐诗/poet.tang.15000.json','["五月渡淮水，南行遶山陂。", "江村遠雞應，竹裏聞繰絲。", "楚女肌髮美，蓮塘煙露滋。", "菱花覆碧渚，黃鳥雙飛時。", "渺渺泝洄遠，憑風託微詞。", "斜光動流睇，此意難自持。", "女歌本輕豔，客行多怨思。", "女蘿蒙幽蔓，擬上青桐枝。"]'),
('9ab87ffd-4188-4986-9367-e47bfafb7e13','五城道中','李益','唐','唐诗','tang','','[]','金鐃隨玉節，落日河邊路。',108,'全唐诗/poet.tang.15000.json','["金鐃隨玉節，落日河邊路。", "沙鳴後騎來，雁起前軍度。", "五城鳴斥堠，三秦新召募。", "天寒白登道，塞濁陰山霧。", "仍聞舊兵老，尚在烏蘭戍。", "笳簫漢思繁，旌旗邊色故。", "寢興倦弓甲，勤役傷風露。", "來遠賞不行，鋒交勳乃茂。", "未知朔方道，何年罷兵賦。"]'),
('0635bc3b-9aab-41e0-92d9-9fee8a31a838','與王楚同登青龍寺上方','李益','唐','唐诗','tang','','[]','連岡出古寺，流睇移芳讌。',60,'全唐诗/poet.tang.15000.json','["連岡出古寺，流睇移芳讌。", "鳥沒漢諸陵，草平秦故殿。", "搖光淺深樹，拂木參差燕。", "春心斷易迷，遠目傷難徧。", "壯日各輕年，暮年方自見。"]'),
('8879571b-91bc-47a4-b2f8-4094ed1440ed','登夏州城觀送行人賦得六州胡兒歌','李益','唐','唐诗','tang','','[]','六州胡兒六蕃語，十歲騎羊逐沙鼠。',160,'全唐诗/poet.tang.15000.json','["六州胡兒六蕃語，十歲騎羊逐沙鼠。", "沙頭牧馬孤雁飛，漢軍遊騎貂錦衣。", "雲中征戍三千里，今日征行何歲歸。", "無定河邊數株柳，共送行人一杯酒。", "胡兒起作和蕃歌，齊唱嗚嗚盡垂手。", "心知舊國西州遠，西向胡天望鄉久。", "回頭忽作異方聲，一聲回盡征人首。", "蕃音虜曲一難分，似說邊情向塞雲。", "故國關山無限路，風沙滿眼堪斷魂。", "不見天邊青作冢，古來愁殺漢昭君。"]'),
('7e7eeac9-cf7a-4b57-af7d-60ac5ab60ad3','從軍夜次六胡北飲馬磨劒石爲祝殤辭','李益','唐','唐诗','tang','','[]','我行空磧，見沙之磷磷，與草之冪冪。',341,'全唐诗/poet.tang.15000.json','["我行空磧，見沙之磷磷，與草之冪冪。", "半沒胡兒磨劒石，當時洗劒血成川。", "至今草與沙皆赤，我因扣石問以言。", "水流嗚咽幽草根，君寧獨不怪陰燐。", "吹火熒熒又爲碧，有鳥自稱蜀帝魂。", "南人伐竹湘山下，交根接葉滿淚痕。", "請君先問湘江水，然我此恨乃可論。", "秦亡漢絕三十國，關山戰死知何極。", "風飄雨灑水自流，此中有冤消不得。", "爲之彈劒作哀吟，風沙四起雲沈沈。", "滿營戰馬嘶欲盡，畢昴不見胡天陰。", "東征曾弔長平苦，往往睛明獨風雨。", "年移代去感精魂，空山月暗聞鼙鼓。", "秦坑趙卒四十萬，未若格鬬傷戎虜。", "聖君破胡爲六州，六州又盡爲胡丘。", "韓公三城斷胡路，漢甲百萬屯邊秋。", "乃分司空授朔土，擁以玉節臨諸侯。", "漢爲一雪萬世讐，我今抽刀勒劒石，告爾萬世爲唐休。", "又聞招魂有美酒，爲我澆酒祝東流。", "殤爲魂兮，可以歸還故鄉些。", "沙場地無人兮，爾獨不可以久留。"]'),
('fd7ee0fc-78eb-4b7c-86e3-efe3e65ffda9','登天壇夜見海','李益','唐','唐诗','tang','','[]','朝遊碧峯三十六，夜上天壇月邊宿。',144,'全唐诗/poet.tang.15000.json','["朝遊碧峯三十六，夜上天壇月邊宿。", "仙人攜我搴玉英，壇上夜半東方明。", "僊鐘撞撞近海日，海中離離三山出。", "霞梯赤城遙可分，霓旌絳節倚彤雲。", "八鸞五鳳紛在御，王母欲上朝元君。", "羣仙指此爲我說，幾見塵飛滄海竭。", "竦身別我期丹宮，空山處處遺清風。", "九州下視杳未旦，一半浮生皆夢中。", "始知武皇求不死，去逐瀛洲羨門子。"]'),
('53507dd1-ecdc-459b-ad7f-18951aa1751b','大禮畢皇帝御丹鳳門改元建中大赦','李益','唐','唐诗','tang','','[]','大明曈曈天地分，六龍負日升天門。',128,'全唐诗/poet.tang.15000.json','["大明曈曈天地分，六龍負日升天門。", "鳳凰飛來銜帝籙，言我萬代金皇孫。", "靈雞鼓舞承天赦，高翔百尺垂朱幡。", "宸居穆清受天曆，建中甲子合上元。", "昊穹景命即已至，王事乃可酬乾坤。", "升中告成答玄貺，泥金檢玉昭鴻恩。", "云亭之事略可記，七十二君寧獨尊。", "小臣欲上封禪表，久而未就歸文園。"]'),
('baf32153-80f8-4276-835e-ad216726ee00','輕薄篇','李益','唐','唐诗','tang','','[]','豪不必馳千騎，雄不在垂雙鞬。',142,'全唐诗/poet.tang.15000.json','["豪不必馳千騎，雄不在垂雙鞬。", "天生俊氣自相逐，出與鵰鶚同飛翻。", "朝行九衢不得意，下鞭走馬城西原。", "忽聞燕雁一聲去，回鞍挾彈平陵園。", "歸來青樓曲未半，美人玉色當金尊。", "淮陰少年不相下，酒酣半笑倚市門。", "安知我有不平色，白日欲落紅塵昏。", "死生容易如反掌，得意失意由一言。", "少年但飲莫相問，此中報讐亦報恩。"]'),
('64efbf7a-0bf7-4d4c-bdfa-66a6868ca3df','野田行','李益','唐','唐诗','tang','','[]','日沒出古城，野田何茫茫。',40,'全唐诗/poet.tang.15000.json','["日沒出古城，野田何茫茫。", "寒狐嘯青冢，鬼火燒白楊。", "昔人未爲泉下客，行到此中曾斷腸。"]'),
('5c1e4978-6cc4-4de9-86d1-f7dcc8cce6e1','古別離','李益','唐','唐诗','tang','','[]','雙劒欲別風淒然，雌沈水底雄上天。',48,'全唐诗/poet.tang.15000.json','["雙劒欲別風淒然，雌沈水底雄上天。", "江回漢轉兩不見，雲交雨合知何年。", "古來萬事皆由命，何用臨岐苦涕漣。"]'),
('6ce804ea-013c-4af4-a4c3-4e1e4fb89500','效古促促曲爲河上思婦作','李益','唐','唐诗','tang','','["\u9ec4\u6cb3"]','促促何促促，黃河九回曲。',40,'全唐诗/poet.tang.15000.json','["促促何促促，黃河九回曲。", "嫁與棹船郎，空牀將影宿。", "不道君心不如石，那教妾貌長如玉。"]'),
('31fa0be9-47e6-424d-8d1a-c31a00492172','漢宮少年行','李益','唐','唐诗','tang','','[]','君不見上宮警夜營八屯，鼕鼕街鼓朝朱軒。',243,'全唐诗/poet.tang.15000.json','["君不見上宮警夜營八屯，鼕鼕街鼓朝朱軒。", "玉堦霜仗擁未合，少年排入銅龍門。", "暗聞弦管九天上，宮漏沈沈清吹繁。", "平明走馬絕馳道，呼鷹挾彈通繚垣。", "玉籠金鎖養黃口，探雛取卵伴王孫。", "分曹陸博快一擲，迎歡先意笑語喧。", "巧爲柔媚學優孟，儒衣嬉戲冠沐猿。", "晚來香街經柳市，行過倡舍宿桃根。", "相逢杯酒一言失，迴朱點白聞至尊。", "金張許史伺顏色，王侯將相莫敢論。", "豈知人事無定勢，朝歡暮戚如掌翻。", "椒房寵移子愛奪，一夕秋風生戾園。", "徒用黃金將買賦，寧知白玉暗成痕。", "持杯收水水已覆，徙薪避火火更燔。", "欲求四老張丞相，南山如天不可上。"]'),
('7b501b42-fe79-4c87-97bc-7ff610629698','竹窗聞風寄苗發司空曙','李益','唐','唐诗','tang','','["\u601d\u5ff5", "\u98ce", "\u5199\u98ce"]','微風驚暮坐，臨牖思悠哉。',48,'全唐诗/poet.tang.15000.json','["微風驚暮坐，臨牖思悠哉。", "開門復動竹，疑是故人來。", "時滴枝上露，稍沾堦下苔。", "何當一入幌，爲拂綠琴埃。"]'),
('eb0f6c98-600f-490d-aab0-8e2eedcf33b4','賦得垣衣','李益','唐','唐诗','tang','','[]','漠漠復霏霏，爲君垣上衣。',48,'全唐诗/poet.tang.15000.json','["漠漠復霏霏，爲君垣上衣。", "昭陽輦下草，應笑此生非。", "掩藹青春去，蒼茫白露稀。", "猶勝萍逐水，流浪不相依。"]'),
('1a2250c9-1c3b-46ec-8872-f0decaa82b7d','送人流貶','李益','唐','唐诗','tang','','[]','漢章雖約法，秦律已除名。',48,'全唐诗/poet.tang.15000.json','["漢章雖約法，秦律已除名。", "謗遠人多惑，官微不自明。", "霜風先獨樹，瘴雨失荒城。", "疇昔長沙事，三年召賈生。"]'),
('8b4c8085-3507-4d7d-b0d0-23b86cde36d1','送人南歸','李益','唐','唐诗','tang','','[]','人言下江疾，君道下江遲。',48,'全唐诗/poet.tang.15000.json','["人言下江疾，君道下江遲。", "五月江路惡，南風驚浪時。", "應知近家喜，還有異鄉悲。", "無奈孤舟夕，山歌聞竹枝。"]'),
('2baaeb98-3c3e-4474-a224-9e251f9f440d','水亭夜坐賦得曉霧','李益','唐','唐诗','tang','','[]','月落寒霧起，沈思浩通川。',48,'全唐诗/poet.tang.15000.json','["月落寒霧起，沈思浩通川。", "宿禽囀木散，山澤一蒼然。", "漠漠沙上路，沄沄洲外田。", "猶當依遠樹，斷續欲窮天。"]'),
('b7796060-d3ba-48f2-ae1b-75d75215548d','送常曾侍御使西蕃寄題西川','李益','唐','唐诗','tang','','[]','涼王宮殿盡，蕪沒隴雲西。',48,'全唐诗/poet.tang.15000.json','["涼王宮殿盡，蕪沒隴雲西。", "今日聞君使，雄心逐鼓鼙。", "行當收漢壘，直可取蒲泥。", "舊國無由到，煩君下馬題。"]'),
('1dba323d-1fb0-4e7c-9631-1756f73cb66c','入南山至全師蘭若','李益','唐','唐诗','tang','','[]','木隕水歸壑，寂然無念心。',48,'全唐诗/poet.tang.15000.json','["木隕水歸壑，寂然無念心。", "南行有真子，被褐息山陰。", "石路瑤草散，松門寒景深。", "吾師亦何愛，自起定中吟。"]'),
('8990d048-1892-4577-b4d7-1fb4b01573d8','送韓將軍還邊','李益','唐','唐诗','tang','','[]','白馬羽林兒，揚鞭薄暮時。',48,'全唐诗/poet.tang.15000.json','["白馬羽林兒，揚鞭薄暮時。", "獨將輕騎出，暗與伏兵期。", "雨雪移軍遠，旌旗上壠遲。", "聖心戎寄重，未許讓恩私。"]'),
('2ed55057-2952-43ca-9480-449f2750d6e2','晚春臥病喜振上人見訪','李益','唐','唐诗','tang','','[]','臥牀如舊日，窺戶易傷春。',48,'全唐诗/poet.tang.15000.json','["臥牀如舊日，窺戶易傷春。", "靈壽扶衰力，芭蕉對病身。", "道心空寂寞，時物自芳新。", "旦夕誰相訪，唯當攝上人。"]'),
('d7ac0c91-1a6a-497e-b9e0-888d5864ef98','春行','李益','唐','唐诗','tang','','[]','侍臣朝謁罷，戚里自相過。',48,'全唐诗/poet.tang.15000.json','["侍臣朝謁罷，戚里自相過。", "落日青絲騎，春風白紵歌。", "恩承三殿近，獵向五陵多。", "歸路南橋望，垂楊拂細波。"]'),
('c003d0a4-d608-4d4f-b9fc-7b87b4202d53','洛陽河亭奉酬留守羣公追送','李益','唐','唐诗','tang','','[]','離亭餞落暉，臘酒減春衣。',48,'全唐诗/poet.tang.15000.json','["離亭餞落暉，臘酒減春衣。", "歲晚煙霞重，川寒雲樹微。", "戎裝千里至，舊路十年歸。", "還似汀洲雁，相逢又背飛。"]'),
('aa3d4999-dde9-40af-958d-0a79eb4d2171','尋紀道士偶會諸叟','李益','唐','唐诗','tang','','[]','山陰尋道士，暎竹羽衣新。',48,'全唐诗/poet.tang.15000.json','["山陰尋道士，暎竹羽衣新。", "侍坐雙童子，陪遊五老人。", "水花松下靜，壇草雪中春。", "見說桃源洞，如今猶避秦。"]'),
('bd1f5183-318f-40d2-ac1c-fe5b12415a25','同蕭鍊師宿太乙廟','李益','唐','唐诗','tang','','[]','微月空山曙，春祠謁少君。',48,'全唐诗/poet.tang.15000.json','["微月空山曙，春祠謁少君。", "落花壇上拂，流水洞中聞。", "酒引芝童奠，香餘桂子焚。", "鶴飛將羽節，遙向赤城分。"]'),
('b4ed9dbf-ff4b-49ee-b3bd-6d621c5f5766','送同落第者東歸','李益','唐','唐诗','tang','','[]','東門有行客，落日滿前山。',48,'全唐诗/poet.tang.15000.json','["東門有行客，落日滿前山。", "聖代誰知者，滄洲今獨還。", "片雲歸海暮，流水背城閑。", "余亦依嵩潁，松花深閉關。"]'),
('1f4dfb15-6a50-428f-8ce8-121b853cce12','送柳判官赴振武','李益','唐','唐诗','tang','','[]','邊庭漢儀重，旌甲似雲中。',48,'全唐诗/poet.tang.15000.json','["邊庭漢儀重，旌甲似雲中。", "虜地山川壯，單于鼓角雄。", "關寒塞榆落，月白胡天風。", "君逐嫖姚將，麒麟有戰功。"]'),
('66d3a87d-2758-4bd0-8e07-927f9e722afc','述懷寄衡州令狐相公','李益','唐','唐诗','tang','','[]','調元方翼聖，軒蓋忽言東。',48,'全唐诗/poet.tang.15000.json','["調元方翼聖，軒蓋忽言東。", "道以中樞密，心將外理同。", "白頭生遠浪，丹葉下高楓。", "江上蕭疎雨，何人對謝公。"]'),
('566b6a8b-7a12-4b35-a277-f9b4a530c908','喜入蘭陵望紫閣峯呈宣上人','李益','唐','唐诗','tang','','[]','薙草開三徑，巢林喜一枝。',48,'全唐诗/poet.tang.15000.json','["薙草開三徑，巢林喜一枝。", "地寬留種竹，泉淺欲開池。", "紫閣當疎牖，青松入壞籬。", "從今安僻陋，蕭相是吾師。"]'),
('d755f74b-18fd-44d1-a6e1-43e77490bb09','喜見外弟又言別','李益','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u79bb\u522b", "\u4e94\u8a00\u5f8b\u8bd7"]','十年離亂後，長大一相逢。',48,'全唐诗/poet.tang.15000.json','["十年離亂後，長大一相逢。", "問姓驚初見，稱名憶舊容。", "別來滄海事，語罷暮天鐘。", "明日巴陵道，秋山又幾重。"]'),
('17e7a317-f30f-4f25-ac0f-d43111ce9da1','立春日寧州行營因賦朔風吹飛雪','李益','唐','唐诗','tang','','[]','邊聲日夜合，朔風驚復來。',48,'全唐诗/poet.tang.15000.json','["邊聲日夜合，朔風驚復來。", "龍山不可望，千里一裴回。", "捐扇破誰執，素紈輕欲裁。", "非時妬桃李，自是舞陽臺。"]'),
('2ece861e-f4da-4663-9ca7-22ed69e049dd','獻劉濟','李益','唐','唐诗','tang','','[]','草綠古燕州，鶯聲引獨遊。',48,'全唐诗/poet.tang.15000.json','["草綠古燕州，鶯聲引獨遊。", "雁歸天北畔，春盡海西頭。", "向日花偏落，馳年水自流。", "感恩知有地，不上望京樓。"]'),
('f99ee05c-2dff-4dc0-9a51-22f8168b5427','哭柏巖禪師','李益','唐','唐诗','tang','','[]','遍與傍人別，臨終盡不愁。',48,'全唐诗/poet.tang.15000.json','["遍與傍人別，臨終盡不愁。", "影堂誰爲掃，坐塔自看修。", "白日鐘邊晚，青苔鉢上秋。", "天涯禪弟子，空到柏巖遊。"]'),
('73165d09-7d28-4501-8b78-3770ebca3914','赴邠寧留別','李益','唐','唐诗','tang','','[]','身承漢飛將，束髮即言兵。',48,'全唐诗/poet.tang.15000.json','["身承漢飛將，束髮即言兵。", "俠少何相問，從來事不平。", "黃雲斷朔吹，白雪擁沙城。", "幸應邊書募，橫戈會取名。"]'),
('1c00d44f-c654-4483-94e0-bdb85cd6f977','紫騮馬','李益','唐','唐诗','tang','','[]','爭場看鬬雞，白鼻紫騮嘶。',48,'全唐诗/poet.tang.15000.json','["爭場看鬬雞，白鼻紫騮嘶。", "漳水春閨晚，叢臺日向低。", "歇鞍珠作汗，試劒玉如泥。", "爲謝紅梁燕，年年妾獨棲。"]'),
('33ab5d59-0df0-48f6-8830-9086b4915a9b','夜上受降城聞笛','李益','唐','唐诗','tang','','[]','入夜思歸切，笛聲清更哀。',48,'全唐诗/poet.tang.15000.json','["入夜思歸切，笛聲清更哀。", "愁人不願聽，自到枕前來。", "風起塞雲斷，夜深關月開。", "平明獨惆悵，落盡一庭梅。"]'),
('2bf81ba1-a18f-4e42-9bad-ac68cae86da4','同崔邠登鸛雀樓','李益','唐','唐诗','tang','','[]','鸛雀樓西百尺檣，汀洲雲樹共茫茫。',64,'全唐诗/poet.tang.15000.json','["鸛雀樓西百尺檣，汀洲雲樹共茫茫。", "漢家簫鼓空流水，魏國山河半夕陽。", "事去千年猶恨速，愁來一日即爲長。", "風煙倂起思歸望，遠目非春亦自傷。"]'),
('13bfd558-12d2-49c1-8968-a94c7246c83a','奉酬崔員外副使攜琴宿使院見示','李益','唐','唐诗','tang','','[]','忽聞此夜攜琴宿，遂歎常時塵吏喧。',64,'全唐诗/poet.tang.15000.json','["忽聞此夜攜琴宿，遂歎常時塵吏喧。", "庭木已衰空月亮，城砧自急對霜繁。", "猶持副節留軍府，未薦高詞直掖垣。", "誰問南飛長繞樹，官微同在謝公門。"]'),
('030307a8-0ef0-4e9a-b7c0-5f1d5240b322','送賈校書東歸寄振上人','李益','唐','唐诗','tang','','[]','北風吹雁數聲悲，況指前林是別時。',64,'全唐诗/poet.tang.15000.json','["北風吹雁數聲悲，況指前林是別時。", "秋草不堪頻送遠，白雲何處更相期。", "山隨匹馬行看暮，路入寒城獨去遲。", "爲向東州故人道，江淹已擬惠休詩。"]'),
('9657c24a-5dc0-409d-af80-ab182a7d336f','過馬嵬二首 一','李益','唐','唐诗','tang','','[]','路至牆垣問樵者，顧予云是太真宮。',64,'全唐诗/poet.tang.15000.json','["路至牆垣問樵者，顧予云是太真宮。", "太真血染馬蹄盡，朱閣影隨天際空。", "丹壑不聞歌吹夜，玉堦唯有薜蘿風。", "世人莫重霓裳曲，曾致干戈是此中。"]'),
('c599d603-fd7c-4711-a36c-155893c365a9','過馬嵬二首 二','李益','唐','唐诗','tang','','[]','金甲銀旌盡已回，蒼茫羅袖隔風埃。',64,'全唐诗/poet.tang.15000.json','["金甲銀旌盡已回，蒼茫羅袖隔風埃。", "濃香猶自隨鸞輅，恨魄無由離馬嵬。", "南內真人悲帳殿，東溟方士問蓬萊。", "唯留坡畔彎環月，時送殘輝入夜臺。"]'),
('63aed9a9-4229-4f68-8fe9-e626ae91b5a0','鹽州過胡兒飲馬泉','李益','唐','唐诗','tang','','[]','綠楊著水草如煙，舊是胡兒飲馬泉。',64,'全唐诗/poet.tang.15000.json','["綠楊著水草如煙，舊是胡兒飲馬泉。", "幾處吹笳明月夜，何人倚劒白雲天。", "從來凍合關山路，今日分流漢使前。", "莫遣行人照容鬢，恐驚憔悴入新年。"]'),
('aa25ad03-1308-4c66-a2cf-351bbc3d22cf','宿馮翊夜雨贈主人','李益','唐','唐诗','tang','','[]','危心驚夜雨，起望漫悠悠。',72,'全唐诗/poet.tang.15000.json','["危心驚夜雨，起望漫悠悠。", "氣耿殘燈暗，聲繁高樹秋。", "涼軒辭夏扇，風幌攬輕裯。", "思緒蓬初斷，歸期燕暫留。", "關山藹已失，臉淚逬難收。", "賴君時一笑，方能解四愁。"]'),
('b22cb818-b07a-4024-855d-c3734cd1d237','送襄陽李尚書','李益','唐','唐诗','tang','','[]','天寒發梅柳，憶昔到襄州。',96,'全唐诗/poet.tang.15000.json','["天寒發梅柳，憶昔到襄州。", "樹暖然紅燭，江清展碧油。", "風煙臨峴首，雲水接昭丘。", "俗尚春秋學，詞稱文選樓。", "都門送旌節，符竹領諸侯。", "漢沔分戎寄，黎元減聖憂。", "時追山簡興，本自習家流。", "莫廢思康樂，詩情滿沃洲。"]'),
('344bb72a-dec5-427d-b523-bc60d71bc8ee','春日晉祠同聲會集得疎字韻','李益','唐','唐诗','tang','','[]','風壤瞻唐本，山祠閱晉餘。',72,'全唐诗/poet.tang.15000.json','["風壤瞻唐本，山祠閱晉餘。", "水亭開帟幕，巖榭引簪裾。", "地綠苔猶少，林黃柳尚疎。", "菱苕生皎鏡，金碧照澄虛。", "翰苑聲何舊，賓筵醉止初。", "中州有遼雁，好爲繫邊書。"]'),
('6d0a1909-8650-4d3f-bd5e-ef4c1b69bb8a','再赴渭北使府留別','李益','唐','唐诗','tang','','[]','結髮逐鳴鼙，連兵追谷蠡。',96,'全唐诗/poet.tang.15000.json','["結髮逐鳴鼙，連兵追谷蠡。", "山川搜伏虜，鎧甲被重犀。", "故府旌旗在，新軍羽校齊。", "報恩身未死，識路馬還嘶。", "列嶂高烽舉，當營太白低。", "平戎七尺劒，封檢一丸泥。", "截海取蒲類，跑泉飲鸊鵜。", "漢庭中選重，更事五原西。"]'),
('16057a4a-3812-4449-8ade-86f71a10b88e','送歸中丞使新羅冊立弔祭','李益','唐','唐诗','tang','','[]','東望扶桑日，何年是到時。',72,'全唐诗/poet.tang.15000.json','["東望扶桑日，何年是到時。", "片帆通雨露，積水隔華夷。", "浩渺風來遠，虛明鳥去遲。", "長波靜雲月，孤島宿旌旗。", "別葉傳秋意，迴潮動客思。", "滄溟無舊路，何處問前期。"]'),
('2571f14e-0c02-4fa0-a52c-f3b75069e0b6','賦得路傍一株柳送邢校書赴延州使府','李益','唐','唐诗','tang','','[]','路傍一株柳，此路向延州。',24,'全唐诗/poet.tang.15000.json','["路傍一株柳，此路向延州。", "延州在何處，此路起悠悠。"]'),
('1e649844-ac06-47a4-96a7-baa2db22ea1b','重贈邢校書','李益','唐','唐诗','tang','','[]','俱從四方事，共會九秋中。',24,'全唐诗/poet.tang.15000.json','["俱從四方事，共會九秋中。", "斷蓬與落葉，相值各因風。"]'),
('66322ac8-46e8-4561-9858-ece254a0de59','照鏡','李益','唐','唐诗','tang','','[]','衰鬢朝臨鏡，將看却自疑。',24,'全唐诗/poet.tang.15000.json','["衰鬢朝臨鏡，將看却自疑。", "慙君明似月，照我白如絲。"]'),
('45b2a162-7434-46de-8d60-84a3f2aff8d9','書院無曆日以詩代書問路侍御六月大小','李益','唐','唐诗','tang','','[]','野性迷堯曆，松窗有道經。',24,'全唐诗/poet.tang.15000.json','["野性迷堯曆，松窗有道經。", "故人爲柱史，爲我數堦蓂。"]'),
('32e1f5b6-ef99-421b-a27a-005cfcab4a58','聞雞贈主人','李益','唐','唐诗','tang','','[]','膠膠司晨鳴，報爾東方旭。',24,'全唐诗/poet.tang.15000.json','["膠膠司晨鳴，報爾東方旭。", "無事戀君軒，今君重鳧鵠。"]'),
('df9d56f5-78e1-44ca-993d-dcf464c5ab49','登白樓見白鳥席上命鷓鴣辭','李益','唐','唐诗','tang','','[]','一鳥如霜雪，飛向白樓前。',24,'全唐诗/poet.tang.15000.json','["一鳥如霜雪，飛向白樓前。", "問君何以至，天子太平年。"]'),
('f8b05c06-42e5-4802-84e5-67d0f804f91e','石樓山見月','李益','唐','唐诗','tang','','[]','紫塞連年戍，黃砂磧路窮。',24,'全唐诗/poet.tang.15000.json','["紫塞連年戍，黃砂磧路窮。", "故人今夜宿，見月石樓中。"]'),
('c98125ab-4707-4368-96e8-349c1678b363','惜春傷同幕故人孟郎中兼呈去年看花友','李益','唐','唐诗','tang','','[]','畏老身全老，逢春解惜春。',24,'全唐诗/poet.tang.15000.json','["畏老身全老，逢春解惜春。", "今年看花伴，已少去年人。"]'),
('4679a379-67a4-4359-b2c6-2fcac0cb20f0','嘉禾寺見亡友王七題壁','李益','唐','唐诗','tang','','[]','今日憶君處，憶君君豈知。',24,'全唐诗/poet.tang.15000.json','["今日憶君處，憶君君豈知。", "空餘暗塵字，讀罷淚仍垂。"]'),
('d8d4a2e2-28ae-42d1-84ce-306a9b4df039','聽唱赤白桃李花','李益','唐','唐诗','tang','','[]','赤白桃李花，先皇在時曲。',26,'全唐诗/poet.tang.15000.json','["赤白桃李花，先皇在時曲。", "欲向西宮唱，西宮[宮]樹綠。"]'),
('9bd49546-5289-4351-97f4-d69296720dfc','江南詞','李益','唐','唐诗','tang','','["\u95fa\u6028", "\u5510\u8bd7\u4e09\u767e\u9996", "\u4e50\u5e9c"]','嫁得瞿塘賈，朝朝悞妾期。',24,'全唐诗/poet.tang.15000.json','["嫁得瞿塘賈，朝朝悞妾期。", "早知潮有信，嫁與弄潮兒。"]'),
('e1d713a6-c56e-4f5c-9dbc-87806a7d9f51','贈內兄盧綸','李益','唐','唐诗','tang','','[]','世故中年別，餘生此會同。',24,'全唐诗/poet.tang.15000.json','["世故中年別，餘生此會同。", "却將悲與病，來對朗陵翁。"]'),
('f7d970e1-655a-4f2d-b68d-f05424a35bba','答竇二曹長留酒還榼','李益','唐','唐诗','tang','','[]','榼小非由榼，星朗是酒星。',24,'全唐诗/poet.tang.15000.json','["榼小非由榼，星朗是酒星。", "解酲元有數，不用嚇劉伶。"]'),
('e7abc1d7-3d6f-4e7a-9d00-399c4d6879c9','答廣宣供奉問蘭陵居','李益','唐','唐诗','tang','','[]','居北有朝路，居南無住人。',24,'全唐诗/poet.tang.15000.json','["居北有朝路，居南無住人。", "勞師問家第，山色是南鄰。"]'),
('60d8de49-e393-4470-bae6-6a7ce35c5d29','乞寬禪師癭山罍呈宣供奉','李益','唐','唐诗','tang','','[]','石色凝秋蘚，峰形若夏雲。',24,'全唐诗/poet.tang.15000.json','["石色凝秋蘚，峰形若夏雲。", "誰留秦苑地，好贈杏溪君。"]'),
('8aa31994-11ad-4080-8373-81b05d155b6e','觀騎射','李益','唐','唐诗','tang','','[]','邊頭射鵰將，走馬出中軍。',24,'全唐诗/poet.tang.15000.json','["邊頭射鵰將，走馬出中軍。", "遠見平原上，翻身向暮雲。"]'),
('1f307977-4e4b-4524-b9a7-f5cdf4c4bbe4','幽州賦詩見意時佐劉幕','李益','唐','唐诗','tang','','[]','征戍在桑乾，年年薊水寒。',24,'全唐诗/poet.tang.15000.json','["征戍在桑乾，年年薊水寒。", "殷勤驛西路，北去向長安。"]'),
('8cfd97dc-c9ce-47c0-81d1-d6fcf8af6859','軍次陽城烽舍北流泉','李益','唐','唐诗','tang','','[]','何地可潸然，陽城烽樹邊。',24,'全唐诗/poet.tang.15000.json','["何地可潸然，陽城烽樹邊。", "今朝望鄉客，不飲北流泉。"]'),
('bb6e33b6-6c5c-4994-8e76-163dfa886998','金吾子','李益','唐','唐诗','tang','','[]','繡帳博山鑪，銀鞍馮子都。',24,'全唐诗/poet.tang.15000.json','["繡帳博山鑪，銀鞍馮子都。", "黃昏莫攀折，驚起欲棲烏。"]'),
('097a5a64-1fd3-4307-94a0-f81bf732e94b','山鷓鴣詞','李益','唐','唐诗','tang','','[]','湘江斑竹枝，錦翅鷓鴣飛。',24,'全唐诗/poet.tang.15000.json','["湘江斑竹枝，錦翅鷓鴣飛。", "處處湘雲合，郎從何處歸。"]'),
('9fd85a05-3d4d-4f65-9a54-9f1f598ad091','立秋前一日覽鏡','李益','唐','唐诗','tang','','[]','萬事銷身外，生涯在鏡中。',24,'全唐诗/poet.tang.15000.json','["萬事銷身外，生涯在鏡中。", "唯將滿鬢雪，明日對秋風。"]'),
('e25d24b0-a03f-4e3e-943c-8ca4ce2d917e','代人乞花','李益','唐','唐诗','tang','','[]','繡戶朝眠起，開簾滿地花。',24,'全唐诗/poet.tang.15000.json','["繡戶朝眠起，開簾滿地花。", "春風解人意，欲落妾西家。"]'),
('40a9fe70-40d2-4718-a1af-09193449508a','上洛橋','李益','唐','唐诗','tang','','[]','金谷園中柳，春來似舞腰。',24,'全唐诗/poet.tang.15000.json','["金谷園中柳，春來似舞腰。", "何堪好風景，獨上洛陽橋。"]'),
('9f62397a-8eef-4408-81dc-2cb54b55a866','揚州懷古','李益','唐','唐诗','tang','','[]','故國歌鐘地，長橋車馬塵。',24,'全唐诗/poet.tang.15000.json','["故國歌鐘地，長橋車馬塵。", "彭城閣邊柳，偏似不勝春。"]'),
('dc6cab7b-c3ed-4645-9573-368a962ac03e','水宿聞雁','李益','唐','唐诗','tang','','[]','早雁忽爲雙，驚秋風水窗。',24,'全唐诗/poet.tang.15000.json','["早雁忽爲雙，驚秋風水窗。", "夜長人自起，星月滿空江。"]'),
('9eae2f1b-936a-4b82-9998-512b02a110e6','揚州早雁','李益','唐','唐诗','tang','','[]','江上三千雁，年年過故宮。',24,'全唐诗/poet.tang.15000.json','["江上三千雁，年年過故宮。", "可憐江上月，偏照斷根蓬。"]'),
('44852ba9-ebb5-4651-8b5a-62e293438389','下樓','李益','唐','唐诗','tang','','[]','話舊全應老，逢春喜又悲。',24,'全唐诗/poet.tang.15000.json','["話舊全應老，逢春喜又悲。", "看花行拭淚，倍覺下樓遲。"]'),
('6be79308-f67c-4d92-80eb-a4f206bc5b83','度破訥沙二首 一','李益','唐','唐诗','tang','','[]','眼見風來沙旋移，經年不省草生時。',32,'全唐诗/poet.tang.15000.json','["眼見風來沙旋移，經年不省草生時。", "莫言塞北無春到，總有春來何處知。"]'),
('72247708-1ff1-4fac-b17b-88cc88a9b553','度破訥沙二首 二','李益','唐','唐诗','tang','','[]','破訥沙頭雁正飛，鸊鵜泉上戰初歸。',32,'全唐诗/poet.tang.15000.json','["破訥沙頭雁正飛，鸊鵜泉上戰初歸。", "平明日出東南地，滿磧寒光生鐵衣。"]'),
('86e7df62-54b0-476d-9722-478c6bb6d8ce','拂雲堆','李益','唐','唐诗','tang','','[]','漢將新從虜地來，旌旗半上拂雲堆。',32,'全唐诗/poet.tang.15000.json','["漢將新從虜地來，旌旗半上拂雲堆。", "單于每近沙場獵，南望陰山哭始回。"]'),
('877d4ad7-11a3-4595-b86c-50052ef738d2','中橋北送穆質兄弟應制戲贈蕭二策','李益','唐','唐诗','tang','','[]','洛水橋邊雁影疎，陸機兄弟駐行車。',32,'全唐诗/poet.tang.15000.json','["洛水橋邊雁影疎，陸機兄弟駐行車。", "欲陳漢帝登封草，猶待蕭郎寄內書。"]'),
('9f32abfa-6459-4020-b79d-5f96a026c945','九月十日雨中過張伯佳期柳鎮未至以詩招之','李益','唐','唐诗','tang','','[]','柳吳興近無消息，張長公貧苦寂寥。',32,'全唐诗/poet.tang.15000.json','["柳吳興近無消息，張長公貧苦寂寥。", "唯有角巾霑雨至，手持殘菊向西招。"]'),
('1ba500f4-7cd5-4e87-91e0-b23ec74228e1','汴河曲','李益','唐','唐诗','tang','','[]','汴水東流無限春，隋家宮闕已成塵。',32,'全唐诗/poet.tang.15000.json','["汴水東流無限春，隋家宮闕已成塵。", "行人莫上長堤望，風起楊花愁殺人。"]');
